def _mock_xyzuvw_payload(args: dict[str, Any]) -> dict[str, Any]:
    selection = _parse_xyzuvw_selection(args)
    rng = np.random.default_rng(42)
    members = []
    models = []
    labels = []
    for aid_index, aid in enumerate(selection["aids"]):
        age_myr = round(float(10 ** (0.7 + 0.28 * aid_index)), 1)
        center = np.asarray([
            -30 + 45 * aid_index,
            20 - 25 * aid_index,
            -10 + 12 * aid_index,
            XYZUVW_C_VALUE * (-10 + 3 * aid_index),
            XYZUVW_C_VALUE * (-18 + 2 * aid_index),
            XYZUVW_C_VALUE * (-6 + aid_index),
        ], dtype=float)
        spread = np.asarray([18, 12, 10, 4 * XYZUVW_C_VALUE, 3 * XYZUVW_C_VALUE, 2.5 * XYZUVW_C_VALUE], dtype=float)
        label = {"moca_aid": aid, "age_myr": age_myr, "x": center[0], "y": center[1], "z": center[2], "u": center[3], "v": center[4], "w": center[5]}
        labels.append(label)
        models.append({
            "moca_aid": aid,
            "age_myr": age_myr,
            "moca_bsmdid": 16,
            "coeff_index": 0,
            "coeff_amplitude": 1.0,
            "x_cen": center[0],
            "y_cen": center[1],
            "z_cen": center[2],
            "u_cen": center[3] / XYZUVW_C_VALUE,
            "v_cen": center[4] / XYZUVW_C_VALUE,
            "w_cen": center[5] / XYZUVW_C_VALUE,
            "xx_covar": spread[0] ** 2,
            "yy_covar": spread[1] ** 2,
            "zz_covar": spread[2] ** 2,
            "uu_covar": (spread[3] / XYZUVW_C_VALUE) ** 2,
            "vv_covar": (spread[4] / XYZUVW_C_VALUE) ** 2,
            "ww_covar": (spread[5] / XYZUVW_C_VALUE) ** 2,
            "xy_covar": 0,
            "xz_covar": 0,
            "yz_covar": 0,
            "uv_covar": 0,
            "uw_covar": 0,
            "vw_covar": 0,
            "xu_covar": 0,
            "xv_covar": 0,
            "xw_covar": 0,
            "yu_covar": 0,
            "yv_covar": 0,
            "yw_covar": 0,
            "zu_covar": 0,
            "zv_covar": 0,
            "zw_covar": 0,
        })
        for index in range(52):
            coords = center + rng.normal(0, spread, size=6)
            oid = 900000 + aid_index * 1000 + index
            mtid = selection["mtids"][index % max(1, len(selection["mtids"]))]
            members.append({
                "designation": f"Mock {aid} member {index:02d}",
                "moca_aid": aid,
                "moca_mtid": mtid,
                "age_myr": age_myr,
                "spt": ["M5", "L1", "T2"][index % 3],
                "dr3_ruwe": round(float(rng.uniform(0.9, 1.6)), 2),
                "moca_oid": oid,
                "x": coords[0],
                "y": coords[1],
                "z": coords[2],
                "u": coords[3],
                "v": coords[4],
                "w": coords[5],
                "x_opt": 0.7 * coords[0] + 0.3 * center[0],
                "y_opt": 0.7 * coords[1] + 0.3 * center[1],
                "z_opt": 0.7 * coords[2] + 0.3 * center[2],
                "u_opt": 0.7 * coords[3] + 0.3 * center[3],
                "v_opt": 0.7 * coords[4] + 0.3 * center[4],
                "w_opt": 0.7 * coords[5] + 0.3 * center[5],
                "xx_covar": 9,
                "yy_covar": 9,
                "zz_covar": 9,
                "uu_covar": 4,
                "vv_covar": 4,
                "ww_covar": 4,
                "ya_prob": round(float(rng.uniform(45, 99)), 1),
                "observables": "XYZUVW",
            })
    objects = []
    for oid in selection["oids"]:
        objects.append({
            "designation": f"Highlighted mock oid{oid}",
            "moca_aid": "N/A",
            "moca_mtid": "N/A",
            "spt": "L/T",
            "dr3_ruwe": 1.1,
            "moca_oid": int(oid),
            "x": 5,
            "y": -10,
            "z": 18,
            "u": None,
            "v": None,
            "w": None,
            "ra": 24.0,
            "dec": 9.5,
            "pmra_masyr": 1200,
            "pmdec_masyr": -450,
            "distance_pc": 6.2,
            "radial_velocity_kms": None,
        })
    if selection["likely"]:
        members = [row for row in members if float(row.get("ya_prob") or 0) >= 80]
    return {
        "selection": selection,
        "members": members,
        "models": models,
        "objects": objects,
        "labels": labels if selection["labels"] else [],
        "meta": {
            "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
            "private_db": False,
            "member_count": len(members),
            "model_count": len(models),
            "object_count": len(objects),
            "truncated": False,
            "max_objects": XYZUVW_MAX_OBJECTS,
            "c_value": XYZUVW_C_VALUE,
        },
        "cache": {"hit": False, "ttl_seconds": 0},
    }


class _TfAgeCurve:
    __slots__ = ("key", "label", "source", "age_myr", "pdf_age", "metadata")

    def __init__(
        self,
        key: str,
        label: str,
        source: str,
        age_myr: np.ndarray,
        pdf_age: np.ndarray,
        metadata: dict[str, Any],
    ) -> None:
        self.key = key
        self.label = label
        self.source = source
        self.age_myr = age_myr
        self.pdf_age = pdf_age
        self.metadata = metadata


def _tfage_scope(args: dict[str, Any]) -> str:
    raw = str(args.get("target") or args.get("scope") or args.get("mode") or "").strip().lower()
    if raw in {"association", "associations", "assoc", "aid"}:
        return "association"
    if raw in {"object", "objects", "oid"}:
        return "object"
    if args.get("moca_aid") or args.get("aid"):
        return "association"
    return "object"


def _tfage_target(args: dict[str, Any], scope: str) -> int | str | None:
    if scope == "association":
        aid = str(args.get("moca_aid") or args.get("aid") or "").strip().upper()
        return aid or None
    raw_oid = args.get("moca_oid") or args.get("oid") or args.get("target_oid") or TRUEFLOW_AGE_DEFAULT_OID
    try:
        return int(raw_oid)
    except (TypeError, ValueError):
        return None


def _tfage_load_posteriors(args: dict[str, Any]) -> bool:
    checkbox = {part.strip().lower() for part in str(args.get("checkbox") or "").split(",") if part.strip()}
    return _as_bool(args.get("posteriors")) or _as_bool(args.get("posterior")) or "posteriors" in checkbox


def _tfage_normalize_curve_role(value: Any) -> str:
    raw = str(value or "").strip().lower()
    if raw in {"posterior", "posteriors"}:
        return "posterior"
    if raw in {"prior", "priors"}:
        return "prior"
    return "likelihood"


def _tfage_has_explicit_curve_role(args: dict[str, Any]) -> bool:
    return any(str(args.get(key) or "").strip() for key in ("curve_role", "role", "pdf_role", "product"))


def _tfage_requested_curve_role(args: dict[str, Any]) -> str:
    for key in ("curve_role", "role", "pdf_role", "product"):
        raw = str(args.get(key) or "").strip()
        if raw:
            return _tfage_normalize_curve_role(raw)
    return "posterior"


def _tfage_db_config(args: dict[str, Any], scope: str) -> dict[str, str]:
    if scope == "object":
        return {
            "host": (
                args.get("host")
                or os.environ.get("ATM_HOST")
                or os.environ.get("MOCA_HOST")
                or DEFAULT_HOST
            ),
            "username": (
                args.get("user")
                or args.get("username")
                or os.environ.get("ATM_USERNAME")
                or os.environ.get("ATM_USER")
                or os.environ.get("MOCA_USERNAME")
                or DEFAULT_USERNAME
            ),
            "password": (
                args.get("pwd")
                or args.get("password")
                or os.environ.get("ATM_PASSWORD")
                or os.environ.get("MOCA_PASSWORD")
                or DEFAULT_PASSWORD
            ),
            "dbname": (
                args.get("dbase")
                or args.get("db")
                or args.get("database")
                or os.environ.get("MOCA_DBNAME")
                or "mocadb_private_tables"
            ),
            "port": args.get("port") or os.environ.get("ATM_PORT") or os.environ.get("MOCA_PORT") or "3306",
        }
    return {
        "host": args.get("host") or os.environ.get("MOCA_HOST") or DEFAULT_HOST,
        "username": args.get("user") or args.get("username") or os.environ.get("MOCA_USERNAME") or DEFAULT_USERNAME,
        "password": args.get("pwd") or args.get("password") or os.environ.get("MOCA_PASSWORD") or DEFAULT_PASSWORD,
        "dbname": (
            args.get("dbase")
            or args.get("db")
            or args.get("database")
            or os.environ.get("MOCA_DBNAME")
            or DEFAULT_DBNAME
        ),
        "port": args.get("port") or os.environ.get("MOCA_PORT") or "3306",
    }


def _tfage_connection_string(args: dict[str, Any], scope: str) -> str:
    cfg = _tfage_db_config(args, scope)
    password = quote_plus(cfg["password"])
    return f"mysql+pymysql://{cfg['username']}:{password}@{cfg['host']}:{cfg['port']}/{cfg['dbname']}"


def _tfage_cache_key(args: dict[str, Any], scope: str, target: int | str | None) -> str:
    cfg = _tfage_db_config(args, scope)
    return "|".join([
        cfg["host"],
        cfg["username"],
        cfg["dbname"],
        cfg["port"],
        TRUEFLOW_AGE_CACHE_SCHEMA,
        scope,
        str(target or ""),
        _tfage_requested_curve_role(args),
        str(int(_tfage_has_explicit_curve_role(args))),
        str(int(_tfage_load_posteriors(args))),
    ])


def _tfage_table_exists(engine, table_name: str) -> bool:
    with engine.connect() as conn:
        return _db_table_exists(conn, table_name)


def _tfage_columns(engine, table_name: str) -> set[str]:
    with engine.connect() as conn:
        return _db_table_columns(conn, table_name)


def _tfage_qid(name: str) -> str:
    if not name.replace("_", "").isalnum():
        raise ValueError(f"Unsafe SQL identifier: {name!r}")
    return f"`{name}`"


def _tfage_fetch_age_rows(engine, scope: str, target: int | str) -> pd.DataFrame:
    age_table = "data_object_ages" if scope == "object" else "data_association_ages"
    target_col = "moca_oid" if scope == "object" else "moca_aid"
    if not _tfage_table_exists(engine, age_table):
        return pd.DataFrame()
    cols = _tfage_columns(engine, age_table)
    order_terms = []
    for col in ("adopted", "public_adopted", "adopt_asis", "public_adopt_asis"):
        if col in cols:
            order_terms.append(f"{_tfage_qid(col)} DESC")
    for col in ("modified_timestamp", "created_timestamp", "id"):
        if col in cols:
            order_terms.append(f"{_tfage_qid(col)} DESC")
    order_sql = ", ".join(order_terms) if order_terms else "1"
    query = text(f"""
        SELECT *
        FROM {_tfage_qid(age_table)}
        WHERE {_tfage_qid(target_col)} = :target
        ORDER BY {order_sql}
    """)
    with engine.connect() as conn:
        rows = conn.execute(query, {"target": target}).mappings().all()
    return pd.DataFrame(rows)


def _tfage_dtype(dtype: str | None, byte_order: str | None) -> np.dtype:
    dtype = dtype or "float32"
    byte_order = byte_order or "little"
    if dtype not in {"float32", "float64"}:
        dtype = "float32"
    prefix = "<" if byte_order != "big" else ">"
    return np.dtype(prefix + ("f4" if dtype == "float32" else "f8"))


def _tfage_decode_array(
    blob: bytes | memoryview,
    *,
    n_values: int,
    dtype: str | None,
    byte_order: str | None,
    compression: str | None,
    expected_sha256: str | None = None,
) -> np.ndarray:
    raw_blob = bytes(blob)
    raw = raw_blob if compression == "none" else zlib.decompress(raw_blob)
    if expected_sha256:
        actual = hashlib.sha256(raw).hexdigest()
        if actual != expected_sha256:
            raise ValueError("Blob SHA256 check failed")
    values = np.frombuffer(raw, dtype=_tfage_dtype(dtype, byte_order), count=int(n_values))
    return values.astype(float, copy=True)


def _tfage_normalize_pdf(age_myr: np.ndarray, pdf: np.ndarray) -> np.ndarray:
    age_myr = np.asarray(age_myr, dtype=float)
    pdf = np.asarray(pdf, dtype=float)
    ok = np.isfinite(age_myr) & np.isfinite(pdf) & (age_myr > 0)
    out = np.zeros_like(pdf, dtype=float)
    if np.count_nonzero(ok) < 2:
        return out
    clipped = np.clip(pdf[ok], 0.0, None)
    norm = float(_np_trapezoid(clipped, age_myr[ok]))
    if not math.isfinite(norm) or norm <= 0:
        return out
    out[ok] = clipped / norm
    return out


def _tfage_cdf_from_pdf(age_myr: np.ndarray, pdf: np.ndarray) -> np.ndarray:
    age_myr = np.asarray(age_myr, dtype=float)
    pdf = _tfage_normalize_pdf(age_myr, pdf)
    cdf = np.zeros_like(pdf, dtype=float)
    if age_myr.size < 2:
        return cdf
    order = np.argsort(age_myr)
    age_sorted = age_myr[order]
    pdf_sorted = pdf[order]
    increments = 0.5 * (pdf_sorted[1:] + pdf_sorted[:-1]) * np.diff(age_sorted)
    cdf_sorted = np.concatenate([[0.0], np.cumsum(increments)])
    if cdf_sorted[-1] > 0:
        cdf_sorted = cdf_sorted / cdf_sorted[-1]
    cdf[order] = np.clip(cdf_sorted, 0.0, 1.0)
    return cdf


def _tfage_percentiles(age_myr: np.ndarray, pdf: np.ndarray) -> tuple[float, float, float] | None:
    age_myr = np.asarray(age_myr, dtype=float)
    pdf = _tfage_normalize_pdf(age_myr, pdf)
    ok = np.isfinite(age_myr) & np.isfinite(pdf) & (age_myr > 0)
    if np.count_nonzero(ok) < 2:
        return None
    age = age_myr[ok]
    cdf = _tfage_cdf_from_pdf(age, pdf[ok])
    if not np.any(np.diff(cdf) > 0):
        return None
    return tuple(float(np.interp(p, cdf, age)) for p in (0.16, 0.5, 0.84))


def _tfage_log10_age_log_pdf_to_age_pdf(
    log10_age_grid: np.ndarray,
    log_pdf: np.ndarray,
) -> tuple[np.ndarray, np.ndarray]:
    log10_age_grid = np.asarray(log10_age_grid, dtype=float)
    log_pdf = np.asarray(log_pdf, dtype=float)
    ok = np.isfinite(log10_age_grid) & np.isfinite(log_pdf)
    if np.count_nonzero(ok) < 2:
        return np.array([], dtype=float), np.array([], dtype=float)
    log10_age_grid = log10_age_grid[ok]
    log_pdf = log_pdf[ok]
    order = np.argsort(log10_age_grid)
    log10_age_grid = log10_age_grid[order]
    log_pdf = log_pdf[order]
    log_age_pdf = np.exp(log_pdf - float(np.nanmax(log_pdf)))
    log_norm = float(_np_trapezoid(log_age_pdf, log10_age_grid))
    if not math.isfinite(log_norm) or log_norm <= 0:
        return np.array([], dtype=float), np.array([], dtype=float)
    log_age_pdf /= log_norm
    age_myr = np.power(10.0, log10_age_grid)
    age_pdf = log_age_pdf / (age_myr * np.log(10.0))
    return age_myr, _tfage_normalize_pdf(age_myr, age_pdf)


def _tfage_blob_curve_sort_key(curve: _TfAgeCurve) -> tuple[Any, ...]:
    meta = curve.metadata or {}
    return (
        meta.get("age_id"),
        meta.get("result_key"),
        meta.get("pdf_space"),
        meta.get("used_colors"),
    )


def _tfage_deduplicate_blob_curves(curves: list[_TfAgeCurve], *, preferred_role: str) -> list[_TfAgeCurve]:
    preferred_role = _tfage_normalize_curve_role(preferred_role)
    by_key: dict[tuple[Any, ...], _TfAgeCurve] = {}
    for curve in curves:
        key = _tfage_blob_curve_sort_key(curve)
        current = by_key.get(key)
        if current is None:
            by_key[key] = curve
            continue
        role = (curve.metadata or {}).get("curve_role")
        current_role = (current.metadata or {}).get("curve_role")
        if role == preferred_role and current_role != preferred_role:
            by_key[key] = curve
    return list(by_key.values())


def _tfage_curve_from_log_pdf_row(data: dict[str, Any], age_meta: dict[Any, dict[str, Any]]) -> _TfAgeCurve | None:
    try:
        grid = _tfage_decode_array(
            data["grid_blob"],
            n_values=int(data["grid_n_grid"]),
            dtype=data.get("grid_dtype"),
            byte_order=data.get("grid_byte_order"),
            compression=data.get("grid_compression"),
            expected_sha256=data.get("grid_sha256"),
        )
        if data.get("grid_coordinate") in (None, "", "log10_age_myr"):
            log10_age = grid
        elif data.get("grid_coordinate") in {"age_myr", "age"}:
            log10_age = np.log10(grid)
        else:
            log10_age = grid
        log_pdf = _tfage_decode_array(
            data["log_pdf_blob"],
            n_values=int(data["grid_n_grid"]),
            dtype=data.get("dtype"),
            byte_order=data.get("byte_order"),
            compression=data.get("compression"),
            expected_sha256=data.get("log_pdf_sha256"),
        )
        age, pdf = _tfage_log10_age_log_pdf_to_age_pdf(log10_age, log_pdf)
    except Exception as exc:
        return _TfAgeCurve(
            key=f"blob-decode-error-{data.get('id')}",
            label=f"Blob decode error id={data.get('id')}",
            source="MOCAFlows error",
            age_myr=np.array([], dtype=float),
            pdf_age=np.array([], dtype=float),
            metadata={"error": str(exc), "age_id": data.get("age_id")},
        )
    if age.size < 2 or not np.any(pdf > 0):
        return None

    meta = age_meta.get(data["age_id"], {})
    row_method = meta.get("calculation_method") or meta.get("method") or meta.get("method_detailed") or ""
    result_key = data.get("result_key") or row_method or "age_pdf"
    role = data.get("curve_role") or "posterior"
    extras = []
    if data.get("used_colors"):
        extras.append(str(data["used_colors"]))
    if data.get("n_contributors") is not None:
        extras.append(f"N={data['n_contributors']}")
    if data.get("prior_id") is not None:
        extras.append(f"prior={data['prior_id']}")
    label = f"{result_key} {role} (age_id={data['age_id']})"
    if row_method and row_method != result_key:
        label = f"{label}; {row_method}"
    if extras:
        label = f"{label}; {', '.join(extras)}"
    return _TfAgeCurve(
        key=f"blob-{data.get('id')}-{data.get('age_id')}-{data.get('result_key')}",
        label=label,
        source="MOCAFlows",
        age_myr=age,
        pdf_age=pdf,
        metadata={**data, "scalar_row": meta},
    )


def _tfage_fetch_hbm_member_stats(engine, scope: str, age_ids: Sequence[int]) -> dict[tuple[int, str], dict[str, Any]]:
    if scope != "association" or not age_ids:
        return {}
    table_name = "calc_association_age_hbm_member_probabilities"
    if not _tfage_table_exists(engine, table_name):
        return {}
    cols = _tfage_columns(engine, table_name)
    required = {"association_age_id", "result_key", "inlier_probability", "outlier_probability"}
    if not required.issubset(cols):
        return {}
    query = text(f"""
        SELECT association_age_id,
               result_key,
               COUNT(*) AS n_hbm_members,
               SUM(CASE WHEN inlier_probability < 0.5 THEN 1 ELSE 0 END) AS n_hbm_outliers,
               SUM(CASE WHEN inlier_probability < 0.5 THEN 1 ELSE 0 END) AS n_p_lt_0p50,
               SUM(CASE WHEN inlier_probability < 0.9 THEN 1 ELSE 0 END) AS n_p_lt_0p90,
               MIN(inlier_probability) AS min_p_inlier,
               MAX(outlier_probability) AS max_p_outlier
        FROM {_tfage_qid(table_name)}
        WHERE association_age_id IN :age_ids
        GROUP BY association_age_id, result_key
    """).bindparams(bindparam("age_ids", expanding=True))
    with engine.connect() as conn:
        rows = conn.execute(query, {"age_ids": [int(value) for value in age_ids]}).mappings().all()
    stats: dict[tuple[int, str], dict[str, Any]] = {}
    for row in rows:
        age_id = row.get("association_age_id")
        result_key = row.get("result_key")
        if age_id is None or result_key in (None, ""):
            continue
        stats[(int(age_id), str(result_key))] = {
            "n_hbm_members": _pythonize(row.get("n_hbm_members")),
            "n_hbm_outliers": _pythonize(row.get("n_hbm_outliers")),
            "n_p_lt_0p50": _pythonize(row.get("n_p_lt_0p50")),
            "n_p_lt_0p90": _pythonize(row.get("n_p_lt_0p90")),
            "min_p_inlier": _pythonize(row.get("min_p_inlier")),
            "max_p_outlier": _pythonize(row.get("max_p_outlier")),
        }
    return stats


def _tfage_merge_hbm_member_stats(curve: _TfAgeCurve, stats: Mapping[str, Any] | None) -> None:
    if not stats:
        return
    meta = curve.metadata or {}
    metadata_json = _tfage_parse_metadata_json(meta.get("metadata_json"))
    if not isinstance(metadata_json, dict):
        metadata_json = {}
    metadata_json.update({key: value for key, value in stats.items() if value is not None})
    meta["metadata_json"] = metadata_json
    curve.metadata = meta


def _tfage_fetch_referenced_prior_curves(
    engine,
    blob_table: str,
    age_ids: Sequence[int],
    age_meta: dict[Any, dict[str, Any]],
) -> list[_TfAgeCurve]:
    if not age_ids:
        return []
    if not (
        _tfage_table_exists(engine, blob_table)
        and _tfage_table_exists(engine, "calc_age_pdf_priors")
        and _tfage_table_exists(engine, "calc_age_pdf_grids")
    ):
        return []
    blob_cols = _tfage_columns(engine, blob_table)
    prior_cols = _tfage_columns(engine, "calc_age_pdf_priors")
    if not {"id", "age_id", "result_key", "prior_id"}.issubset(blob_cols):
        return []
    required_prior_cols = {"id", "prior_key", "grid_id", "pdf_space", "log_pdf_blob"}
    if not required_prior_cols.issubset(prior_cols):
        return []

    wanted_blob_cols = [
        "id",
        "age_id",
        "result_key",
        "used_colors",
        "n_contributors",
        "curve_role",
        "peak_age_myr",
        "age_lo_myr",
        "age_hi_myr",
        "peak_log10_age_myr",
        "log10_age_lo",
        "log10_age_hi",
        "eps_peak",
        "eps_mean",
        "eps_lo",
        "eps_hi",
        "metadata_json",
    ]
    wanted_prior_cols = [
        "id",
        "prior_key",
        "pdf_space",
        "dtype",
        "byte_order",
        "compression",
        "compression_level",
        "log_pdf_sha256",
        "log_pdf_blob",
        "source",
        "metadata_json",
    ]
    blob_aliases = {
        "id": "parent_id",
        "curve_role": "parent_curve_role",
        "metadata_json": "parent_metadata_json",
    }
    select_blob = ",\n               ".join(
        f"b.{_tfage_qid(col)} AS {_tfage_qid(blob_aliases.get(col, col))}"
        for col in wanted_blob_cols
        if col in blob_cols
    )
    prior_aliases = {"id": "prior_id"}
    select_prior = ",\n               ".join(
        f"p.{_tfage_qid(col)} AS {_tfage_qid(prior_aliases.get(col, col))}"
        for col in wanted_prior_cols
        if col in prior_cols
    )
    query = text(f"""
        SELECT {select_blob},
               {select_prior},
               g.id AS grid_row_id,
               g.coordinate AS grid_coordinate,
               g.n_grid AS grid_n_grid,
               g.dtype AS grid_dtype,
               g.byte_order AS grid_byte_order,
               g.compression AS grid_compression,
               g.grid_sha256 AS grid_sha256,
               g.grid_blob AS grid_blob
        FROM {_tfage_qid(blob_table)} AS b
        JOIN calc_age_pdf_priors AS p
            ON p.id = b.prior_id
        JOIN calc_age_pdf_grids AS g
            ON g.id = p.grid_id
        WHERE b.age_id IN :age_ids
            AND b.prior_id IS NOT NULL
        ORDER BY b.age_id, b.result_key, p.id, b.curve_role, b.id
    """).bindparams(bindparam("age_ids", expanding=True))
    with engine.connect() as conn:
        rows = conn.execute(query, {"age_ids": [int(value) for value in age_ids]}).mappings().all()

    curves: list[_TfAgeCurve] = []
    for row in rows:
        row_data = dict(row)
        row_data["id"] = f"prior-{row_data.get('prior_id')}-parent-{row_data.get('parent_id')}"
        row_data["curve_role"] = "prior"
        curve = _tfage_curve_from_log_pdf_row(row_data, age_meta)
        if curve is not None:
            curves.append(curve)
    return _tfage_deduplicate_blob_curves(curves, preferred_role="prior")


def _tfage_fetch_blob_curves(
    engine,
    scope: str,
    age_rows: pd.DataFrame,
    *,
    curve_role: str = "likelihood",
    include_likelihood_fallback: bool = False,
    include_hbm_member_stats: bool = True,
) -> list[_TfAgeCurve]:
    if age_rows.empty or "id" not in age_rows:
        return []
    blob_table = "calc_object_age_pdf_blobs" if scope == "object" else "calc_association_age_pdf_blobs"
    if not (_tfage_table_exists(engine, blob_table) and _tfage_table_exists(engine, "calc_age_pdf_grids")):
        return []

    age_ids = [int(v) for v in age_rows["id"].dropna().astype(int).unique()]
    if not age_ids:
        return []

    blob_cols = _tfage_columns(engine, blob_table)
    required = {"id", "age_id", "grid_id", "result_key", "curve_role", "pdf_space", "log_pdf_blob"}
    if not required.issubset(blob_cols):
        return []
    requested_role = _tfage_normalize_curve_role(curve_role)
    age_meta = age_rows.set_index("id", drop=False).to_dict(orient="index")
    hbm_member_stats = _tfage_fetch_hbm_member_stats(engine, scope, age_ids) if include_hbm_member_stats else {}
    if requested_role == "prior":
        curves = _tfage_fetch_referenced_prior_curves(engine, blob_table, age_ids, age_meta)
        for curve in curves:
            meta = curve.metadata or {}
            stats = None
            if meta.get("age_id") is not None and meta.get("result_key") not in (None, ""):
                stats = hbm_member_stats.get((int(meta.get("age_id")), str(meta.get("result_key"))))
            _tfage_merge_hbm_member_stats(curve, stats)
        return curves

    wanted_blob_cols = [
        "id",
        "age_id",
        "grid_id",
        "result_key",
        "curve_role",
        "pdf_space",
        "dtype",
        "byte_order",
        "compression",
        "compression_level",
        "log_pdf_sha256",
        "log_pdf_blob",
        "log_pdf_floor",
        "peak_age_myr",
        "age_lo_myr",
        "age_hi_myr",
        "peak_log10_age_myr",
        "log10_age_lo",
        "log10_age_hi",
        "n_contributors",
        "used_colors",
        "metadata_json",
        "eps_peak",
        "eps_mean",
        "eps_lo",
        "eps_hi",
        "prior_id",
    ]
    select_blob = ",\n               ".join(
        f"b.{_tfage_qid(col)} AS {_tfage_qid(col)}" for col in wanted_blob_cols if col in blob_cols
    )
    role_values = (
        ("posterior", "likelihood")
        if requested_role == "posterior" and include_likelihood_fallback
        else (requested_role,)
    )
    query = text(f"""
        SELECT {select_blob},
               g.id AS grid_row_id,
               g.coordinate AS grid_coordinate,
               g.n_grid AS grid_n_grid,
               g.dtype AS grid_dtype,
               g.byte_order AS grid_byte_order,
               g.compression AS grid_compression,
               g.grid_sha256 AS grid_sha256,
               g.grid_blob AS grid_blob
        FROM {_tfage_qid(blob_table)} AS b
        JOIN calc_age_pdf_grids AS g
            ON g.id = b.grid_id
        WHERE b.age_id IN :age_ids
            AND b.curve_role IN :role_values
        ORDER BY b.age_id, b.result_key, b.curve_role, b.id
    """).bindparams(bindparam("age_ids", expanding=True), bindparam("role_values", expanding=True))
    with engine.connect() as conn:
        rows = conn.execute(query, {"age_ids": age_ids, "role_values": role_values}).mappings().all()

    curves = []
    for row in rows:
        row_data = dict(row)
        curve = _tfage_curve_from_log_pdf_row(row_data, age_meta)
        if curve is not None:
            stats = hbm_member_stats.get((int(row_data.get("age_id")), str(row_data.get("result_key"))))
            _tfage_merge_hbm_member_stats(curve, stats)
            curves.append(curve)
    return _tfage_deduplicate_blob_curves(curves, preferred_role=requested_role)


def _tfage_fetch_legacy_pdf_curves(engine, scope: str, age_rows: pd.DataFrame) -> list[_TfAgeCurve]:
    if age_rows.empty or "id" not in age_rows:
        return []
    pdf_table = "calc_object_age_pdfs" if scope == "object" else "calc_association_age_pdfs"
    if not _tfage_table_exists(engine, pdf_table):
        return []
    cols = _tfage_columns(engine, pdf_table)
    if not {"age_id", "age_myr", "log_probability_density"}.issubset(cols):
        return []
    age_ids = [int(v) for v in age_rows["id"].dropna().astype(int).unique()]
    if not age_ids:
        return []
    query = text(f"""
        SELECT age_id, age_myr, log_probability_density
        FROM {_tfage_qid(pdf_table)}
        WHERE age_id IN :age_ids
        ORDER BY age_id, age_myr
    """).bindparams(bindparam("age_ids", expanding=True))
    with engine.connect() as conn:
        rows = conn.execute(query, {"age_ids": age_ids}).mappings().all()
    pdf_rows = pd.DataFrame(rows)
    if pdf_rows.empty:
        return []
    age_meta = age_rows.set_index("id", drop=False).to_dict(orient="index")
    curves = []
    for age_id, sub in pdf_rows.groupby("age_id", sort=False):
        sub = sub.dropna(subset=["age_myr", "log_probability_density"]).copy()
        sub = sub[sub["age_myr"] > 0]
        if sub.shape[0] < 2:
            continue
        sub.sort_values("age_myr", inplace=True)
        age = sub["age_myr"].to_numpy(dtype=float)
        log_pdf = sub["log_probability_density"].to_numpy(dtype=float)
        pdf = np.exp(log_pdf - float(np.nanmax(log_pdf)))
        pdf = _tfage_normalize_pdf(age, pdf)
        if not np.any(pdf > 0):
            continue
        meta = age_meta.get(age_id, {})
        method = meta.get("calculation_method") or meta.get("method") or meta.get("method_detailed") or "legacy age PDF"
        curves.append(_TfAgeCurve(
            key=f"legacy-{age_id}",
            label=f"{method} legacy PDF (age_id={age_id})",
            source="Legacy",
            age_myr=age,
            pdf_age=pdf,
            metadata={"age_id": age_id, "scalar_row": meta},
        ))
    return curves


def _tfage_first_number(row: dict[str, Any], names: tuple[str, ...]) -> float | None:
    for name in names:
        if name in row:
            value = _safe_float(row.get(name))
            if value is not None:
                return value
    return None


def _tfage_scalar_age_summary(row: dict[str, Any]) -> tuple[float, float, float, str] | None:
    center = _tfage_first_number(row, ("age_myr", "age", "age_value_myr", "best_age_myr"))
    note = "stored uncertainty"
    if center is None:
        log_age_yr = _tfage_first_number(row, ("log_age_yr", "log10_age_yr"))
        if log_age_yr is not None:
            center = 10.0**log_age_yr / 1e6
    if center is None or center <= 0:
        return None

    lo_unc = _tfage_first_number(row, ("age_myr_unc_neg", "age_myr_err_neg", "age_myr_minus", "age_unc_neg", "age_err_neg"))
    hi_unc = _tfage_first_number(row, ("age_myr_unc_pos", "age_myr_err_pos", "age_myr_plus", "age_unc_pos", "age_err_pos"))
    sym_unc = _tfage_first_number(row, ("age_myr_unc", "age_unc", "age_err", "uncertainty_myr"))
    if lo_unc is None and hi_unc is None and sym_unc is not None:
        lo_unc = sym_unc
        hi_unc = sym_unc

    log_center = math.log10(center * 1e6)
    log_lo = _tfage_first_number(row, ("log_age_unc_neg", "log_age_yr_unc_neg", "log10_age_yr_unc_neg"))
    log_hi = _tfage_first_number(row, ("log_age_unc_pos", "log_age_yr_unc_pos", "log10_age_yr_unc_pos"))
    log_sym = _tfage_first_number(row, ("log_age_unc", "log_age_yr_unc", "log10_age_yr_unc"))
    if log_lo is None and log_hi is None and log_sym is not None:
        log_lo = log_sym
        log_hi = log_sym
    if lo_unc is None and log_lo is not None:
        lo_unc = center - (10.0 ** (log_center - abs(log_lo)) / 1e6)
    if hi_unc is None and log_hi is not None:
        hi_unc = (10.0 ** (log_center + abs(log_hi)) / 1e6) - center

    if lo_unc is None or lo_unc <= 0:
        lo_unc = 0.10 * center
        note = "fallback 10% uncertainty"
    if hi_unc is None or hi_unc <= 0:
        hi_unc = 0.10 * center
        note = "fallback 10% uncertainty"
    return float(center), float(abs(lo_unc)), float(abs(hi_unc)), note


def _tfage_first_text(row: dict[str, Any], names: tuple[str, ...]) -> str:
    for name in names:
        if name not in row:
            continue
        value = row.get(name)
        if value is None:
            continue
        text_value = str(value).strip()
        if text_value and text_value.lower() not in {"nan", "none", "null"}:
            return text_value
    return ""


def _tfage_ads_url(bibcode: str = "", query: str = "") -> str:
    bibcode = str(bibcode or "").strip()
    if bibcode:
        return f"https://ui.adsabs.harvard.edu/abs/{quote_plus(bibcode)}/abstract"
    query = str(query or "").strip()
    return f"https://ui.adsabs.harvard.edu/search/q={quote_plus(query)}" if query else ""


def _tfage_publication_info(engine, row: dict[str, Any]) -> dict[str, str]:
    info = {
        "publication_name": _tfage_first_text(row, ("publication_name", "reference_name", "reference")),
        "publication_bibcode": _tfage_first_text(row, ("publication_bibcode", "bibcode")),
    }
    moca_pid = _tfage_first_text(row, ("moca_pid",))
    if not moca_pid or not _tfage_table_exists(engine, "moca_publications"):
        return info

    cols = _tfage_columns(engine, "moca_publications")
    if "moca_pid" not in cols:
        return info
    select_terms = ["moca_pid"]
    if "name" in cols:
        select_terms.append("name AS publication_name")
    if "bibcode" in cols:
        select_terms.append("bibcode AS publication_bibcode")
    if len(select_terms) == 1:
        return info

    query = text(f"""
        SELECT {", ".join(select_terms)}
        FROM moca_publications
        WHERE moca_pid = :moca_pid
        LIMIT 1
    """)
    with engine.connect() as conn:
        pub = conn.execute(query, {"moca_pid": moca_pid}).mappings().first()
    if pub:
        for key in ("publication_name", "publication_bibcode"):
            text_value = _tfage_first_text(dict(pub), (key,))
            if text_value:
                info[key] = text_value
    return info


def _tfage_adopted_age_row(age_rows: pd.DataFrame) -> tuple[dict[str, Any], str] | None:
    if age_rows.empty:
        return None
    rows = age_rows.to_dict(orient="records")
    for flag, label in (
        ("adopted", "adopted"),
        ("public_adopted", "public adopted"),
        ("adopt_asis", "adopted as-is"),
        ("public_adopt_asis", "public adopted as-is"),
    ):
        for row in rows:
            if flag in row and _as_bool(row.get(flag)):
                return row, label
    return None


def _tfage_age_marker_payload(
    engine,
    row: dict[str, Any],
    *,
    adoption_flag: str,
    method: str | None = None,
    kind: str = "adopted",
    extra: dict[str, Any] | None = None,
) -> dict[str, Any] | None:
    summary = _tfage_scalar_age_summary(row)
    if not summary:
        return None
    center, lo_unc, hi_unc, note = summary
    method = method or _tfage_first_text(row, ("calculation_method", "method", "method_detailed")) or "adopted age"
    moca_pid = _tfage_first_text(row, ("moca_pid",))
    publication = _tfage_publication_info(engine, row)
    publication_name = publication.get("publication_name") or _tfage_first_text(row, ("origin",)) or moca_pid
    publication_bibcode = publication.get("publication_bibcode") or ""
    reference_query = publication_name or moca_pid or publication_bibcode
    return {
        "age_id": _pythonize(row.get("id")),
        "value_myr": float(center),
        "uncertainty_minus_myr": float(lo_unc),
        "uncertainty_plus_myr": float(hi_unc),
        "lower_myr": max(float(center - lo_unc), 1e-6),
        "upper_myr": float(center + hi_unc),
        "uncertainty_note": note,
        "adoption_flag": adoption_flag,
        "kind": kind,
        "method": method,
        "moca_pid": moca_pid,
        "reference_name": publication_name or publication_bibcode or moca_pid or "ADS reference",
        "reference_bibcode": publication_bibcode,
        "reference_query": reference_query,
        "ads_url": _tfage_ads_url(publication_bibcode, reference_query),
        "comments": _tfage_first_text(row, ("comments",)),
        **(extra or {}),
    }


def _tfage_adopted_age_payload(engine, age_rows: pd.DataFrame) -> dict[str, Any] | None:
    selected = _tfage_adopted_age_row(age_rows)
    if not selected:
        return None
    row, adoption_flag = selected
    return _tfage_age_marker_payload(engine, row, adoption_flag=adoption_flag, kind="adopted")


def _tfage_row_adoption_flag(row: dict[str, Any]) -> str:
    labels = []
    for flag, label in (
        ("adopted", "adopted"),
        ("public_adopted", "public adopted"),
        ("adopt_asis", "adopted as-is"),
        ("public_adopt_asis", "public adopted as-is"),
    ):
        if flag in row and _as_bool(row.get(flag)):
            labels.append(label)
    return ", ".join(labels)


def _tfage_age_measurements_payload(engine, age_rows: pd.DataFrame) -> list[dict[str, Any]]:
    if age_rows.empty:
        return []
    measurements: list[dict[str, Any]] = []
    for row in age_rows.to_dict(orient="records"):
        marker = _tfage_age_marker_payload(
            engine,
            row,
            adoption_flag=_tfage_row_adoption_flag(row),
            kind="measurement",
        )
        if not marker:
            continue
        marker["is_adopted"] = bool(_tfage_row_adoption_flag(row))
        marker["quality_flag"] = _pythonize(row.get("quality_flag"))
        marker["origin"] = _pythonize(row.get("origin"))
        marker["method_short"] = _pythonize(row.get("method_short"))
        marker["method_detailed"] = _pythonize(row.get("method_detailed"))
        measurements.append(marker)
    measurements.sort(
        key=lambda item: (
            not bool(item.get("is_adopted")),
            float(item.get("value_myr") or 0.0),
            str(item.get("method") or ""),
        )
    )
    return measurements


def _tfage_private_schema(args: dict[str, Any], scope: str) -> bool:
    return str(_tfage_db_config(args, scope)["dbname"]).strip("`").lower() == "mocadb_private_tables"


def _tfage_membership_tables_available(engine) -> bool:
    required_tables = {"calc_banyan_sigma", "moca_banyan_sigma_models", "data_association_ages"}
    return all(_tfage_table_exists(engine, table_name) for table_name in required_tables)


def _tfage_membership_age_payload_from_engine(
    engine,
    target: int | str | None,
    *,
    private_schema: bool,
) -> dict[str, Any] | None:
    if target in (None, "") or not _tfage_membership_tables_available(engine):
        return None
    cbs_cols = _tfage_columns(engine, "calc_banyan_sigma")
    model_cols = _tfage_columns(engine, "moca_banyan_sigma_models")
    age_cols = _tfage_columns(engine, "data_association_ages")
    if not {"moca_oid", "moca_aid", "moca_bsmdid", "max_observables", "ya_prob"}.issubset(cbs_cols):
        return None
    if not {"moca_bsmdid", "adopted"}.issubset(model_cols):
        return None
    if not {"moca_aid", "age_myr", "adopted"}.issubset(age_cols):
        return None

    wanted_age_cols = [
        "id",
        "moca_aid",
        "age_myr",
        "age",
        "age_value_myr",
        "best_age_myr",
        "log_age_yr",
        "log10_age_yr",
        "age_myr_unc_neg",
        "age_myr_err_neg",
        "age_myr_minus",
        "age_unc_neg",
        "age_err_neg",
        "age_myr_unc_pos",
        "age_myr_err_pos",
        "age_myr_plus",
        "age_unc_pos",
        "age_err_pos",
        "age_myr_unc",
        "age_unc",
        "age_err",
        "uncertainty_myr",
        "log_age_unc_neg",
        "log_age_yr_unc_neg",
        "log10_age_yr_unc_neg",
        "log_age_unc_pos",
        "log_age_yr_unc_pos",
        "log10_age_yr_unc_pos",
        "log_age_unc",
        "log_age_yr_unc",
        "log10_age_yr_unc",
        "calculation_method",
        "method",
        "method_detailed",
        "moca_pid",
        "origin",
        "comments",
        "bibcode",
        "adopted",
        "public_adopted",
        "adopt_asis",
        "public_adopt_asis",
    ]
    age_select = ",\n               ".join(
        f"daa.{_tfage_qid(col)} AS {_tfage_qid(col)}" for col in wanted_age_cols if col in age_cols
    )
    if not age_select:
        return None

    cbs_public_filter = (
        "AND cbs.is_public = 1"
        if private_schema and "is_public" in cbs_cols
        else ""
    )
    cbs_id_select = "cbs.id AS membership_banyan_id," if "id" in cbs_cols else "NULL AS membership_banyan_id,"
    cbs_observables_select = "cbs.observables AS membership_observables," if "observables" in cbs_cols else "NULL AS membership_observables,"
    cbs_best_hyp_select = "cbs.best_hyp AS membership_best_hyp," if "best_hyp" in cbs_cols else "NULL AS membership_best_hyp,"
    cbs_best_ya_select = "cbs.best_ya AS membership_best_ya" if "best_ya" in cbs_cols else "NULL AS membership_best_ya"
    cbs_id_order = "cbs.id DESC," if "id" in cbs_cols else ""
    age_id_order = "daa.id DESC" if "id" in age_cols else "daa.age_myr DESC"
    age_ignore_filter = "AND COALESCE(daa.ignored, 0) = 0" if "ignored" in age_cols else ""
    assoc_name_join = ""
    assoc_name_select = "NULL AS membership_name,"
    if _tfage_table_exists(engine, "moca_associations"):
        assoc_cols = _tfage_columns(engine, "moca_associations")
        if {"moca_aid", "name"}.issubset(assoc_cols):
            assoc_name_join = "LEFT JOIN moca_associations ma ON ma.moca_aid = cbs.moca_aid"
            assoc_name_select = "ma.name AS membership_name,"

    query = text(f"""
        SELECT
               {age_select},
               {cbs_id_select}
               cbs.moca_aid AS membership_moca_aid,
               cbs.moca_bsmdid AS membership_moca_bsmdid,
               cbs.ya_prob AS membership_ya_prob,
               {cbs_observables_select}
               {assoc_name_select}
               {cbs_best_hyp_select}
               {cbs_best_ya_select}
        FROM calc_banyan_sigma cbs
        JOIN data_association_ages daa
            ON daa.moca_aid = cbs.moca_aid
        {assoc_name_join}
        WHERE cbs.moca_oid = :moca_oid
            AND cbs.max_observables = 1
            AND cbs.moca_aid IS NOT NULL
            AND cbs.moca_aid <> ''
            AND UPPER(cbs.moca_aid) <> 'FIELD'
            AND cbs.ya_prob >= 80
            AND cbs.moca_bsmdid = (
                SELECT moca_bsmdid
                FROM moca_banyan_sigma_models
                WHERE adopted = 1
                ORDER BY moca_bsmdid DESC
                LIMIT 1
            )
            {cbs_public_filter}
            AND daa.age_myr IS NOT NULL
            AND daa.age_myr > 0
            AND daa.adopted = 1
            {age_ignore_filter}
        ORDER BY cbs.ya_prob DESC, {cbs_id_order} {age_id_order}
        LIMIT 1
    """)
    with engine.connect() as conn:
        row = conn.execute(query, {"moca_oid": int(target)}).mappings().first()
    if not row:
        return None

    data = dict(row)
    moca_aid = _tfage_first_text(data, ("membership_moca_aid", "moca_aid"))
    membership_name = _tfage_first_text(data, ("membership_name",))
    ya_prob = _safe_float(data.get("membership_ya_prob"))
    membership_label = f"{moca_aid}; {membership_name}" if moca_aid and membership_name else (moca_aid or membership_name)
    if ya_prob is not None and membership_label:
        method = f"BANYAN Sigma membership age from {membership_label} (YA={ya_prob:.1f}%)"
    elif membership_label:
        method = f"BANYAN Sigma membership age from {membership_label}"
    else:
        method = "BANYAN Sigma membership age"
    return _tfage_age_marker_payload(
        engine,
        data,
        adoption_flag="membership adopted association age",
        method=method,
        kind="membership",
        extra={
            "membership_moca_aid": moca_aid,
            "membership_name": membership_name,
            "membership_ya_prob": ya_prob,
            "membership_moca_bsmdid": _pythonize(data.get("membership_moca_bsmdid")),
            "membership_banyan_id": _pythonize(data.get("membership_banyan_id")),
            "membership_observables": _pythonize(data.get("membership_observables")),
            "membership_best_hyp": _pythonize(data.get("membership_best_hyp")),
            "membership_best_ya": _pythonize(data.get("membership_best_ya")),
        },
    )


def _tfage_membership_age_payload(engine, args: dict[str, Any], target: int | str | None) -> dict[str, Any] | None:
    if target in (None, ""):
        return None
    if _tfage_membership_tables_available(engine):
        return _tfage_membership_age_payload_from_engine(
            engine,
            target,
            private_schema=_tfage_private_schema(args, "object"),
        )

    try:
        metadata_engine = _engine(_connection_string(args))
    except Exception:
        return None
    if not _tfage_membership_tables_available(metadata_engine):
        return None
    return _tfage_membership_age_payload_from_engine(
        metadata_engine,
        target,
        private_schema=_is_private_db(args),
    )


def _tfage_gaussian_grid(age_rows: pd.DataFrame, stored_curves: list[_TfAgeCurve]) -> np.ndarray:
    candidates: list[float] = []
    for curve in stored_curves:
        if curve.age_myr.size:
            good = curve.age_myr[np.isfinite(curve.age_myr) & (curve.age_myr > 0)]
            if good.size:
                candidates.extend([float(np.nanmin(good)), float(np.nanmax(good))])
    for row in age_rows.to_dict(orient="records"):
        summary = _tfage_scalar_age_summary(row)
        if not summary:
            continue
        center, lo_unc, hi_unc, _ = summary
        candidates.extend([max(center - 6.0 * lo_unc, 0.02), center + 6.0 * hi_unc])
    if not candidates:
        return np.geomspace(0.5, 20000.0, 1200)
    amin = max(0.02, min(candidates))
    amax = max(amin * 10.0, max(candidates))
    amin = max(0.02, amin / 1.5)
    amax = min(50000.0, amax * 1.5)
    return np.geomspace(amin, amax, 1400)


def _tfage_stored_pdf_age_ids(stored_curves: list[_TfAgeCurve]) -> set[int]:
    age_ids: set[int] = set()
    for curve in stored_curves:
        meta = curve.metadata or {}
        age_id = meta.get("age_id")
        if age_id is None:
            scalar = meta.get("scalar_row") or {}
            age_id = scalar.get("id")
        try:
            if age_id is not None:
                age_ids.add(int(age_id))
        except (TypeError, ValueError):
            continue
    return age_ids


def _tfage_all_stored_pdf_age_ids(engine, scope: str, age_rows: pd.DataFrame) -> set[int]:
    if age_rows.empty or "id" not in age_rows:
        return set()
    age_ids = [int(v) for v in age_rows["id"].dropna().astype(int).unique()]
    if not age_ids:
        return set()
    out: set[int] = set()
    for table_name in (
        "calc_object_age_pdf_blobs" if scope == "object" else "calc_association_age_pdf_blobs",
        "calc_object_age_pdfs" if scope == "object" else "calc_association_age_pdfs",
    ):
        if not _tfage_table_exists(engine, table_name):
            continue
        cols = _tfage_columns(engine, table_name)
        if "age_id" not in cols:
            continue
        query = text(f"""
            SELECT DISTINCT age_id
            FROM {_tfage_qid(table_name)}
            WHERE age_id IN :age_ids
        """).bindparams(bindparam("age_ids", expanding=True))
        with engine.connect() as conn:
            out.update(int(row[0]) for row in conn.execute(query, {"age_ids": age_ids}))
    return out


def _tfage_scalar_gaussian_curves(
    age_rows: pd.DataFrame,
    stored_curves: list[_TfAgeCurve],
    skip_age_ids: set[int] | None = None,
) -> list[_TfAgeCurve]:
    if age_rows.empty:
        return []
    skip_age_ids = skip_age_ids or set()
    grid = _tfage_gaussian_grid(age_rows, stored_curves)
    curves = []
    for row in age_rows.to_dict(orient="records"):
        age_id_raw = row.get("id")
        try:
            age_id_int = int(age_id_raw) if age_id_raw is not None else None
        except (TypeError, ValueError):
            age_id_int = None
        if age_id_int is not None and age_id_int in skip_age_ids:
            continue
        summary = _tfage_scalar_age_summary(row)
        if not summary:
            continue
        center, lo_unc, hi_unc, note = summary
        sigma = np.where(grid < center, lo_unc, hi_unc)
        pdf = np.exp(-0.5 * ((grid - center) / sigma) ** 2)
        pdf = _tfage_normalize_pdf(grid, pdf)
        if not np.any(pdf > 0):
            continue
        method = row.get("calculation_method") or row.get("method") or row.get("method_detailed") or "scalar age"
        age_id = row.get("id", "unknown")
        curves.append(_TfAgeCurve(
            key=f"gaussian-{age_id}",
            label=f"{method} asymmetric Gaussian (age_id={age_id})",
            source="Scalar Gaussian",
            age_myr=grid,
            pdf_age=pdf,
            metadata={
                "age_id": age_id,
                "age_myr": center,
                "age_myr_unc_neg": lo_unc,
                "age_myr_unc_pos": hi_unc,
                "uncertainty_note": note,
                "scalar_row": row,
            },
        ))
    return curves


def _tfage_is_hbm_mocaflows_curve(curve: _TfAgeCurve) -> bool:
    meta = curve.metadata or {}
    scalar = meta.get("scalar_row") or {}
    values = [
        meta.get("result_key"),
        meta.get("metadata_json"),
        scalar.get("calculation_method"),
        scalar.get("method"),
        scalar.get("method_detailed"),
        scalar.get("comments"),
        scalar.get("origin"),
    ]
    text_blob = " ".join(str(value).lower() for value in values if value not in (None, ""))
    calc_method = str(scalar.get("calculation_method") or "").lower()
    return (
        calc_method.startswith("mfhbm")
        or "hbm" in text_blob
        or "hierarchical bayesian" in text_blob
        or "hierarchical_bayesian" in text_blob
        or "outlier rejection" in text_blob
    )


def _tfage_load_curves(
    engine,
    scope: str,
    target: int | str,
    *,
    curve_role: str = "likelihood",
    load_blob_posteriors: bool = False,
) -> tuple[pd.DataFrame, list[_TfAgeCurve]]:
    age_rows = _tfage_fetch_age_rows(engine, scope, target)
    requested_role = _tfage_normalize_curve_role(curve_role)
    blob_curves = _tfage_fetch_blob_curves(
        engine,
        scope,
        age_rows,
        curve_role=requested_role,
        include_likelihood_fallback=bool(load_blob_posteriors and requested_role == "posterior"),
    )
    legacy_curves = _tfage_fetch_legacy_pdf_curves(engine, scope, age_rows)
    stored_curves = blob_curves + legacy_curves
    skip_age_ids = _tfage_all_stored_pdf_age_ids(engine, scope, age_rows)
    skip_age_ids.update(_tfage_stored_pdf_age_ids(stored_curves))
    scalar_curves = _tfage_scalar_gaussian_curves(age_rows, stored_curves, skip_age_ids=skip_age_ids)
    return age_rows, blob_curves + legacy_curves + scalar_curves


def _tfage_displayable_curves(curves: list[_TfAgeCurve]) -> list[_TfAgeCurve]:
    return [
        curve for curve in curves
        if curve.source != "MOCAFlows error" and curve.age_myr.size > 1 and np.any(curve.pdf_age > 0)
    ]


def _tfage_object_fallback_engine(args: dict[str, Any]):
    primary_cfg = _tfage_db_config(args, "object")
    fallback_cfg = _db_config(args)
    comparable_keys = ("host", "username", "dbname", "port")
    if all(str(primary_cfg.get(key) or "") == str(fallback_cfg.get(key) or "") for key in comparable_keys):
        return None
    try:
        return _engine(_connection_string(args))
    except Exception:
        return None


def _tfage_curve_summary_row(curve: _TfAgeCurve) -> dict[str, Any]:
    pct = _tfage_percentiles(curve.age_myr, curve.pdf_age)
    meta = curve.metadata or {}
    scalar = meta.get("scalar_row") or {}
    if pct:
        age16, age50, age84 = pct
        age_text = f"{age50:.3g} (+{age84 - age50:.3g}/-{age50 - age16:.3g}) Myr"
    else:
        age_text = ""
    return {
        "curve": curve.label,
        "source": curve.source,
        "age": age_text,
        "calculation_method": scalar.get("calculation_method", ""),
        "moca_pid": scalar.get("moca_pid", ""),
        "adopted": scalar.get("adopted", ""),
        "public_adopted": scalar.get("public_adopted", ""),
        "comments": scalar.get("comments", ""),
    }


def _tfage_parse_metadata_json(value: Any) -> Any:
    if value in (None, ""):
        return None
    if isinstance(value, (dict, list)):
        return _json_clean(value)
    try:
        return _json_clean(json.loads(str(value)))
    except Exception:
        return _pythonize(value)


def _tfage_curve_payload(curve: _TfAgeCurve) -> dict[str, Any]:
    meta = curve.metadata or {}
    scalar = meta.get("scalar_row") or {}
    age = np.asarray(curve.age_myr, dtype=float)
    pdf = _tfage_normalize_pdf(age, np.asarray(curve.pdf_age, dtype=float))
    ok = np.isfinite(age) & np.isfinite(pdf) & (age > 0)
    age = age[ok]
    pdf = pdf[ok]
    return {
        "key": curve.key,
        "label": curve.label,
        "source": curve.source,
        "age_myr": [float(value) for value in age],
        "pdf_age": [float(value) for value in pdf],
        "is_hbm_mocaflows": bool(_tfage_is_hbm_mocaflows_curve(curve)),
        "summary": _tfage_curve_summary_row(curve),
        "metadata": {
            "age_id": _pythonize(meta.get("age_id") if meta.get("age_id") is not None else scalar.get("id")),
            "result_key": _pythonize(meta.get("result_key")),
            "curve_role": _pythonize(meta.get("curve_role")),
            "pdf_space": _pythonize(meta.get("pdf_space")),
            "used_colors": _pythonize(meta.get("used_colors")),
            "n_contributors": _pythonize(meta.get("n_contributors")),
            "peak_age_myr": _pythonize(meta.get("peak_age_myr")),
            "age_lo_myr": _pythonize(meta.get("age_lo_myr")),
            "age_hi_myr": _pythonize(meta.get("age_hi_myr")),
            "peak_log10_age_myr": _pythonize(meta.get("peak_log10_age_myr")),
            "log10_age_lo": _pythonize(meta.get("log10_age_lo")),
            "log10_age_hi": _pythonize(meta.get("log10_age_hi")),
            "eps_peak": _pythonize(meta.get("eps_peak")),
            "eps_mean": _pythonize(meta.get("eps_mean")),
            "eps_lo": _pythonize(meta.get("eps_lo")),
            "eps_hi": _pythonize(meta.get("eps_hi")),
            "prior_id": _pythonize(meta.get("prior_id")),
            "metadata_json": _tfage_parse_metadata_json(meta.get("metadata_json")),
            "moca_pid": _pythonize(scalar.get("moca_pid")),
            "calculation_method": _pythonize(scalar.get("calculation_method")),
            "method": _pythonize(scalar.get("method")),
            "method_detailed": _pythonize(scalar.get("method_detailed")),
            "comments": _pythonize(scalar.get("comments")),
            "created_timestamp": _pythonize(scalar.get("created_timestamp")),
            "modified_timestamp": _pythonize(scalar.get("modified_timestamp")),
            "age_row_id": _pythonize(scalar.get("id")),
            "age_myr": _pythonize(scalar.get("age_myr")),
            "age_myr_unc": _pythonize(scalar.get("age_myr_unc")),
            "age_myr_unc_pos": _pythonize(scalar.get("age_myr_unc_pos")),
            "age_myr_unc_neg": _pythonize(scalar.get("age_myr_unc_neg")),
        },
    }


def _tfage_object_info_from_engine(engine, target: int) -> dict[str, Any]:
    info: dict[str, Any] = {"moca_oid": int(target)}
    has_objects = _tfage_table_exists(engine, "moca_objects")
    has_designations = _tfage_table_exists(engine, "mechanics_all_designations")
    has_spectral_types = _tfage_table_exists(engine, "data_spectral_types")
    if not has_objects and not has_designations and not has_spectral_types:
        return info
    with engine.connect() as conn:
        object_columns = _db_table_columns(conn, "moca_objects") if has_objects else set()
        moca_designation_sql = "mo.moca_designation" if "moca_designation" in object_columns else "NULL"
        if has_objects and has_designations:
            rows = _records(_read_sql(conn, """
                SELECT
                    mo.moca_oid,
                    COALESCE(NULLIF(mo.designation, ''), mad.designation) AS designation,
                    {moca_designation_sql} AS full_designation
                FROM moca_objects mo
                LEFT JOIN (
                    SELECT moca_oid, MIN(designation) AS designation
                    FROM mechanics_all_designations
                    WHERE moca_oid = :target
                        AND designation IS NOT NULL
                        AND designation <> ''
                    GROUP BY moca_oid
                ) mad
                    ON mad.moca_oid = mo.moca_oid
                WHERE mo.moca_oid = :target
                LIMIT 1
            """.format(moca_designation_sql=moca_designation_sql), {"target": int(target)}))
        elif has_objects:
            rows = _records(_read_sql(conn, f"""
                SELECT mo.moca_oid, mo.designation, {moca_designation_sql} AS full_designation
                FROM moca_objects mo
                WHERE mo.moca_oid = :target
                LIMIT 1
            """, {"target": int(target)}))
        else:
            rows = _records(_read_sql(conn, """
                SELECT
                    mad.moca_oid,
                    MIN(mad.designation) AS designation
                FROM mechanics_all_designations mad
                WHERE mad.moca_oid = :target
                    AND mad.designation IS NOT NULL
                    AND mad.designation <> ''
                GROUP BY mad.moca_oid
                LIMIT 1
            """, {"target": int(target)}))
        designation_rows = []
        if has_designations:
            designation_rows = _records(_read_sql(conn, """
                SELECT DISTINCT mad.designation
                FROM mechanics_all_designations mad
                WHERE mad.moca_oid = :target
                    AND mad.designation IS NOT NULL
                    AND mad.designation <> ''
                ORDER BY mad.designation
                LIMIT 120
            """, {"target": int(target)}))
        adopted_spectral_type = _tfage_adopted_spectral_type_from_conn(conn, int(target)) if has_spectral_types else None
    if rows:
        info.update(rows[0])
        info["moca_oid"] = int(info.get("moca_oid") or target)
    designations = []
    for value in [info.get("full_designation"), info.get("designation")]:
        if value is not None and str(value).strip() and str(value).strip() not in designations:
            designations.append(str(value).strip())
    for row in designation_rows:
        value = str(row.get("designation") or "").strip()
        if value and value not in designations:
            designations.append(value)
    if designations:
        info["designations"] = designations
        if not str(info.get("full_designation") or "").strip():
            info["full_designation"] = designations[0]
        if not str(info.get("designation") or "").strip():
            info["designation"] = designations[0]
    if adopted_spectral_type:
        info["adopted_spectral_type"] = adopted_spectral_type
    return info


def _tfage_adopted_spectral_type_from_conn(conn, target: int) -> dict[str, Any] | None:
    if not _db_table_exists(conn, "data_spectral_types"):
        return None
    columns = _db_table_columns(conn, "data_spectral_types")
    type_columns = [
        column
        for column in ("complete_spectral_type", "spectral_type", "simple_spectral_type")
        if column in columns
    ]
    if not type_columns:
        return None
    type_expr = "COALESCE(" + ", ".join(f"NULLIF(dst.{column}, '')" for column in type_columns) + ")"
    select_parts = [
        f"{type_expr} AS spectral_type",
        "dst.spectral_type_number" if "spectral_type_number" in columns else "NULL AS spectral_type_number",
        "dst.spectral_type_unc" if "spectral_type_unc" in columns else "NULL AS spectral_type_unc",
        "dst.photometric_estimate" if "photometric_estimate" in columns else "0 AS photometric_estimate",
        "dst.public_adopted" if "public_adopted" in columns else "0 AS public_adopted",
        "dst.adopted" if "adopted" in columns else "0 AS adopted",
        "dst.moca_pid" if "moca_pid" in columns else "NULL AS moca_pid",
    ]
    publication_join = ""
    if "moca_pid" in columns and _db_table_exists(conn, "moca_publications"):
        publication_columns = _db_table_columns(conn, "moca_publications")
        if "name" in publication_columns:
            select_parts.append("mp.name AS reference_name")
        if "bibcode" in publication_columns:
            select_parts.append("mp.bibcode AS reference_bibcode")
        publication_join = "LEFT JOIN moca_publications mp ON mp.moca_pid = dst.moca_pid"
    ignored_clause = "AND COALESCE(dst.ignored, 0) = 0" if "ignored" in columns else ""
    adoption_terms = []
    if "adopted" in columns:
        adoption_terms.append("COALESCE(dst.adopted, 0) = 1")
    if "public_adopted" in columns:
        adoption_terms.append("COALESCE(dst.public_adopted, 0) = 1")
    adoption_clause = f"AND ({' OR '.join(adoption_terms)})" if adoption_terms else ""
    order_parts = []
    if "adopted" in columns:
        order_parts.append("COALESCE(dst.adopted, 0) DESC")
    if "photometric_estimate" in columns:
        order_parts.append("COALESCE(dst.photometric_estimate, 0) ASC")
    if "public_adopted" in columns:
        order_parts.append("COALESCE(dst.public_adopted, 0) DESC")
    if "id" in columns:
        order_parts.append("dst.id DESC")
    order_sql = ", ".join(order_parts) or "spectral_type"
    rows = _records(_read_sql(conn, f"""
        SELECT {", ".join(select_parts)}
        FROM data_spectral_types dst
        {publication_join}
        WHERE dst.moca_oid = :target
            AND {type_expr} IS NOT NULL
            {ignored_clause}
            {adoption_clause}
        ORDER BY {order_sql}
        LIMIT 1
    """, {"target": int(target)}))
    return rows[0] if rows else None


def _tfage_metadata_object_info(args: dict[str, Any], target: int) -> dict[str, Any]:
    metadata_args = dict(args)
    for key in ("dbase", "db", "database"):
        metadata_args.pop(key, None)
    try:
        metadata_engine = _engine(_connection_string(metadata_args))
        return _tfage_object_info_from_engine(metadata_engine, int(target))
    except Exception:
        return {"moca_oid": int(target)}


def _tfage_resolve_object_info(engine, args: dict[str, Any], target: int) -> dict[str, Any]:
    info = _tfage_object_info_from_engine(engine, int(target))
    if not str(info.get("designation") or "").strip():
        metadata_info = _tfage_metadata_object_info(args, int(target))
        if str(metadata_info.get("designation") or "").strip():
            info.update(metadata_info)
    return info


def _tfage_object_option(row: dict[str, Any]) -> dict[str, Any]:
    oid = int(row["moca_oid"])
    designation = row.get("designation")
    return {
        "value": oid,
        "moca_oid": oid,
        "designation": designation,
        "label": f"oid{oid}: {designation or 'MOCAdb object'}",
    }


def _tfage_target_info(engine, scope: str, target: int | str | None, args: dict[str, Any] | None = None) -> dict[str, Any]:
    if target in (None, ""):
        return {}
    if scope == "object":
        if args is not None:
            return _tfage_resolve_object_info(engine, args, int(target))
        return _tfage_object_info_from_engine(engine, int(target))
    with engine.connect() as conn:
        if _tfage_table_exists(engine, "moca_associations"):
            rows = _records(_read_sql(conn, """
                SELECT ma.moca_aid, ma.name
                FROM moca_associations ma
                WHERE ma.moca_aid = :target
                LIMIT 1
            """, {"target": str(target)}))
            return rows[0] if rows else {"moca_aid": str(target)}
    return {"moca_aid": str(target)}


def _tfage_count_value(value: Any) -> int | None:
    number = _safe_float(value)
    if number is None:
        return None
    return max(0, int(round(number)))


def _tfage_mocaflows_hbm_expr(
    age_cols: set[str],
    blob_cols: set[str],
    *,
    age_alias: str = "daa",
    blob_alias: str = "b",
) -> str:
    hbm_terms: list[str] = []
    for table_alias, cols, candidates in (
        (age_alias, age_cols, ("calculation_method", "method", "method_detailed", "comments", "origin")),
        (blob_alias, blob_cols, ("result_key",)),
    ):
        for col in candidates:
            if col not in cols:
                continue
            expr = f"LOWER(COALESCE({table_alias}.{_tfage_qid(col)}, ''))"
            hbm_terms.extend([
                f"{expr} LIKE 'mfhbm%'",
                f"{expr} LIKE '%hbm%'",
                f"{expr} LIKE '%hierarchical bayesian%'",
                f"{expr} LIKE '%hierarchical_bayesian%'",
                f"{expr} LIKE '%outlier rejection%'",
            ])
    return "(" + " OR ".join(hbm_terms) + ")" if hbm_terms else "0"


def _tfage_association_stacked_counts_from_db(engine) -> dict[str, dict[str, int]]:
    if not (
        _tfage_table_exists(engine, "data_association_ages")
        and _tfage_table_exists(engine, "calc_association_age_pdf_blobs")
    ):
        return {}
    age_cols = _tfage_columns(engine, "data_association_ages")
    blob_cols = _tfage_columns(engine, "calc_association_age_pdf_blobs")
    if not {"id", "moca_aid"}.issubset(age_cols):
        return {}
    if not {"age_id", "n_contributors"}.issubset(blob_cols):
        return {}

    hbm_expr = _tfage_mocaflows_hbm_expr(age_cols, blob_cols)
    query = text(f"""
        SELECT moca_aid,
               MAX(n_contributors) AS stacked_member_count,
               MAX(CASE WHEN is_hbm = 1 THEN n_contributors END) AS hbm_stacked_member_count,
               MAX(CASE WHEN is_hbm = 0 THEN n_contributors END) AS normal_stacked_member_count
        FROM (
            SELECT daa.moca_aid AS moca_aid,
                   b.n_contributors AS n_contributors,
                   CASE WHEN {hbm_expr} THEN 1 ELSE 0 END AS is_hbm
            FROM data_association_ages AS daa
            JOIN calc_association_age_pdf_blobs AS b
                ON b.age_id = daa.id
            WHERE daa.moca_aid IS NOT NULL
                AND daa.moca_aid <> ''
                AND b.n_contributors IS NOT NULL
        ) stacked_counts
        GROUP BY moca_aid
    """)
    with engine.connect() as conn:
        rows = conn.execute(query).mappings().all()

    counts: dict[str, dict[str, int]] = {}
    for row in rows:
        aid = str(row.get("moca_aid") or "").strip().upper()
        if not aid:
            continue
        item: dict[str, int] = {}
        for key in ("stacked_member_count", "hbm_stacked_member_count", "normal_stacked_member_count"):
            count = _tfage_count_value(row.get(key))
            if count is not None:
                item[key] = count
        if item:
            counts[aid] = item
    return counts


def _load_tfage_options_from_db(args: dict[str, Any]) -> dict[str, Any]:
    scope = "association"
    cache_key = f"{_tfage_cache_key(args, scope, 'options')}|options-counts-v1"
    now = time.time()
    cached = _TRUEFLOW_AGE_CACHE.get(cache_key)
    if cached and now - cached[0] < CACHE_SECONDS:
        payload = copy.deepcopy(cached[1])
        payload["cache"] = {"hit": True, "ttl_seconds": CACHE_SECONDS}
        return payload

    engine = _engine(_tfage_connection_string(args, scope))
    associations: list[dict[str, Any]] = []
    count_map = _tfage_association_stacked_counts_from_db(engine)
    if _tfage_table_exists(engine, "data_association_ages"):
        with engine.connect() as conn:
            if _tfage_table_exists(engine, "moca_associations"):
                rows = _records(_read_sql(conn, """
                    SELECT aid_rows.moca_aid, ma.name
                    FROM (
                        SELECT DISTINCT daa.moca_aid
                        FROM data_association_ages daa
                        WHERE daa.moca_aid IS NOT NULL
                    ) aid_rows
                    LEFT JOIN moca_associations ma
                        ON ma.moca_aid = aid_rows.moca_aid
                    ORDER BY aid_rows.moca_aid
                """))
            else:
                rows = _records(_read_sql(conn, """
                    SELECT DISTINCT daa.moca_aid, NULL AS name
                    FROM data_association_ages daa
                    WHERE daa.moca_aid IS NOT NULL
                    ORDER BY daa.moca_aid
                """))
        associations = [
            {
                "value": row.get("moca_aid"),
                "name": row.get("name"),
                "label": f"{row.get('moca_aid')} - {row.get('name')}" if row.get("name") else row.get("moca_aid"),
                **count_map.get(str(row.get("moca_aid") or "").strip().upper(), {}),
            }
            for row in rows
            if row.get("moca_aid")
        ]
    payload = {
        "associations": associations,
        "meta": {
            "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
            "association_count": len(associations),
        },
        "cache": {"hit": False, "ttl_seconds": CACHE_SECONDS},
    }
    _TRUEFLOW_AGE_CACHE[cache_key] = (now, copy.deepcopy(payload))
    return payload


def _load_mflows_options_from_db(args: dict[str, Any]) -> dict[str, Any]:
    scope = "association"
    cache_key = f"{_tfage_cache_key(args, scope, 'options')}|mflows-options-counts-v2"
    now = time.time()
    cached = _TRUEFLOW_AGE_CACHE.get(cache_key)
    if cached and now - cached[0] < CACHE_SECONDS:
        payload = copy.deepcopy(cached[1])
        payload["cache"] = {"hit": True, "ttl_seconds": CACHE_SECONDS}
        return payload

    started = time.time()
    engine = _engine(_tfage_connection_string(args, scope))
    count_map = _tfage_association_stacked_counts_from_db(engine)
    aids = sorted(count_map)
    names: dict[str, str] = {}
    if aids and _tfage_table_exists(engine, "moca_associations"):
        with engine.connect() as conn:
            rows = _records(_read_sql_expanding(conn, """
                SELECT ma.moca_aid, ma.name
                FROM moca_associations ma
                WHERE ma.moca_aid IN :mflows_option_aids
                ORDER BY ma.moca_aid
            """, "mflows_option_aids", aids))
        names = {
            str(row.get("moca_aid") or "").strip().upper(): str(row.get("name") or "").strip()
            for row in rows
            if row.get("moca_aid")
        }
    associations = []
    for aid in aids:
        name = names.get(aid, "")
        associations.append({
            "value": aid,
            "name": name or None,
            "label": f"{aid} - {name}" if name else aid,
            **count_map.get(aid, {}),
        })
    payload = {
        "associations": associations,
        "meta": {
            "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
            "association_count": len(associations),
            "option_scope": "mocaflows_blob_associations",
            "timings": {"options_total": round(time.time() - started, 3)},
        },
        "cache": {"hit": False, "ttl_seconds": CACHE_SECONDS},
    }
    _TRUEFLOW_AGE_CACHE[cache_key] = (now, copy.deepcopy(payload))
    return payload


def _search_tfage_objects_from_db(args: dict[str, Any], query: str, selected_oid: int | None = None) -> dict[str, Any]:
    scope = "object"
    engine = _engine(_tfage_connection_string(args, scope))
    has_objects = _tfage_table_exists(engine, "moca_objects")
    has_designations = _tfage_table_exists(engine, "mechanics_all_designations")
    if selected_oid is not None:
        info = _tfage_resolve_object_info(engine, args, int(selected_oid))
        return {
            "options": [_tfage_object_option(info)],
            "value": int(selected_oid),
            "meta": {"row_count": 1},
        }
    with engine.connect() as conn:
        query = (query or "").strip()
        if not query:
            query = str(TRUEFLOW_AGE_DEFAULT_OID)
        if query.isdigit():
            rows = [_tfage_resolve_object_info(engine, args, int(query))]
        elif has_objects and has_designations:
            params = {"prefix": f"{query}%"}
            rows = _records(_read_sql(conn, """
                SELECT mo.moca_oid, mo.designation
                FROM moca_objects mo
                WHERE mo.designation LIKE :prefix
                    OR EXISTS (
                        SELECT 1
                        FROM mechanics_all_designations mad
                        WHERE mad.moca_oid = mo.moca_oid
                            AND mad.designation LIKE :prefix
                    )
                ORDER BY mo.designation, mo.moca_oid
                LIMIT 40
            """, params))
        elif has_objects:
            rows = _records(_read_sql(conn, """
                SELECT mo.moca_oid, mo.designation
                FROM moca_objects mo
                WHERE mo.designation LIKE :prefix
                ORDER BY mo.designation, mo.moca_oid
                LIMIT 40
            """, {"prefix": f"{query}%"}))
        elif has_designations:
            rows = _records(_read_sql(conn, """
                SELECT mad.moca_oid, mad.designation
                FROM mechanics_all_designations mad
                WHERE mad.designation LIKE :prefix
                ORDER BY mad.designation, mad.moca_oid
                LIMIT 40
            """, {"prefix": f"{query}%"}))
        else:
            rows = []
    options = [_tfage_object_option(row) for row in rows if row.get("moca_oid") is not None]
    return {"options": options, "value": selected_oid if selected_oid and options else None, "meta": {"row_count": len(options)}}


def _load_tfage_payload_from_db(args: dict[str, Any]) -> dict[str, Any]:
    scope = _tfage_scope(args)
    target = _tfage_target(args, scope)
    curve_role = _tfage_requested_curve_role(args)
    load_posteriors = curve_role == "posterior"
    allow_likelihood_fallback = bool(load_posteriors and not _tfage_has_explicit_curve_role(args))
    cache_key = _tfage_cache_key(args, scope, target)
    now = time.time()
    cached = _TRUEFLOW_AGE_CACHE.get(cache_key)
    if cached and now - cached[0] < CACHE_SECONDS:
        payload = copy.deepcopy(cached[1])
        payload["cache"] = {"hit": True, "ttl_seconds": CACHE_SECONDS}
        return payload
    if target in (None, ""):
        return {
            "selection": {"scope": scope, "target": None, "curve_role": curve_role, "load_posteriors": load_posteriors},
            "target": {},
            "curves": [],
            "tableRows": [],
            "adoptedAge": None,
            "ageMeasurements": [],
            "membershipAge": None,
            "meta": {
                "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
                "age_row_count": 0,
                "curve_count": 0,
                "displayable_curve_count": 0,
                "curve_role": curve_role,
                "load_posteriors": load_posteriors,
            },
            "cache": {"hit": False, "ttl_seconds": CACHE_SECONDS},
        }

    started = time.time()
    engine = _engine(_tfage_connection_string(args, scope))
    age_rows, curves = _tfage_load_curves(
        engine,
        scope,
        target,
        curve_role=curve_role,
        load_blob_posteriors=allow_likelihood_fallback,
    )
    displayable = _tfage_displayable_curves(curves)
    fallback_used = False
    if scope == "object" and not displayable:
        fallback_engine = _tfage_object_fallback_engine(args)
        if fallback_engine is not None:
            fallback_age_rows, fallback_curves = _tfage_load_curves(
                fallback_engine,
                scope,
                target,
                curve_role=curve_role,
                load_blob_posteriors=allow_likelihood_fallback,
            )
            fallback_displayable = _tfage_displayable_curves(fallback_curves)
            if fallback_displayable:
                engine = fallback_engine
                age_rows = fallback_age_rows
                curves = fallback_curves
                displayable = fallback_displayable
                fallback_used = True
    curve_payloads = [_tfage_curve_payload(curve) for curve in displayable]
    target_info = _tfage_target_info(engine, scope, target, args)
    adopted_age = _tfage_adopted_age_payload(engine, age_rows)
    age_measurements = _tfage_age_measurements_payload(engine, age_rows)
    membership_age = _tfage_membership_age_payload(engine, args, target) if scope == "object" else None
    payload = {
        "selection": {
            "scope": scope,
            "target": target,
            "moca_oid": int(target) if scope == "object" else None,
            "moca_aid": str(target) if scope == "association" else None,
            "curve_role": curve_role,
            "load_posteriors": load_posteriors,
        },
        "target": target_info,
        "curves": curve_payloads,
        "tableRows": [row["summary"] for row in curve_payloads],
        "adoptedAge": adopted_age,
        "ageMeasurements": age_measurements,
        "membershipAge": membership_age,
        "meta": {
            "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
            "age_row_count": int(len(age_rows)),
            "curve_count": int(len(curves)),
            "displayable_curve_count": int(len(curve_payloads)),
            "curve_role": curve_role,
            "load_posteriors": load_posteriors,
            "object_age_fallback": fallback_used,
            "source_counts": {
                source: sum(1 for curve in curve_payloads if curve["source"] == source)
                for source in sorted({curve["source"] for curve in curve_payloads})
            },
            "timings": {"load_total": round(time.time() - started, 3)},
        },
        "cache": {"hit": False, "ttl_seconds": CACHE_SECONDS},
    }
    _TRUEFLOW_AGE_CACHE[cache_key] = (now, copy.deepcopy(payload))
    return payload


