def _mflows_requested_stack_mode(args: dict[str, Any]) -> str:
    raw = str(args.get("stack_mode") or args.get("stack") or args.get("stacking") or "").strip().lower()
    if raw in {"hbm", "hierarchical", "hierarchical_bayesian", "hierarchical-bayesian"}:
        return "hbm"
    if raw in {"normal", "simple", "stack", "stacking"}:
        return "normal"
    checkbox = {part.strip().lower() for part in str(args.get("checkbox") or "").split(",") if part.strip()}
    return "hbm" if "hbm" in checkbox else "normal"


def _mflows_requested_mh_treatment(args: dict[str, Any]) -> str:
    raw = str(
        args.get("mh_treatment")
        or args.get("metallicity")
        or args.get("feh")
        or args.get("mh")
        or ""
    ).strip().lower()
    aliases = {
        "db": "db",
        "database": "db",
        "conditioned": "db",
        "conditioned_db": "db",
        "conditioned-on-db": "db",
        "marginalized": "marginalized",
        "marginalised": "marginalized",
        "field": "marginalized",
        "field_prior": "marginalized",
        "copula": "copula2d",
        "copula2d": "copula2d",
        "2d": "copula2d",
        "age_feh": "copula2d",
        "age-feh": "copula2d",
    }
    return aliases.get(raw, "db")


def _mflows_result_key_from_curve(curve: Mapping[str, Any]) -> str:
    meta = curve.get("metadata") if isinstance(curve.get("metadata"), Mapping) else {}
    result_key = str(meta.get("result_key") or "").strip()
    if result_key:
        return result_key
    key = str(curve.get("key") or curve.get("label") or "").lower()
    for known in MOCA_FLOWS_RESULT_ORDER:
        if known in key:
            return known
    if "full forward" in key:
        return "full_forward_model"
    if "stack" in key or "toomre" in key or "vtan" in key:
        return "stacked"
    return key.replace(" ", "_")[:64] or "mocaflows"


def _mflows_result_label(result_key: str) -> str:
    return (
        MOCA_FLOWS_RESULT_LABELS.get(result_key)
        or MOCA_FLOWS_RESULT_LABELS.get(str(result_key or "").lower())
        or result_key.replace("_", " ").strip().title()
        or "MOCAFlows"
    )


def _mflows_kinematic_result_label(result_key: str, curve: Mapping[str, Any]) -> str:
    result_key = str(result_key or "").strip()
    if result_key == "vtan":
        return "Vtan"
    if result_key != "toomre_t":
        return _mflows_result_label(result_key)
    meta = curve.get("metadata") if isinstance(curve.get("metadata"), Mapping) else {}
    scalar = meta.get("scalar_row") if isinstance(meta.get("scalar_row"), Mapping) else {}
    summary = curve.get("summary") if isinstance(curve.get("summary"), Mapping) else {}
    text = " ".join(
        str(value or "").lower()
        for value in (
            curve.get("label"),
            meta.get("calculation_method"),
            meta.get("comments"),
            scalar.get("calculation_method"),
            scalar.get("method"),
            scalar.get("method_detailed"),
            scalar.get("comments"),
            summary.get("calculation_method"),
            summary.get("comments"),
        )
        if value not in (None, "")
    )
    has_toomre = "toomre" in text or "toomre_t" in text
    has_vtan = "vtan" in text or "v tan" in text or "tangential" in text
    if has_toomre and has_vtan:
        return "Toomre T / Vtan"
    if has_vtan and not has_toomre:
        return "Vtan"
    return "Toomre T"


def _mflows_result_order(result_key: str) -> int:
    try:
        return MOCA_FLOWS_RESULT_ORDER.index(result_key)
    except ValueError:
        return 1000


def _mflows_curve_calculation_method(curve: Mapping[str, Any]) -> str:
    meta = curve.get("metadata") if isinstance(curve.get("metadata"), Mapping) else {}
    scalar = meta.get("scalar_row") if isinstance(meta.get("scalar_row"), Mapping) else {}
    summary = curve.get("summary") if isinstance(curve.get("summary"), Mapping) else {}
    for value in (
        meta.get("calculation_method"),
        meta.get("method"),
        meta.get("method_detailed"),
        scalar.get("calculation_method"),
        scalar.get("method"),
        scalar.get("method_detailed"),
        summary.get("calculation_method"),
    ):
        text_value = str(value or "").strip().lower()
        if text_value:
            return text_value
    return ""


def _mflows_curve_uses_db_feh(curve: Mapping[str, Any]) -> bool:
    method = _mflows_curve_calculation_method(curve)
    return method.startswith(MOCA_FLOWS_FEH_METHOD_PREFIXES)


def _mflows_curve_is_legacy_trueflow(curve: Mapping[str, Any]) -> bool:
    method = _mflows_curve_calculation_method(curve)
    return method.startswith(MOCA_FLOWS_LEGACY_METHOD_PREFIXES)


def _mflows_result_can_use_feh(result_key: str) -> bool:
    return str(result_key or "").strip() in MOCA_FLOWS_FEH_DEPENDENT_RESULT_KEYS


def _mflows_metadata_candidate_map(metadata_json: Any) -> Any:
    if not isinstance(metadata_json, Mapping):
        return None
    for key in ("age_feh_map", "ageFehMap", "copula2d", "copula_2d", "map2d", "map"):
        value = metadata_json.get(key)
        if isinstance(value, Mapping):
            return value
    products = metadata_json.get("products")
    if isinstance(products, Mapping):
        for value in products.values():
            if isinstance(value, Mapping):
                nested = _mflows_metadata_candidate_map(value)
                if nested is not None:
                    return nested
    return None


def _mflows_map_payload_from_curve(curve: Mapping[str, Any]) -> dict[str, Any] | None:
    meta = curve.get("metadata") if isinstance(curve.get("metadata"), Mapping) else {}
    candidate = _mflows_metadata_candidate_map(meta.get("metadata_json"))
    if not isinstance(candidate, Mapping):
        return None
    age = candidate.get("age_myr") or candidate.get("age") or candidate.get("x")
    feh = candidate.get("feh") or candidate.get("mh") or candidate.get("metallicity") or candidate.get("y")
    density = (
        candidate.get("density")
        or candidate.get("posterior")
        or candidate.get("likelihood")
        or candidate.get("z")
        or candidate.get("values")
    )
    if age is None or feh is None or density is None:
        return None
    try:
        age_values = [float(value) for value in age]
        feh_values = [float(value) for value in feh]
        z_values = [[float(item) for item in row] for row in density]
    except Exception:
        return None
    if len(age_values) < 2 or len(feh_values) < 2 or len(z_values) != len(feh_values):
        return None
    if any(len(row) != len(age_values) for row in z_values):
        return None
    return {
        "age_myr": age_values,
        "feh": feh_values,
        "density": z_values,
        "z_label": str(candidate.get("z_label") or "Posterior density"),
    }


def _mflows_select_curves(curves: Sequence[Mapping[str, Any]], scope: str, stack_mode: str, mh_treatment: str) -> list[dict[str, Any]]:
    mocaflows = [
        dict(curve)
        for curve in curves
        if str(curve.get("source") or "").strip() == "MOCAFlows"
        and not _mflows_curve_is_legacy_trueflow(curve)
    ]
    if scope == "object":
        object_result_keys = {_mflows_result_key_from_curve(curve) for curve in mocaflows}
        mocaflows = [
            curve for curve in mocaflows
            if not (
                _mflows_result_key_from_curve(curve) in MOCA_FLOWS_OBJECT_RESULT_ALIASES
                and MOCA_FLOWS_OBJECT_RESULT_ALIASES[_mflows_result_key_from_curve(curve)] in object_result_keys
            )
        ]
    if scope == "association":
        want_hbm = stack_mode == "hbm"
        mocaflows = [
            curve for curve in mocaflows
            if bool(curve.get("is_hbm_mocaflows")) == want_hbm
        ]
    grouped: dict[str, list[dict[str, Any]]] = {}
    for curve in mocaflows:
        grouped.setdefault(_mflows_result_key_from_curve(curve), []).append(curve)
    selected: list[dict[str, Any]] = []
    for result_key, group in grouped.items():
        non_feh_group = [curve for curve in group if not _mflows_curve_uses_db_feh(curve)]
        if not _mflows_result_can_use_feh(result_key):
            selected.extend(non_feh_group)
            continue
        if _mflows_result_can_use_feh(result_key):
            if mh_treatment == "db":
                preferred = [curve for curve in group if _mflows_curve_uses_db_feh(curve)]
                group = preferred or non_feh_group
            elif mh_treatment == "marginalized":
                group = non_feh_group
            elif mh_treatment == "copula2d":
                preferred = [curve for curve in group if _mflows_map_payload_from_curve(curve)]
                group = preferred
        selected.extend(group)
    selected.sort(key=lambda curve: (
        _mflows_result_order(_mflows_result_key_from_curve(curve)),
        str((curve.get("metadata") or {}).get("curve_role") if isinstance(curve.get("metadata"), Mapping) else ""),
        str(curve.get("key") or curve.get("label") or ""),
    ))
    return selected


def _mflows_panel_from_curve(curve: Mapping[str, Any], index: int, mh_treatment: str) -> dict[str, Any]:
    result_key = _mflows_result_key_from_curve(curve)
    meta = curve.get("metadata") if isinstance(curve.get("metadata"), Mapping) else {}
    return {
        "key": str(curve.get("key") or f"mocaflows-{index}"),
        "result_key": result_key,
        "title": _mflows_kinematic_result_label(result_key, curve) if result_key in {"toomre_t", "vtan"} else _mflows_result_label(result_key),
        "curve": dict(curve),
        "map": _mflows_map_payload_from_curve(curve),
        "uses_db_feh": _mflows_result_can_use_feh(result_key) and _mflows_curve_uses_db_feh(curve),
        "mh_sensitive": _mflows_result_can_use_feh(result_key),
        "curve_role": _pythonize(meta.get("curve_role")),
        "metadata": {
            "age_id": _pythonize(meta.get("age_id")),
            "result_key": result_key,
            "n_contributors": _pythonize(meta.get("n_contributors")),
            "used_colors": _pythonize(meta.get("used_colors")),
            "peak_age_myr": _pythonize(meta.get("peak_age_myr")),
            "age_lo_myr": _pythonize(meta.get("age_lo_myr")),
            "age_hi_myr": _pythonize(meta.get("age_hi_myr")),
            "eps_peak": _pythonize(meta.get("eps_peak")),
            "eps_mean": _pythonize(meta.get("eps_mean")),
            "eps_lo": _pythonize(meta.get("eps_lo")),
            "eps_hi": _pythonize(meta.get("eps_hi")),
            "calculation_method": _pythonize(meta.get("calculation_method")),
            "moca_pid": _pythonize(meta.get("moca_pid")),
            "comments": _pythonize(meta.get("comments")),
            "created_timestamp": _pythonize(meta.get("created_timestamp")),
            "modified_timestamp": _pythonize(meta.get("modified_timestamp")),
            "age_row_id": _pythonize(meta.get("age_row_id") or meta.get("age_id")),
            "mh_treatment": mh_treatment,
        },
    }


def _mflows_uncertainty_pair(row: Mapping[str, Any]) -> tuple[float | None, float | None]:
    sym = _safe_float(row.get("feh_unc"))
    lo = _safe_float(row.get("feh_unc_neg"))
    hi = _safe_float(row.get("feh_unc_pos"))
    if lo is None:
        lo = sym
    if hi is None:
        hi = sym
    return (abs(lo) if lo is not None else None, abs(hi) if hi is not None else None)


def _mflows_metallicity_payload_from_engine(engine, scope: str, target: int | str | None) -> dict[str, Any] | None:
    if target in (None, ""):
        return None
    table = "data_object_metallicities" if scope == "object" else "data_association_metallicities"
    target_col = "moca_oid" if scope == "object" else "moca_aid"
    if not _tfage_table_exists(engine, table):
        return None
    cols = _tfage_columns(engine, table)
    if not {target_col, "feh_val"}.issubset(cols):
        return None
    alias = "met"
    wanted = [
        "id",
        target_col,
        "moca_pid",
        "abundance_type",
        "feh_string",
        "feh_val",
        "feh_unc",
        "feh_unc_pos",
        "feh_unc_neg",
        "method",
        "method_detailed",
        "calculation_method",
        "quality_flag",
        "adopted",
        "public_adopted",
        "adopt_asis",
        "public_adopt_asis",
        "comments",
        "bibcode",
    ]
    select_parts = [
        f"{alias}.{_tfage_qid(col)} AS {_tfage_qid(col)}"
        for col in wanted
        if col in cols
    ]
    join = ""
    if "moca_pid" in cols and _tfage_table_exists(engine, "moca_publications"):
        pub_cols = _tfage_columns(engine, "moca_publications")
        if "name" in pub_cols:
            select_parts.append("mp.name AS reference_name")
        if "bibcode" in pub_cols:
            select_parts.append("mp.bibcode AS reference_bibcode")
        join = "LEFT JOIN moca_publications mp ON mp.moca_pid = met.moca_pid"
    ignored_clause = "AND COALESCE(met.ignored, 0) = 0" if "ignored" in cols else ""
    abundance_clause = ""
    if "abundance_type" in cols:
        abundance_clause = "AND (met.abundance_type IS NULL OR met.abundance_type IN ('[Fe/H]', 'Fe/H', 'M/H', '[M/H]'))"
    order_terms = []
    for col in ("adopted", "public_adopted", "adopt_asis", "public_adopt_asis"):
        if col in cols:
            order_terms.append(f"COALESCE(met.{_tfage_qid(col)}, 0) DESC")
    if "id" in cols:
        order_terms.append("met.id DESC")
    order_sql = ", ".join(order_terms) or "met.feh_val DESC"
    query = text(f"""
        SELECT {", ".join(select_parts)}
        FROM {_tfage_qid(table)} met
        {join}
        WHERE met.{_tfage_qid(target_col)} = :target
            AND met.feh_val IS NOT NULL
            {ignored_clause}
            {abundance_clause}
        ORDER BY {order_sql}
        LIMIT 1
    """)
    with engine.connect() as conn:
        row = conn.execute(query, {"target": target}).mappings().first()
    if not row:
        return None
    data = dict(row)
    lo, hi = _mflows_uncertainty_pair(data)
    reference_name = _tfage_first_text(data, ("reference_name", "moca_pid", "bibcode"))
    reference_bibcode = _tfage_first_text(data, ("reference_bibcode", "bibcode"))
    return {
        "id": _pythonize(data.get("id")),
        "scope": scope,
        "target": _pythonize(target),
        "source_table": table,
        "value": _pythonize(data.get("feh_val")),
        "uncertainty_minus": lo,
        "uncertainty_plus": hi,
        "abundance_type": _pythonize(data.get("abundance_type") or "[Fe/H]"),
        "feh_string": _pythonize(data.get("feh_string")),
        "method": _pythonize(data.get("method") or data.get("method_detailed") or data.get("calculation_method")),
        "quality_flag": _pythonize(data.get("quality_flag")),
        "moca_pid": _pythonize(data.get("moca_pid")),
        "reference_name": reference_name or "ADS reference",
        "reference_bibcode": reference_bibcode,
        "reference_query": reference_name or reference_bibcode or _tfage_first_text(data, ("moca_pid",)),
        "ads_url": _tfage_ads_url(reference_bibcode, reference_name or reference_bibcode or _tfage_first_text(data, ("moca_pid",))),
        "comments": _pythonize(data.get("comments")),
        "adoption_flag": _tfage_row_adoption_flag(data),
    }


def _mflows_metallicity_payload(args: dict[str, Any], scope: str, target: int | str | None) -> dict[str, Any] | None:
    try:
        engine = _engine(_tfage_connection_string(args, scope))
        payload = _mflows_metallicity_payload_from_engine(engine, scope, target)
        if payload is not None:
            return payload
    except Exception:
        pass
    if scope == "object":
        try:
            engine = _engine(_connection_string(args))
            return _mflows_metallicity_payload_from_engine(engine, scope, target)
        except Exception:
            return None
    return None


def _mflows_feh_prior_from_metadata(metadata_json: Any) -> Mapping[str, Any] | None:
    if not isinstance(metadata_json, Mapping):
        return None
    direct = metadata_json.get("feh_prior")
    if isinstance(direct, Mapping):
        return direct
    nested_input = metadata_json.get("input")
    if isinstance(nested_input, Mapping) and isinstance(nested_input.get("feh_prior"), Mapping):
        return nested_input["feh_prior"]
    for value in metadata_json.values():
        if isinstance(value, Mapping):
            nested = _mflows_feh_prior_from_metadata(value)
            if nested is not None:
                return nested
    return None


def _mflows_metallicity_payload_from_feh_prior(
    prior: Mapping[str, Any],
    scope: str,
    target: int | str | None,
) -> dict[str, Any] | None:
    value = _safe_float(prior.get("feh"))
    if value is None:
        return None
    lo = (
        _safe_float(prior.get("effective_feh_unc_neg"))
        or _safe_float(prior.get("feh_unc_neg"))
        or _safe_float(prior.get("effective_feh_unc"))
        or _safe_float(prior.get("feh_unc"))
    )
    hi = (
        _safe_float(prior.get("effective_feh_unc_pos"))
        or _safe_float(prior.get("feh_unc_pos"))
        or _safe_float(prior.get("effective_feh_unc"))
        or _safe_float(prior.get("feh_unc"))
    )
    reference_name = _pythonize(prior.get("label") or prior.get("source_moca_pid") or prior.get("source_bibcode"))
    reference_bibcode = _pythonize(prior.get("source_bibcode"))
    return {
        "id": _pythonize(prior.get("source_id")),
        "scope": scope,
        "target": _pythonize(target),
        "source_table": _pythonize(prior.get("source_table") or "MOCAFlows metadata"),
        "value": value,
        "uncertainty_minus": abs(lo) if lo is not None else None,
        "uncertainty_plus": abs(hi) if hi is not None else None,
        "abundance_type": "[Fe/H]",
        "method": _pythonize(prior.get("source_kind") or "MOCAFlows Fe/H prior"),
        "moca_pid": _pythonize(prior.get("source_moca_pid")),
        "reference_name": reference_name or "MOCAFlows Fe/H prior",
        "reference_bibcode": reference_bibcode,
        "reference_query": reference_name or reference_bibcode,
        "ads_url": _tfage_ads_url(reference_bibcode, reference_name or reference_bibcode),
        "adoption_flag": "adopted" if _as_bool(prior.get("source_adopted")) else "",
    }


def _mflows_metallicity_payload_from_curves(
    curves: Sequence[Mapping[str, Any]],
    scope: str,
    target: int | str | None,
) -> dict[str, Any] | None:
    for curve in curves:
        meta = curve.get("metadata") if isinstance(curve.get("metadata"), Mapping) else {}
        prior = _mflows_feh_prior_from_metadata(meta.get("metadata_json"))
        if prior is None:
            continue
        payload = _mflows_metallicity_payload_from_feh_prior(prior, scope, target)
        if payload is not None:
            return payload
    return None


def _mflows_mh_treatment_payload(mh_treatment: str, metallicity: dict[str, Any] | None) -> dict[str, Any]:
    labels = {
        "db": (
            "Conditioned on available MOCAdb [M/H]"
            if metallicity is not None
            else "No MOCAdb [M/H] measurement available"
        ),
        "marginalized": "M/H marginalized from the 2D copula",
        "copula2d": "2D age-[M/H] likelihood maps",
    }
    return {
        "mode": mh_treatment,
        "label": labels.get(mh_treatment, labels["db"]),
        "dbMeasurement": metallicity,
        "has_db_measurement": metallicity is not None,
    }


def _mflows_payload_from_tfage(
    args: dict[str, Any],
    tf_payload: dict[str, Any],
    *,
    metallicity_override: dict[str, Any] | None = None,
    lookup_metallicity: bool = True,
) -> dict[str, Any]:
    selection = dict(tf_payload.get("selection") or {})
    scope = str(selection.get("scope") or _tfage_scope(args))
    target = selection.get("target")
    stack_mode = _mflows_requested_stack_mode(args)
    mh_treatment = _mflows_requested_mh_treatment(args)
    curve_role = _tfage_normalize_curve_role(selection.get("curve_role") or _tfage_requested_curve_role(args))
    curves = _mflows_select_curves(tf_payload.get("curves") or [], scope, stack_mode, mh_treatment)
    panels = [_mflows_panel_from_curve(curve, index, mh_treatment) for index, curve in enumerate(curves)]
    metallicity = _mflows_metallicity_payload(args, scope, target) if lookup_metallicity else metallicity_override
    if metallicity is None:
        metallicity = _mflows_metallicity_payload_from_curves(curves, scope, target)
    selection.update({
        "scope": scope,
        "target": target,
        "stack_mode": stack_mode,
        "mh_treatment": mh_treatment,
        "curve_role": curve_role,
        "load_posteriors": curve_role == "posterior",
    })
    meta = dict(tf_payload.get("meta") or {})
    meta.update({
        "mocaflows_panel_count": len(panels),
        "mocaflows_curve_count": len(curves),
        "mocaflows_map_count": sum(1 for panel in panels if panel.get("map")),
        "stack_mode": stack_mode,
        "mh_treatment": mh_treatment,
        "curve_role": curve_role,
        "load_posteriors": curve_role == "posterior",
    })
    return {
        "selection": selection,
        "target": tf_payload.get("target") or {},
        "panels": panels,
        "curves": [],
        "tableRows": [curve.get("summary") or {} for curve in curves],
        "adoptedAge": tf_payload.get("adoptedAge"),
        "membershipAge": tf_payload.get("membershipAge"),
        "ageMeasurements": tf_payload.get("ageMeasurements") or [],
        "metallicity": _mflows_mh_treatment_payload(mh_treatment, metallicity),
        "meta": meta,
        "cache": tf_payload.get("cache") or {"hit": False, "ttl_seconds": CACHE_SECONDS},
    }


def _mflows_show_measurements_requested(args: Mapping[str, Any]) -> bool:
    raw = args.get("show_measurements") if "show_measurements" in args else args.get("measurements")
    if raw is not None and str(raw).strip() != "":
        return _as_bool(raw)
    checkbox = {part.strip().lower() for part in str(args.get("checkbox") or "").split(",") if part.strip()}
    return "show_measurements" in checkbox or "measurements" in checkbox


def _mflows_association_has_blob(
    engine,
    target: int | str | None,
) -> bool:
    if target in (None, ""):
        return False
    if not (
        _tfage_table_exists(engine, "data_association_ages")
        and _tfage_table_exists(engine, "calc_association_age_pdf_blobs")
    ):
        return False
    age_cols = _tfage_columns(engine, "data_association_ages")
    blob_cols = _tfage_columns(engine, "calc_association_age_pdf_blobs")
    if not {"id", "moca_aid"}.issubset(age_cols) or not {"id", "age_id"}.issubset(blob_cols):
        return False
    query = text(f"""
        SELECT 1
        FROM data_association_ages AS daa
        JOIN calc_association_age_pdf_blobs AS b
            ON b.age_id = daa.id
        WHERE daa.moca_aid = :target
        LIMIT 1
    """)
    with engine.connect() as conn:
        return conn.execute(query, {"target": str(target)}).first() is not None


def _load_mflows_payload_from_db(args: dict[str, Any]) -> dict[str, Any]:
    scope = _tfage_scope(args)
    target = _tfage_target(args, scope)
    curve_role = _tfage_requested_curve_role(args)
    stack_mode = _mflows_requested_stack_mode(args)
    mh_treatment = _mflows_requested_mh_treatment(args)
    show_measurements = _mflows_show_measurements_requested(args)
    allow_likelihood_fallback = bool(curve_role == "posterior" and not _tfage_has_explicit_curve_role(args))
    cache_key = "|".join([
        _tfage_cache_key(args, scope, target),
        "mflows-data-v9",
        stack_mode,
        mh_treatment,
        str(int(show_measurements)),
    ])
    now = time.time()
    cached = _TRUEFLOW_AGE_CACHE.get(cache_key)
    if cached and now - cached[0] < CACHE_SECONDS:
        payload = copy.deepcopy(cached[1])
        payload["cache"] = {"hit": True, "ttl_seconds": CACHE_SECONDS}
        return payload

    started_total = time.time()
    timings: dict[str, float] = {}
    if target in (None, ""):
        return _mflows_payload_from_tfage(args, {
            "selection": {
                "scope": scope,
                "target": None,
                "moca_oid": None,
                "moca_aid": None,
                "curve_role": curve_role,
                "load_posteriors": curve_role == "posterior",
            },
            "target": {},
            "curves": [],
            "tableRows": [],
            "adoptedAge": None,
            "ageMeasurements": [],
            "membershipAge": None,
            "meta": {
                "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
                "age_row_count": 0,
                "curve_count": 0,
                "displayable_curve_count": 0,
                "curve_role": curve_role,
                "load_posteriors": curve_role == "posterior",
                "timings": {"mflows_total": 0.0},
            },
            "cache": {"hit": False, "ttl_seconds": CACHE_SECONDS},
        })

    engine = _engine(_tfage_connection_string(args, scope))
    if scope == "association":
        started = time.time()
        has_blob = _mflows_association_has_blob(engine, target)
        timings["blob_presence"] = round(time.time() - started, 3)
        if not has_blob:
            tf_payload = {
                "selection": {
                    "scope": scope,
                    "target": target,
                    "moca_oid": None,
                    "moca_aid": str(target) if target is not None else None,
                    "curve_role": curve_role,
                    "load_posteriors": curve_role == "posterior",
                },
                "target": {"moca_aid": str(target)} if target is not None else {},
                "curves": [],
                "tableRows": [],
                "adoptedAge": None,
                "ageMeasurements": [],
                "membershipAge": None,
                "meta": {
                    "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
                    "age_row_count": 0,
                    "age_rows_skipped": True,
                    "blob_presence": False,
                    "curve_count": 0,
                    "displayable_curve_count": 0,
                    "curve_role": curve_role,
                    "load_posteriors": curve_role == "posterior",
                    "object_age_fallback": False,
                    "source_counts": {},
                    "timings": timings,
                },
                "cache": {"hit": False, "ttl_seconds": CACHE_SECONDS},
            }
            payload = _mflows_payload_from_tfage(
                args,
                tf_payload,
                metallicity_override=None,
                lookup_metallicity=False,
            )
            payload.setdefault("meta", {}).setdefault("timings", {}).update(timings)
            payload["meta"]["timings"]["mflows_total"] = round(time.time() - started_total, 3)
            _TRUEFLOW_AGE_CACHE[cache_key] = (now, copy.deepcopy(payload))
            return payload

    def load_age_rows_and_curves(load_engine) -> tuple[pd.DataFrame, list[_TfAgeCurve], dict[str, float]]:
        local_timings: dict[str, float] = {}
        local_started = time.time()
        local_age_rows = _tfage_fetch_age_rows(load_engine, scope, target)
        local_timings["age_rows"] = round(time.time() - local_started, 3)

        local_started = time.time()
        local_curves = _tfage_fetch_blob_curves(
            load_engine,
            scope,
            local_age_rows,
            curve_role=curve_role,
            include_likelihood_fallback=allow_likelihood_fallback,
            include_hbm_member_stats=stack_mode == "hbm",
        )
        local_timings["blob_curves"] = round(time.time() - local_started, 3)
        return local_age_rows, local_curves, local_timings

    age_rows, curves, load_timings = load_age_rows_and_curves(engine)
    timings.update(load_timings)
    fallback_used = False

    if scope == "object" and not _tfage_displayable_curves(curves):
        fallback_engine = _tfage_object_fallback_engine(args)
        if fallback_engine is not None:
            fallback_age_rows, fallback_curves, fallback_timings = load_age_rows_and_curves(fallback_engine)
            if _tfage_displayable_curves(fallback_curves):
                timings.update({f"primary_{key}": value for key, value in load_timings.items()})
                timings.update(fallback_timings)
                engine = fallback_engine
                age_rows = fallback_age_rows
                curves = fallback_curves
                fallback_used = True

    started = time.time()
    displayable = _tfage_displayable_curves(curves)
    curve_payloads = [_tfage_curve_payload(curve) for curve in displayable]
    timings["curve_payloads"] = round(time.time() - started, 3)

    started = time.time()
    target_info = _tfage_target_info(engine, scope, target, args)
    timings["target_info"] = round(time.time() - started, 3)

    started = time.time()
    adopted_age = _tfage_adopted_age_payload(engine, age_rows)
    timings["adopted_age"] = round(time.time() - started, 3)

    age_measurements: list[dict[str, Any]] = []
    if show_measurements:
        started = time.time()
        age_measurements = _tfage_age_measurements_payload(engine, age_rows)
        timings["age_measurements"] = round(time.time() - started, 3)

    membership_age = None
    if scope == "object":
        started = time.time()
        membership_age = _tfage_membership_age_payload(engine, args, target)
        timings["membership_age"] = round(time.time() - started, 3)

    tf_payload = {
        "selection": {
            "scope": scope,
            "target": target,
            "moca_oid": int(target) if scope == "object" else None,
            "moca_aid": str(target) if scope == "association" else None,
            "curve_role": curve_role,
            "load_posteriors": curve_role == "posterior",
        },
        "target": target_info,
        "curves": curve_payloads,
        "tableRows": [row["summary"] for row in curve_payloads],
        "adoptedAge": adopted_age,
        "ageMeasurements": age_measurements,
        "membershipAge": membership_age,
        "meta": {
            "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
            "age_row_count": int(len(age_rows)),
            "curve_count": int(len(curves)),
            "displayable_curve_count": int(len(curve_payloads)),
            "curve_role": curve_role,
            "load_posteriors": curve_role == "posterior",
            "object_age_fallback": fallback_used,
            "source_counts": {
                source: sum(1 for curve in curve_payloads if curve["source"] == source)
                for source in sorted({curve["source"] for curve in curve_payloads})
            },
            "timings": timings,
        },
        "cache": {"hit": False, "ttl_seconds": CACHE_SECONDS},
    }
    payload = _mflows_payload_from_tfage(args, tf_payload)
    payload.setdefault("meta", {}).setdefault("timings", {}).update(timings)
    payload["meta"]["timings"]["mflows_total"] = round(time.time() - started_total, 3)
    _TRUEFLOW_AGE_CACHE[cache_key] = (now, copy.deepcopy(payload))
    return payload


def _mock_mflows_curve_payload(
    *,
    result_key: str,
    center: float,
    sigma: float,
    n_contributors: int,
    hbm: bool,
    age_grid: np.ndarray,
    curve_role: str,
    secondary: float | None = None,
) -> dict[str, Any]:
    curve_role = _tfage_normalize_curve_role(curve_role)
    role_sigma_scale = {"prior": 1.65, "posterior": 0.8}.get(curve_role, 1.0)
    sigma *= role_sigma_scale
    log_age = np.log(age_grid)
    pdf = np.exp(-0.5 * ((log_age - math.log(center)) / sigma) ** 2)
    if secondary is not None:
        pdf += 0.45 * np.exp(-0.5 * ((log_age - math.log(secondary)) / (sigma * 0.9)) ** 2)
    pdf = _tfage_normalize_pdf(age_grid, pdf)
    pct = _tfage_percentiles(age_grid, pdf) or (center * 0.8, center, center * 1.2)
    peak = float(age_grid[int(np.nanargmax(pdf))])
    calc_method = ("mfhbmfeh_" if hbm else "mfafeh_") + result_key[:10].replace("_", "")
    return {
        "key": f"mock-{result_key}-{curve_role}-{'hbm' if hbm else 'normal'}",
        "label": f"{result_key} {curve_role} (mock MOCAFlows)",
        "source": "MOCAFlows",
        "age_myr": [float(value) for value in age_grid],
        "pdf_age": [float(value) for value in pdf],
        "is_hbm_mocaflows": hbm,
        "summary": {
            "curve": _mflows_result_label(result_key),
            "source": "MOCAFlows",
            "age": f"{pct[1]:.3g} (+{pct[2] - pct[1]:.3g}/-{pct[1] - pct[0]:.3g}) Myr",
            "calculation_method": calc_method,
            "moca_pid": "mock",
            "adopted": 0,
            "public_adopted": 0,
            "comments": "Synthetic MOCAFlows panel for smoke testing",
        },
        "metadata": {
            "age_id": f"mock-{result_key}",
            "result_key": result_key,
            "curve_role": curve_role,
            "pdf_space": "log_pdf_dlog10age",
            "used_colors": "BP-RP, G-RP" if result_key == "gaia_cmd" else "",
            "n_contributors": n_contributors,
            "peak_age_myr": peak,
            "age_lo_myr": float(pct[0]),
            "age_hi_myr": float(pct[2]),
            "eps_peak": 0.08 if hbm else None,
            "eps_mean": 0.09 if hbm else None,
            "eps_lo": 0.04 if hbm else None,
            "eps_hi": 0.18 if hbm else None,
            "moca_pid": "mock",
            "calculation_method": calc_method,
            "comments": "Synthetic MOCAFlows panel for smoke testing",
            "metadata_json": {
                "min_p_inlier": 0.87 if hbm else None,
                "n_p_lt_0p50": 1 if hbm and n_contributors < 10 else 0,
                "n_p_lt_0p90": 4 if hbm and n_contributors > 20 else 0,
            },
        },
    }


def _mock_mflows_map(age_grid: np.ndarray, center: float, feh_center: float, curve_role: str) -> dict[str, Any]:
    curve_role = _tfage_normalize_curve_role(curve_role)
    age = np.geomspace(max(1.0, center / 12.0), min(12000.0, center * 12.0), 72)
    feh = np.linspace(feh_center - 0.35, feh_center + 0.35, 54)
    log_age = np.log(age)
    zz = []
    for fvalue in feh:
        ridge = math.log(center) + 0.7 * (fvalue - feh_center)
        zrow = np.exp(-0.5 * ((log_age - ridge) / 0.34) ** 2 - 0.5 * ((fvalue - feh_center) / 0.12) ** 2)
        zz.append([float(value) for value in zrow])
    return {
        "age_myr": [float(value) for value in age],
        "feh": [float(value) for value in feh],
        "density": zz,
        "z_label": f"Mock joint {curve_role}",
    }


def _mock_mflows_payload(args: dict[str, Any]) -> dict[str, Any]:
    scope = _tfage_scope(args)
    target = _tfage_target(args, scope)
    stack_mode = _mflows_requested_stack_mode(args)
    mh_treatment = _mflows_requested_mh_treatment(args)
    curve_role = _tfage_requested_curve_role(args)
    hbm = stack_mode == "hbm"
    age_grid = np.geomspace(1.0, 12000.0, 280)
    specs = [
        ("lithium", 740, 0.26, 1, None),
        ("prot", 119, 0.09, 28, None),
        ("prot_amp", 114, 0.48, 22, 2.0),
        ("vsini", 110, 0.58, 7, None),
        ("halpha", 475, 0.62, 1, None),
        ("gaia_act", 50, 0.44, 4, None),
        ("varg", 99, 0.31, 6, 2.2),
        ("varbp", 36, 1.16, 6, 2.5),
        ("varrp", 45, 0.42, 6, 2.3),
        ("galex_nuv", 10, 0.55, 6, 70),
        ("log_lx", 60, 0.70, 1, None),
        ("radio_lnu", 35, 0.95, 1, None),
        ("gaia_cmd", 316, 0.25, 41, None),
        ("stacked", 119, 0.06, 42, None),
        ("full_forward_model", 129, 0.09, 42, None),
    ]
    curves = [
        _mock_mflows_curve_payload(
            result_key=result_key,
            center=center,
            sigma=sigma,
            n_contributors=n_contributors,
            hbm=hbm,
            age_grid=age_grid,
            curve_role=curve_role,
            secondary=secondary,
        )
        for result_key, center, sigma, n_contributors, secondary in specs
    ]
    for curve in curves:
        result_key = curve["metadata"]["result_key"]
        if result_key in {"gaia_cmd", "full_forward_model"}:
            curve["metadata"]["metadata_json"]["age_feh_map"] = _mock_mflows_map(
                age_grid,
                curve["metadata"]["peak_age_myr"],
                -0.02,
                curve_role,
            )
    target_info = (
        {"moca_aid": target or MOCA_FLOWS_DEFAULT_AID, "name": "Mock association"}
        if scope == "association"
        else {"moca_oid": int(target or TRUEFLOW_AGE_DEFAULT_OID), "designation": "Mock MOCAFlows target"}
    )
    adopted_age = {
        "value_myr": 120.0,
        "uncertainty_minus_myr": 12.0,
        "uncertainty_plus_myr": 14.0,
        "lower_myr": 108.0,
        "upper_myr": 134.0,
        "method": "Mock adopted association age",
        "reference_name": "Mock Age Reference et al. (2026)",
        "reference_bibcode": "2026Mock....4D",
        "ads_url": _tfage_ads_url("2026Mock....4D"),
        "kind": "adopted",
    }
    metallicity = {
        "id": "mock-feh",
        "scope": scope,
        "target": target,
        "source_table": "data_association_metallicities" if scope == "association" else "data_object_metallicities",
        "value": -0.02,
        "uncertainty_minus": 0.06,
        "uncertainty_plus": 0.07,
        "abundance_type": "[Fe/H]",
        "method": "Mock adopted MOCAdb [Fe/H]",
        "moca_pid": "mock",
        "reference_name": "Mock Metallicity Reference et al. (2026)",
        "reference_bibcode": "2026Mock....7M",
        "reference_query": "Mock Metallicity Reference et al. (2026)",
        "ads_url": _tfage_ads_url("2026Mock....7M"),
        "adoption_flag": "adopted",
    }
    tf_payload = {
        "selection": {
            "scope": scope,
            "target": target,
            "moca_oid": int(target) if scope == "object" and target is not None else None,
            "moca_aid": str(target) if scope == "association" and target is not None else None,
            "curve_role": curve_role,
            "load_posteriors": curve_role == "posterior",
        },
        "target": target_info,
        "curves": curves,
        "tableRows": [curve["summary"] for curve in curves],
        "adoptedAge": adopted_age if scope == "association" else None,
        "membershipAge": adopted_age if scope == "object" else None,
        "ageMeasurements": [adopted_age],
        "meta": {
            "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
            "displayable_curve_count": len(curves),
            "curve_role": curve_role,
            "load_posteriors": curve_role == "posterior",
            "mock": True,
        },
        "cache": {"hit": False, "ttl_seconds": 0},
    }
    payload = _mflows_payload_from_tfage(
        args,
        tf_payload,
        metallicity_override=metallicity,
        lookup_metallicity=False,
    )
    payload["source"] = "mock"
    return payload


def _astrometry_db_cache_key(args: dict[str, Any], oid: int) -> str:
    cfg = _db_config(args)
    return "|".join([
        "refunc-pubrefs-v1",
        cfg["host"],
        cfg["username"],
        cfg["dbname"],
        str(int(oid)),
        str(_include_merged_astrometry(args)),
    ])


def _include_merged_astrometry(args: dict[str, Any]) -> bool:
    return any(_as_bool(args.get(key)) for key in ("display_merged", "include_merged", "merged"))


def _astrometry_ultranest_available() -> bool:
    try:
        import importlib.util

        return importlib.util.find_spec("ultranest") is not None
    except Exception:
        return False


def _astrometry_ultranest_requires_management() -> bool:
    return not _as_false(os.environ.get("ASTROMETRY_ULTRANEST_REQUIRES_MANAGEMENT", "1"))


def _astrometry_fit_capabilities(args: dict[str, Any]) -> dict[str, Any]:
    auth = _auth_context(args)
    ultranest_available = _astrometry_ultranest_available()
    requires_management = _astrometry_ultranest_requires_management()
    management_allowed = auth.get("role") == "management"
    return {
        "auth": auth,
        "fitters": {
            "scipy": {
                "available": True,
                "label": "SciPy",
                "requires_management": False,
                "enabled": True,
                "message": "",
            },
            "ultranest": {
                "available": ultranest_available,
                "label": "UltraNest",
                "requires_management": requires_management,
                "enabled": bool(ultranest_available and (management_allowed or not requires_management)),
                "message": (
                    "UltraNest is not installed in this Python environment."
                    if not ultranest_available
                    else (
                        "UltraNest fits require management credentials."
                        if requires_management and not management_allowed
                        else ""
                    )
                ),
            },
        },
        "defaults": {
            "fitter": "scipy",
            "outlier_mixture": True,
            "error_floor": True,
        },
    }


def _astrometry_first_float(row: Mapping[str, Any], *keys: str) -> float | None:
    for key in keys:
        if key in row:
            value = _safe_float(row.get(key))
            if value is not None:
                return value
    return None


def _astrometry_parallax_factors(ra_deg: float, dec_deg: float, epochs: Any) -> tuple[np.ndarray, np.ndarray]:
    epoch_arr = np.asarray(epochs, dtype=float)
    ra = np.radians(float(ra_deg))
    dec = np.radians(float(dec_deg))
    n = (epoch_arr - 2000.0) * 365.25
    mean_long = np.radians(np.mod(280.460 + 0.9856474 * n, 360.0))
    anomaly = np.radians(np.mod(357.528 + 0.9856003 * n, 360.0))
    sun_long = mean_long + np.radians(1.915) * np.sin(anomaly) + np.radians(0.020) * np.sin(2.0 * anomaly)
    obliquity = np.radians(23.439 - 0.0000004 * n)

    cos_ra = math.cos(ra)
    sin_ra = math.sin(ra)
    cos_dec = math.cos(dec)
    sin_dec = math.sin(dec)
    cos_obl = np.cos(obliquity)
    sin_obl = np.sin(obliquity)
    cos_sun = np.cos(sun_long)
    sin_sun = np.sin(sun_long)

    pra = (cos_ra * cos_obl * sin_sun - sin_ra * cos_sun) * cos_dec
    pdec = cos_dec * sin_obl * sin_sun - cos_ra * sin_dec * cos_sun - sin_ra * sin_dec * cos_obl * sin_sun
    return np.asarray(pra, dtype=float), np.asarray(pdec, dtype=float)


def _astrometry_fit_arrays(body: Mapping[str, Any]) -> dict[str, Any]:
    rows_in = body.get("rows") or []
    if not isinstance(rows_in, Sequence) or isinstance(rows_in, (str, bytes)):
        raise ValueError("Fit rows must be supplied as a list.")

    mode = str(body.get("mode") or "pm").strip().lower()
    if mode not in {"pm", "pm_plx"}:
        raise ValueError("Fit mode must be 'pm' or 'pm_plx'.")
    is_parallax = mode == "pm_plx"

    reference = body.get("reference") if isinstance(body.get("reference"), Mapping) else {}
    ref_ra = _safe_float(reference.get("ra"))
    ref_dec = _safe_float(reference.get("dec"))
    if ref_ra is None or ref_dec is None:
        raise ValueError("A finite reference R.A. and Decl. are required for fitting.")
    ref_epoch = _safe_float(reference.get("epoch"))

    parallax = body.get("parallax") if isinstance(body.get("parallax"), Mapping) else {}
    fixed_plx = _safe_float(body.get("fixedPlx"))
    if fixed_plx is None:
        fixed_plx = _safe_float(parallax.get("value"))
    if fixed_plx is None:
        fixed_plx = 0.0

    ids: list[str] = []
    missions: list[str] = []
    epochs: list[float] = []
    rel_ra: list[float] = []
    rel_dec: list[float] = []
    sig_ra: list[float] = []
    sig_dec: list[float] = []

    for index, raw_row in enumerate(rows_in):
        if not isinstance(raw_row, Mapping):
            continue
        epoch = _astrometry_first_float(raw_row, "plot_epoch_abs", "measurement_epoch_yr", "epoch")
        y_ra = _astrometry_first_float(raw_row, "base_rel_ra", "rel_ra", "ra_offset_mas")
        y_dec = _astrometry_first_float(raw_row, "base_rel_dec", "rel_dec", "dec_offset_mas")
        e_ra = _astrometry_first_float(raw_row, "ra_unc_mas", "era_mas", "ra_unc")
        e_dec = _astrometry_first_float(raw_row, "dec_unc_mas", "edec_mas", "dec_unc")
        if epoch is None or y_ra is None or y_dec is None:
            continue
        e_ra = max(float(e_ra if e_ra is not None else 1.0), 1e-3)
        e_dec = max(float(e_dec if e_dec is not None else 1.0), 1e-3)
        ids.append(str(raw_row.get("id") if raw_row.get("id") is not None else index))
        missions.append(str(raw_row.get("mission") or "No mission"))
        epochs.append(float(epoch))
        rel_ra.append(float(y_ra))
        rel_dec.append(float(y_dec))
        sig_ra.append(e_ra)
        sig_dec.append(e_dec)

    if not epochs:
        raise ValueError("No usable astrometry rows were supplied for fitting.")

    t = np.asarray(epochs, dtype=float)
    y_ra_arr = np.asarray(rel_ra, dtype=float)
    y_dec_arr = np.asarray(rel_dec, dtype=float)
    s_ra_arr = np.asarray(sig_ra, dtype=float)
    s_dec_arr = np.asarray(sig_dec, dtype=float)
    valid = (
        np.isfinite(t)
        & np.isfinite(y_ra_arr)
        & np.isfinite(y_dec_arr)
        & np.isfinite(s_ra_arr)
        & np.isfinite(s_dec_arr)
        & (s_ra_arr > 0)
        & (s_dec_arr > 0)
    )
    if not np.any(valid):
        raise ValueError("No finite astrometry rows were supplied for fitting.")

    ids_arr = np.asarray(ids, dtype=object)[valid]
    missions_arr = np.asarray(missions, dtype=object)[valid]
    t = t[valid]
    y_ra_arr = y_ra_arr[valid]
    y_dec_arr = y_dec_arr[valid]
    s_ra_arr = s_ra_arr[valid]
    s_dec_arr = s_dec_arr[valid]
    t0 = float(ref_epoch if ref_epoch is not None else np.nanmedian(t))
    pra, pdec = _astrometry_parallax_factors(ref_ra, ref_dec, t)

    min_rows = 3 if is_parallax else 2
    if t.size < min_rows:
        raise ValueError(f"Need at least {min_rows} usable measurements for this fit.")

    return {
        "mode": mode,
        "is_parallax": is_parallax,
        "ids": ids_arr,
        "missions": missions_arr,
        "t": t,
        "dt": t - t0,
        "y_ra": y_ra_arr,
        "y_dec": y_dec_arr,
        "s_ra": s_ra_arr,
        "s_dec": s_dec_arr,
        "pra": pra,
        "pdec": pdec,
        "t0": t0,
        "ref_ra": float(ref_ra),
        "ref_dec": float(ref_dec),
        "fixed_plx": float(fixed_plx),
        "n_params": 5 if is_parallax else 4,
        "min_rows": min_rows,
    }


def _astrometry_design_matrix(arrays: Mapping[str, Any], sigma_scale: Any | None = None) -> tuple[np.ndarray, np.ndarray, np.ndarray]:
    dt = np.asarray(arrays["dt"], dtype=float)
    pra = np.asarray(arrays["pra"], dtype=float)
    pdec = np.asarray(arrays["pdec"], dtype=float)
    n = dt.size
    is_parallax = bool(arrays["is_parallax"])
    n_params = int(arrays["n_params"])
    design = np.zeros((2 * n, n_params), dtype=float)
    design[:n, 0] = 1.0
    design[:n, 1] = dt
    design[n:, 2] = 1.0
    design[n:, 3] = dt
    if is_parallax:
        design[:n, 4] = pra
        design[n:, 4] = pdec

    y_ra = np.asarray(arrays["y_ra"], dtype=float).copy()
    y_dec = np.asarray(arrays["y_dec"], dtype=float).copy()
    if not is_parallax:
        fixed_plx = float(arrays.get("fixed_plx") or 0.0)
        y_ra -= fixed_plx * pra
        y_dec -= fixed_plx * pdec
    y = np.concatenate([y_ra, y_dec])

    sigma = np.concatenate([
        np.asarray(arrays["s_ra"], dtype=float),
        np.asarray(arrays["s_dec"], dtype=float),
    ])
    if sigma_scale is not None:
        scale = np.asarray(sigma_scale, dtype=float)
        if scale.size == n:
            scale = np.concatenate([scale, scale])
        sigma = sigma / np.sqrt(np.clip(scale, 1e-6, None))
    sigma = np.clip(sigma, 1e-3, np.inf)
    return design, y, sigma


def _astrometry_linear_fit(arrays: Mapping[str, Any], sigma_scale: Any | None = None) -> tuple[np.ndarray, np.ndarray]:
    design, y, sigma = _astrometry_design_matrix(arrays, sigma_scale=sigma_scale)
    aw = design / sigma[:, np.newaxis]
    yw = y / sigma
    normal = aw.T @ aw
    rhs = aw.T @ yw
    try:
        covariance = np.linalg.inv(normal)
        params = covariance @ rhs
    except np.linalg.LinAlgError:
        covariance = np.linalg.pinv(normal)
        params = covariance @ rhs
    return np.asarray(params, dtype=float), np.asarray(covariance, dtype=float)


def _astrometry_model_from_params(arrays: Mapping[str, Any], params: Any) -> tuple[np.ndarray, np.ndarray]:
    p = np.asarray(params, dtype=float)
    dt = np.asarray(arrays["dt"], dtype=float)
    pra = np.asarray(arrays["pra"], dtype=float)
    pdec = np.asarray(arrays["pdec"], dtype=float)
    plx = float(p[4]) if bool(arrays["is_parallax"]) else float(arrays.get("fixed_plx") or 0.0)
    ra_model = p[0] + p[1] * dt + plx * pra
    dec_model = p[2] + p[3] * dt + plx * pdec
    return np.asarray(ra_model, dtype=float), np.asarray(dec_model, dtype=float)


def _astrometry_curve_fit(arrays: Mapping[str, Any], p0: Any | None = None, sigma_scale: Any | None = None) -> tuple[np.ndarray, np.ndarray]:
    try:
        from scipy.optimize import curve_fit
    except Exception:
        return _astrometry_linear_fit(arrays, sigma_scale=sigma_scale)

    if p0 is None:
        p0, _ = _astrometry_linear_fit(arrays, sigma_scale=sigma_scale)
    xdata = np.vstack([
        np.asarray(arrays["dt"], dtype=float),
        np.asarray(arrays["pra"], dtype=float),
        np.asarray(arrays["pdec"], dtype=float),
    ])
    ydata = np.concatenate([
        np.asarray(arrays["y_ra"], dtype=float),
        np.asarray(arrays["y_dec"], dtype=float),
    ])
    sigma = np.concatenate([
        np.asarray(arrays["s_ra"], dtype=float),
        np.asarray(arrays["s_dec"], dtype=float),
    ])
    if sigma_scale is not None:
        scale = np.asarray(sigma_scale, dtype=float)
        if scale.size == np.asarray(arrays["dt"]).size:
            scale = np.concatenate([scale, scale])
        sigma = sigma / np.sqrt(np.clip(scale, 1e-6, None))
    sigma = np.clip(sigma, 1e-3, np.inf)

    def model(xvals: Any, *theta: float) -> np.ndarray:
        local = dict(arrays)
        local["dt"] = np.asarray(xvals[0], dtype=float)
        local["pra"] = np.asarray(xvals[1], dtype=float)
        local["pdec"] = np.asarray(xvals[2], dtype=float)
        ra_model, dec_model = _astrometry_model_from_params(local, theta)
        return np.concatenate([ra_model, dec_model])

    try:
        popt, pcov = curve_fit(
            model,
            xdata,
            ydata,
            p0=np.asarray(p0, dtype=float),
            sigma=sigma,
            absolute_sigma=True,
            maxfev=20000,
        )
        return np.asarray(popt, dtype=float), np.asarray(pcov, dtype=float)
    except Exception:
        return _astrometry_linear_fit(arrays, sigma_scale=sigma_scale)


def _astrometry_outlier_scales(arrays: Mapping[str, Any]) -> tuple[float, float]:
    y_ra = np.asarray(arrays["y_ra"], dtype=float)
    y_dec = np.asarray(arrays["y_dec"], dtype=float)
    s_ra = np.asarray(arrays["s_ra"], dtype=float)
    s_dec = np.asarray(arrays["s_dec"], dtype=float)
    mad_ra = np.nanmedian(np.abs(y_ra - np.nanmedian(y_ra)))
    mad_dec = np.nanmedian(np.abs(y_dec - np.nanmedian(y_dec)))
    scale_ra = max(float(1.4826 * mad_ra) if np.isfinite(mad_ra) else 0.0, 4.0 * float(np.nanmedian(s_ra)), 1.0)
    scale_dec = max(float(1.4826 * mad_dec) if np.isfinite(mad_dec) else 0.0, 4.0 * float(np.nanmedian(s_dec)), 1.0)
    return scale_ra, scale_dec


def _astrometry_mixture_responsibilities(
    arrays: Mapping[str, Any],
    params: Any,
    stationary_ra: float,
    stationary_dec: float,
    mixture_weight: float,
    outlier_scale_ra: float,
    outlier_scale_dec: float,
    error_floor_ra: float = 0.0,
    error_floor_dec: float = 0.0,
) -> np.ndarray:
    y_ra = np.asarray(arrays["y_ra"], dtype=float)
    y_dec = np.asarray(arrays["y_dec"], dtype=float)
    s_ra = np.asarray(arrays["s_ra"], dtype=float)
    s_dec = np.asarray(arrays["s_dec"], dtype=float)
    ra_model, dec_model = _astrometry_model_from_params(arrays, params)
    floor_ra = max(float(error_floor_ra or 0.0), 0.0)
    floor_dec = max(float(error_floor_dec or 0.0), 0.0)
    sig_ra_mov = np.sqrt(s_ra**2 + floor_ra**2)
    sig_dec_mov = np.sqrt(s_dec**2 + floor_dec**2)
    sig_ra_out = np.sqrt(sig_ra_mov**2 + float(outlier_scale_ra) ** 2)
    sig_dec_out = np.sqrt(sig_dec_mov**2 + float(outlier_scale_dec) ** 2)
    w = float(np.clip(mixture_weight, 1e-4, 1.0 - 1e-4))
    log_mov = (
        math.log(w)
        - 0.5 * (((y_ra - ra_model) / sig_ra_mov) ** 2 + ((y_dec - dec_model) / sig_dec_mov) ** 2)
        - np.log(2.0 * math.pi * sig_ra_mov * sig_dec_mov)
    )
    log_out = (
        math.log(1.0 - w)
        - 0.5 * (((y_ra - stationary_ra) / sig_ra_out) ** 2 + ((y_dec - stationary_dec) / sig_dec_out) ** 2)
        - np.log(2.0 * math.pi * sig_ra_out * sig_dec_out)
    )
    delta = np.clip(log_out - log_mov, -700.0, 700.0)
    return 1.0 / (1.0 + np.exp(delta))


def _astrometry_stationary_offsets(
    arrays: Mapping[str, Any],
    responsibilities: Any,
    outlier_scale_ra: float,
    outlier_scale_dec: float,
    error_floor_ra: float = 0.0,
    error_floor_dec: float = 0.0,
) -> tuple[float, float]:
    r = np.asarray(responsibilities, dtype=float)
    y_ra = np.asarray(arrays["y_ra"], dtype=float)
    y_dec = np.asarray(arrays["y_dec"], dtype=float)
    s_ra = np.asarray(arrays["s_ra"], dtype=float)
    s_dec = np.asarray(arrays["s_dec"], dtype=float)
    sig_ra_out = np.sqrt(s_ra**2 + max(float(error_floor_ra or 0.0), 0.0) ** 2 + float(outlier_scale_ra) ** 2)
    sig_dec_out = np.sqrt(s_dec**2 + max(float(error_floor_dec or 0.0), 0.0) ** 2 + float(outlier_scale_dec) ** 2)
    w_ra = (1.0 - np.clip(r, 0.0, 1.0)) / np.clip(sig_ra_out, 1e-3, np.inf) ** 2
    w_dec = (1.0 - np.clip(r, 0.0, 1.0)) / np.clip(sig_dec_out, 1e-3, np.inf) ** 2
    stationary_ra = float(np.sum(w_ra * y_ra) / np.sum(w_ra)) if np.sum(w_ra) > 0 else float(np.nanmedian(y_ra))
    stationary_dec = float(np.sum(w_dec * y_dec) / np.sum(w_dec)) if np.sum(w_dec) > 0 else float(np.nanmedian(y_dec))
    return stationary_ra, stationary_dec


def _astrometry_weighted_quantile(values: Any, weights: Any, quantile: float) -> float:
    vals = np.asarray(values, dtype=float)
    w = np.asarray(weights, dtype=float)
    valid = np.isfinite(vals) & np.isfinite(w) & (w > 0)
    if not np.any(valid):
        return float("nan")
    vals = vals[valid]
    w = w[valid]
    order = np.argsort(vals)
    vals = vals[order]
    w = w[order]
    cumulative = np.cumsum(w)
    total = float(cumulative[-1])
    if total <= 0:
        return float("nan")
    return float(np.interp(float(np.clip(quantile, 0.0, 1.0)) * total, cumulative, vals))


def _astrometry_residual_error_floor(
    arrays: Mapping[str, Any],
    params: Any,
    responsibilities: Any | None = None,
) -> tuple[float, float]:
    n = np.asarray(arrays["t"]).size
    weights = np.ones(n, dtype=float) if responsibilities is None else np.clip(np.asarray(responsibilities, dtype=float), 0.0, 1.0)
    weights = np.maximum(weights, 1e-3)
    ra_model, dec_model = _astrometry_model_from_params(arrays, params)

    def axis_floor(residual: Any, sigma: Any) -> float:
        abs_resid = np.abs(np.asarray(residual, dtype=float))
        sig = np.asarray(sigma, dtype=float)
        med_abs = _astrometry_weighted_quantile(abs_resid, weights, 0.5)
        med_sigma = _astrometry_weighted_quantile(sig, weights, 0.5)
        if not np.isfinite(med_abs) or not np.isfinite(med_sigma):
            return 0.0
        robust_sigma = med_abs / 0.67448975
        floor_sq = robust_sigma**2 - med_sigma**2
        if not np.isfinite(floor_sq) or floor_sq <= 0:
            return 0.0
        return float(math.sqrt(floor_sq))

    return (
        axis_floor(np.asarray(arrays["y_ra"], dtype=float) - ra_model, arrays["s_ra"]),
        axis_floor(np.asarray(arrays["y_dec"], dtype=float) - dec_model, arrays["s_dec"]),
    )


def _astrometry_arrays_with_error_floor(
    arrays: Mapping[str, Any],
    error_floor_ra: float,
    error_floor_dec: float,
) -> dict[str, Any]:
    local = dict(arrays)
    floor_ra = max(float(error_floor_ra or 0.0), 0.0)
    floor_dec = max(float(error_floor_dec or 0.0), 0.0)
    local["s_ra"] = np.sqrt(np.asarray(arrays["s_ra"], dtype=float) ** 2 + floor_ra**2)
    local["s_dec"] = np.sqrt(np.asarray(arrays["s_dec"], dtype=float) ** 2 + floor_dec**2)
    return local


def _astrometry_raw_fit_result(
    arrays: Mapping[str, Any],
    params: Any,
    covariance: Any,
    responsibilities: Any | None,
    *,
    fitter: str,
    outlier_mixture: bool,
    stationary_ra: float | None = None,
    stationary_dec: float | None = None,
    mixture_weight: float | None = None,
    outlier_scale_ra: float | None = None,
    outlier_scale_dec: float | None = None,
    error_floor: bool = False,
    error_floor_ra: float | None = None,
    error_floor_dec: float | None = None,
) -> dict[str, Any]:
    p = np.asarray(params, dtype=float)
    cov = np.asarray(covariance, dtype=float)
    n = np.asarray(arrays["t"]).size
    if responsibilities is None:
        r = np.ones(n, dtype=float)
    else:
        r = np.clip(np.asarray(responsibilities, dtype=float), 0.0, 1.0)
    inlier_mask = r >= 0.5 if outlier_mixture else np.ones(n, dtype=bool)
    if int(np.sum(inlier_mask)) < int(arrays["min_rows"]):
        order = np.argsort(r)[::-1]
        inlier_mask = np.zeros(n, dtype=bool)
        inlier_mask[order[: int(arrays["min_rows"])]] = True

    ra_model, dec_model = _astrometry_model_from_params(arrays, p)
    floor_ra = max(float(error_floor_ra or 0.0), 0.0) if error_floor else 0.0
    floor_dec = max(float(error_floor_dec or 0.0), 0.0) if error_floor else 0.0
    s_ra_eff = np.sqrt(np.asarray(arrays["s_ra"], dtype=float) ** 2 + floor_ra**2)
    s_dec_eff = np.sqrt(np.asarray(arrays["s_dec"], dtype=float) ** 2 + floor_dec**2)
    chi2_per_row = (
        ((np.asarray(arrays["y_ra"]) - ra_model) / s_ra_eff) ** 2
        + ((np.asarray(arrays["y_dec"]) - dec_model) / s_dec_eff) ** 2
    )
    chi2 = float(np.nansum(chi2_per_row[inlier_mask]))
    dof = max(2 * int(np.sum(inlier_mask)) - int(arrays["n_params"]), 1)
    reduced_chi2 = chi2 / dof
    variance_scale = max(reduced_chi2, 1.0)
    diag = np.diag(cov) if cov.ndim == 2 and cov.shape[0] >= p.size else np.full(p.size, np.nan)
    unc = np.sqrt(np.maximum(diag * variance_scale, 0.0))
    ids = np.asarray(arrays["ids"], dtype=object)
    return {
        "mode": arrays["mode"],
        "label": (
            f"{'UltraNest' if fitter == 'ultranest' else 'SciPy'} "
            f"{'PM + parallax' if arrays['is_parallax'] else 'PM'}"
        ),
        "fitter": fitter,
        "fitterLabel": "UltraNest" if fitter == "ultranest" else "SciPy",
        "outlierMixture": bool(outlier_mixture),
        "nRows": int(n),
        "nInliers": int(np.sum(inlier_mask)),
        "nOutliers": int(n - np.sum(inlier_mask)),
        "inlierIds": [str(value) for value in ids[inlier_mask]],
        "outlierIds": [str(value) for value in ids[~inlier_mask]],
        "responsibilities": [
            {"id": str(row_id), "inlierProbability": float(prob), "inlier": bool(mask)}
            for row_id, prob, mask in zip(ids, r, inlier_mask)
        ],
        "t0": float(arrays["t0"]),
        "posRa": float(p[0]),
        "pmra": float(p[1]),
        "posDec": float(p[2]),
        "pmdec": float(p[3]),
        "plx": float(p[4]) if arrays["is_parallax"] else None,
        "fixedPlx": None if arrays["is_parallax"] else float(arrays.get("fixed_plx") or 0.0),
        "posRaUnc": float(unc[0]) if unc.size > 0 and np.isfinite(unc[0]) else None,
        "pmraUnc": float(unc[1]) if unc.size > 1 and np.isfinite(unc[1]) else None,
        "posDecUnc": float(unc[2]) if unc.size > 2 and np.isfinite(unc[2]) else None,
        "pmdecUnc": float(unc[3]) if unc.size > 3 and np.isfinite(unc[3]) else None,
        "plxUnc": float(unc[4]) if arrays["is_parallax"] and unc.size > 4 and np.isfinite(unc[4]) else None,
        "chi2": chi2,
        "dof": int(dof),
        "reducedChi2": float(reduced_chi2),
        "stationaryRa": float(stationary_ra) if stationary_ra is not None and np.isfinite(stationary_ra) else None,
        "stationaryDec": float(stationary_dec) if stationary_dec is not None and np.isfinite(stationary_dec) else None,
        "mixtureWeight": float(mixture_weight) if mixture_weight is not None and np.isfinite(mixture_weight) else None,
        "outlierScaleRa": float(outlier_scale_ra) if outlier_scale_ra is not None and np.isfinite(outlier_scale_ra) else None,
        "outlierScaleDec": float(outlier_scale_dec) if outlier_scale_dec is not None and np.isfinite(outlier_scale_dec) else None,
        "errorFloor": bool(error_floor),
        "errorFloorRa": float(floor_ra) if error_floor and np.isfinite(floor_ra) else None,
        "errorFloorDec": float(floor_dec) if error_floor and np.isfinite(floor_dec) else None,
    }


def _astrometry_scipy_fit(
    arrays: Mapping[str, Any],
    outlier_mixture: bool,
    error_floor: bool = True,
) -> dict[str, Any]:
    params, covariance = _astrometry_curve_fit(arrays)
    stationary_ra = float(np.nanmedian(np.asarray(arrays["y_ra"], dtype=float)))
    stationary_dec = float(np.nanmedian(np.asarray(arrays["y_dec"], dtype=float)))
    mixture_weight = 1.0
    outlier_scale_ra, outlier_scale_dec = _astrometry_outlier_scales(arrays)
    responsibilities = np.ones(np.asarray(arrays["t"]).size, dtype=float)
    error_floor_ra = 0.0
    error_floor_dec = 0.0

    if error_floor:
        error_floor_ra, error_floor_dec = _astrometry_residual_error_floor(arrays, params, responsibilities)
        working_arrays = _astrometry_arrays_with_error_floor(arrays, error_floor_ra, error_floor_dec)
        params, covariance = _astrometry_curve_fit(working_arrays, p0=params)
    else:
        working_arrays = dict(arrays)

    if outlier_mixture:
        mixture_weight = 0.8
        for _ in range(18):
            responsibilities = _astrometry_mixture_responsibilities(
                arrays,
                params,
                stationary_ra,
                stationary_dec,
                mixture_weight,
                outlier_scale_ra,
                outlier_scale_dec,
                error_floor_ra=error_floor_ra,
                error_floor_dec=error_floor_dec,
            )
            if error_floor:
                error_floor_ra, error_floor_dec = _astrometry_residual_error_floor(arrays, params, responsibilities)
                working_arrays = _astrometry_arrays_with_error_floor(arrays, error_floor_ra, error_floor_dec)
            params, covariance = _astrometry_curve_fit(working_arrays, p0=params, sigma_scale=responsibilities)
            stationary_ra, stationary_dec = _astrometry_stationary_offsets(
                arrays,
                responsibilities,
                outlier_scale_ra,
                outlier_scale_dec,
                error_floor_ra=error_floor_ra,
                error_floor_dec=error_floor_dec,
            )
            mixture_weight = float(np.clip(np.nanmean(responsibilities), 0.05, 0.98))
        responsibilities = _astrometry_mixture_responsibilities(
            arrays,
            params,
            stationary_ra,
            stationary_dec,
            mixture_weight,
            outlier_scale_ra,
            outlier_scale_dec,
            error_floor_ra=error_floor_ra,
            error_floor_dec=error_floor_dec,
        )
    elif error_floor:
        for _ in range(4):
            error_floor_ra, error_floor_dec = _astrometry_residual_error_floor(arrays, params, responsibilities)
            working_arrays = _astrometry_arrays_with_error_floor(arrays, error_floor_ra, error_floor_dec)
            params, covariance = _astrometry_curve_fit(working_arrays, p0=params)

    return {
        "params": params,
        "covariance": covariance,
        "responsibilities": responsibilities,
        "stationary_ra": stationary_ra,
        "stationary_dec": stationary_dec,
        "mixture_weight": mixture_weight,
        "outlier_scale_ra": outlier_scale_ra,
        "outlier_scale_dec": outlier_scale_dec,
        "error_floor_ra": error_floor_ra,
        "error_floor_dec": error_floor_dec,
    }


def _astrometry_ultranest_bounds(arrays: Mapping[str, Any], seed_params: Any) -> list[tuple[float, float]]:
    seed = np.asarray(seed_params, dtype=float)
    ra_model, dec_model = _astrometry_model_from_params(arrays, seed)
    ra_resid = np.asarray(arrays["y_ra"], dtype=float) - ra_model
    dec_resid = np.asarray(arrays["y_dec"], dtype=float) - dec_model
    mad_ra = np.nanmedian(np.abs(ra_resid - np.nanmedian(ra_resid)))
    mad_dec = np.nanmedian(np.abs(dec_resid - np.nanmedian(dec_resid)))
    pos_scale = max(float(1.4826 * max(mad_ra, mad_dec)) if np.isfinite(max(mad_ra, mad_dec)) else 0.0, 1.0)
    baseline = max(float(np.nanmax(arrays["dt"]) - np.nanmin(arrays["dt"])), 1e-3)
    pm_scale = max(pos_scale / baseline, 0.05)
    pra = np.asarray(arrays["pra"], dtype=float)
    pdec = np.asarray(arrays["pdec"], dtype=float)
    proj_amp = max(float(np.nanmax(np.abs(np.concatenate([pra, pdec])))), 1e-2)
    plx_scale = max(pos_scale / proj_amp, 0.02)
    bounds = [
        (float(seed[0] - 8.0 * pos_scale), float(seed[0] + 8.0 * pos_scale)),
        (float(seed[1] - 8.0 * pm_scale), float(seed[1] + 8.0 * pm_scale)),
        (float(seed[2] - 8.0 * pos_scale), float(seed[2] + 8.0 * pos_scale)),
        (float(seed[3] - 8.0 * pm_scale), float(seed[3] + 8.0 * pm_scale)),
    ]
    if bool(arrays["is_parallax"]):
        bounds.append((float(seed[4] - 8.0 * plx_scale), float(seed[4] + 8.0 * plx_scale)))
    min_widths = [2.0, 0.2, 2.0, 0.2, 0.1]
    widened: list[tuple[float, float]] = []
    for index, (lo, hi) in enumerate(bounds):
        width = hi - lo
        min_width = min_widths[index]
        if width < min_width:
            mid = 0.5 * (lo + hi)
            lo = mid - 0.5 * min_width
            hi = mid + 0.5 * min_width
        widened.append((lo, hi))
    return widened


def _astrometry_ultranest_fit(
    arrays: Mapping[str, Any],
    seed_fit: Mapping[str, Any],
    outlier_mixture: bool,
    error_floor: bool = True,
) -> dict[str, Any]:
    if not _astrometry_ultranest_available():
        raise RuntimeError("UltraNest is not installed in this Python environment.")
    import ultranest
    import ultranest.stepsampler

    seed_params = np.asarray(seed_fit["params"], dtype=float)
    bounds = _astrometry_ultranest_bounds(arrays, seed_params)
    param_names = ["pos_ra", "pmra", "pos_dec", "pmdec"] + (["plx"] if arrays["is_parallax"] else [])
    stationary_ra = float(seed_fit.get("stationary_ra") if seed_fit.get("stationary_ra") is not None else np.nanmedian(arrays["y_ra"]))
    stationary_dec = float(seed_fit.get("stationary_dec") if seed_fit.get("stationary_dec") is not None else np.nanmedian(arrays["y_dec"]))
    mixture_weight = float(seed_fit.get("mixture_weight") if seed_fit.get("mixture_weight") is not None else 0.8)
    outlier_scale_ra = float(seed_fit.get("outlier_scale_ra") if seed_fit.get("outlier_scale_ra") is not None else _astrometry_outlier_scales(arrays)[0])
    outlier_scale_dec = float(seed_fit.get("outlier_scale_dec") if seed_fit.get("outlier_scale_dec") is not None else _astrometry_outlier_scales(arrays)[1])
    error_floor_ra = max(float(seed_fit.get("error_floor_ra") or 0.0), 0.0) if error_floor else 0.0
    error_floor_dec = max(float(seed_fit.get("error_floor_dec") or 0.0), 0.0) if error_floor else 0.0
    y_ra = np.asarray(arrays["y_ra"], dtype=float)
    y_dec = np.asarray(arrays["y_dec"], dtype=float)
    s_ra = np.asarray(arrays["s_ra"], dtype=float)
    s_dec = np.asarray(arrays["s_dec"], dtype=float)
    sig_ra_mov = np.sqrt(s_ra**2 + error_floor_ra**2)
    sig_dec_mov = np.sqrt(s_dec**2 + error_floor_dec**2)
    sig_ra_out = np.sqrt(sig_ra_mov**2 + outlier_scale_ra**2)
    sig_dec_out = np.sqrt(sig_dec_mov**2 + outlier_scale_dec**2)

    def transform(unit_cube: Any) -> list[float]:
        u = np.asarray(unit_cube, dtype=float)
        return [lo + u[index] * (hi - lo) for index, (lo, hi) in enumerate(bounds)]

    def loglike(theta: Any) -> float:
        ra_model, dec_model = _astrometry_model_from_params(arrays, theta)
        mov = (
            -0.5 * (((y_ra - ra_model) / sig_ra_mov) ** 2 + ((y_dec - dec_model) / sig_dec_mov) ** 2)
            - np.log(2.0 * math.pi * sig_ra_mov * sig_dec_mov)
        )
        if not outlier_mixture:
            return float(np.nansum(mov))
        w = float(np.clip(mixture_weight, 1e-4, 1.0 - 1e-4))
        out = (
            -0.5 * (((y_ra - stationary_ra) / sig_ra_out) ** 2 + ((y_dec - stationary_dec) / sig_dec_out) ** 2)
            - np.log(2.0 * math.pi * sig_ra_out * sig_dec_out)
        )
        return float(np.nansum(np.logaddexp(math.log(w) + mov, math.log(1.0 - w) + out)))

    log_dir = Path(tempfile.gettempdir()) / "mocaviz_astrometry_ultranest"
    sampler = ultranest.ReactiveNestedSampler(
        param_names=param_names,
        loglike=loglike,
        transform=transform,
        resume="overwrite",
        log_dir=str(log_dir),
    )
    sampler.stepsampler = ultranest.stepsampler.RegionSliceSampler(nsteps=32)
    result = sampler.run(
        min_num_live_points=int(os.environ.get("ASTROMETRY_ULTRANEST_LIVE_POINTS", "300")),
        dlogz=float(os.environ.get("ASTROMETRY_ULTRANEST_DLOGZ", "0.5")),
    )
    posterior = result.get("posterior") if isinstance(result, Mapping) else None
    if not posterior:
        posterior = sampler.results.get("posterior")
    mean = np.asarray(posterior["mean"], dtype=float)
    stdev = np.asarray(posterior["stdev"], dtype=float)
    covariance = np.diag(stdev**2)
    responsibilities = (
        _astrometry_mixture_responsibilities(
            arrays,
            mean,
            stationary_ra,
            stationary_dec,
            mixture_weight,
            outlier_scale_ra,
            outlier_scale_dec,
            error_floor_ra=error_floor_ra,
            error_floor_dec=error_floor_dec,
        )
        if outlier_mixture
        else np.ones(np.asarray(arrays["t"]).size, dtype=float)
    )
    return {
        "params": mean,
        "covariance": covariance,
        "responsibilities": responsibilities,
        "stationary_ra": stationary_ra,
        "stationary_dec": stationary_dec,
        "mixture_weight": mixture_weight,
        "outlier_scale_ra": outlier_scale_ra,
        "outlier_scale_dec": outlier_scale_dec,
        "error_floor_ra": error_floor_ra,
        "error_floor_dec": error_floor_dec,
    }


def _run_astrometry_fit(body: Mapping[str, Any], args: dict[str, Any]) -> dict[str, Any]:
    arrays = _astrometry_fit_arrays(body)
    fitter = str(body.get("fitter") or body.get("method") or "scipy").strip().lower()
    if fitter not in {"scipy", "ultranest"}:
        raise ValueError("Fit method must be 'scipy' or 'ultranest'.")
    outlier_mixture = not _as_false(body.get("outlierMixture", body.get("outlier_mixture", True)))
    error_floor = not _as_false(body.get("errorFloor", body.get("error_floor", True)))

    scipy_fit = _astrometry_scipy_fit(arrays, outlier_mixture=outlier_mixture, error_floor=error_floor)
    if fitter == "ultranest":
        capabilities = _astrometry_fit_capabilities(args)
        ultranest_capability = capabilities["fitters"]["ultranest"]
        if not ultranest_capability["enabled"]:
            raise RuntimeError(ultranest_capability["message"] or "UltraNest fitting is not available.")
        raw_fit = _astrometry_ultranest_fit(arrays, scipy_fit, outlier_mixture=outlier_mixture, error_floor=error_floor)
    else:
        raw_fit = scipy_fit

    fit = _astrometry_raw_fit_result(
        arrays,
        raw_fit["params"],
        raw_fit["covariance"],
        raw_fit["responsibilities"],
        fitter=fitter,
        outlier_mixture=outlier_mixture,
        stationary_ra=raw_fit.get("stationary_ra"),
        stationary_dec=raw_fit.get("stationary_dec"),
        mixture_weight=raw_fit.get("mixture_weight"),
        outlier_scale_ra=raw_fit.get("outlier_scale_ra"),
        outlier_scale_dec=raw_fit.get("outlier_scale_dec"),
        error_floor=error_floor,
        error_floor_ra=raw_fit.get("error_floor_ra"),
        error_floor_dec=raw_fit.get("error_floor_dec"),
    )
    return {"fit": _pythonize(fit), "capabilities": _astrometry_fit_capabilities(args)}


def _astrometry_management_allowed(args: dict[str, Any]) -> tuple[bool, str]:
    auth = _auth_context(args)
    if auth.get("has_credentials") and not auth.get("private_db"):
        return False, "Astrometry fit pushes require the private MOCAdb schema."
    if auth.get("role") != "management":
        return False, "Management credentials are required."
    if args.get("mock") in {"1", "true", "yes"}:
        return False, "Mock astrometry cannot be written to MOCAdb."
    if not _is_private_db(args):
        return False, "Astrometry fit pushes require the private MOCAdb schema."
    return True, ""


def _astrometry_push_bool(value: Any) -> bool:
    if isinstance(value, bool):
        return value
    return _as_bool(value)


def _astrometry_push_float(value: Any, label: str, *, positive: bool = False) -> float:
    number = _safe_float(value)
    if number is None or (positive and number <= 0):
        suffix = " positive" if positive else " finite"
        raise ValueError(f"A{suffix} {label} is required.")
    return float(number)


def _astrometry_push_optional_float(value: Any) -> float | None:
    number = _safe_float(value)
    return float(number) if number is not None else None


def _astrometry_push_selected_tables(body: Mapping[str, Any]) -> list[str]:
    push = body.get("push") if isinstance(body.get("push"), Mapping) else {}
    selected: list[str] = []
    if _astrometry_push_bool(push.get("coordinate", push.get("coordinates", push.get("refCoord", False)))):
        selected.append("coordinate")
    if _astrometry_push_bool(push.get("pm", push.get("properMotion", False))):
        selected.append("pm")
    if _astrometry_push_bool(push.get("parallax", push.get("plx", False))):
        selected.append("parallax")
    if not selected:
        raise ValueError("Select at least one fitted quantity to push.")
    return selected


def _astrometry_push_visibility(body: Mapping[str, Any]) -> tuple[int, str]:
    visibility = body.get("visibility") if isinstance(body.get("visibility"), Mapping) else {}
    is_public = 1 if _astrometry_push_bool(visibility.get("isPublic", body.get("is_public", False))) else 0
    rls = str(visibility.get("rls", body.get("rls", "gagne")) or "").strip().lower()
    if is_public:
        return 1, "public"
    if not rls:
        raise ValueError("A non-public RLS value is required for private rows.")
    if len(rls) > 20:
        raise ValueError("RLS must be 20 characters or fewer.")
    return 0, rls


def _astrometry_push_text(value: Any, *, default: str = "", max_length: int | None = None) -> str:
    text_value = str(value if value is not None else default).strip()
    if not text_value:
        text_value = default
    if max_length is not None and len(text_value) > max_length:
        text_value = text_value[:max_length]
    return text_value


def _astrometry_push_moca_pid(value: Any) -> str | None:
    text_value = str(value or "").strip()
    if not text_value:
        return None
    if len(text_value) > 20:
        raise ValueError("moca_pid must be 20 characters or fewer.")
    return text_value


def _astrometry_parse_mission_label(label: Any) -> tuple[str | None, str]:
    text_value = str(label or "").strip()
    if not text_value or text_value.lower() == "no mission":
        return None, ""
    parts = text_value.split()
    if len(parts) >= 2:
        return " ".join(parts[:-1]), parts[-1]
    return parts[0], ""


def _astrometry_push_mission_parts(body: Mapping[str, Any]) -> tuple[str | None, str]:
    metadata = body.get("metadata") if isinstance(body.get("metadata"), Mapping) else {}
    raw = metadata.get("selectedMissions", metadata.get("selected_missions", []))
    if isinstance(raw, str):
        missions = [item.strip() for item in raw.replace(";", ",").split(",") if item.strip()]
    elif isinstance(raw, Sequence) and not isinstance(raw, (bytes, bytearray)):
        missions = [str(item).strip() for item in raw if str(item).strip()]
    else:
        missions = []
    unique = list(dict.fromkeys(missions))
    if len(unique) == 1:
        return _astrometry_parse_mission_label(unique[0])
    return None, ""


def _astrometry_push_nonnegative_int(value: Any) -> int | None:
    if value is None or value == "":
        return None
    try:
        number = float(value)
    except (TypeError, ValueError):
        return None
    if not math.isfinite(number) or number < 0:
        return None
    return int(round(number))


def _astrometry_push_count_from_ids(value: Any) -> int:
    if isinstance(value, str):
        items = [item.strip() for item in value.replace(";", ",").split(",") if item.strip()]
        return len(items)
    if isinstance(value, Sequence) and not isinstance(value, (bytes, bytearray)):
        return len([item for item in value if item is not None and str(item).strip()])
    return 0


def _astrometry_push_manual_rejected_count(metadata: Mapping[str, Any]) -> int:
    explicit = _astrometry_push_nonnegative_int(
        metadata.get("manualRejectedCount", metadata.get("manual_rejected_count"))
    )
    if explicit is not None:
        return explicit
    return _astrometry_push_count_from_ids(metadata.get("manualRejectedIds", metadata.get("manual_rejected_ids", [])))


def _astrometry_push_automatic_rejected_count(metadata: Mapping[str, Any], fit: Mapping[str, Any]) -> int:
    explicit = _astrometry_push_nonnegative_int(
        metadata.get("automaticRejectedCount", metadata.get("automatic_rejected_count"))
    )
    if explicit is not None:
        return explicit
    if _as_false(fit.get("outlierMixture", fit.get("outlier_mixture", True))):
        return 0
    n_outliers = _astrometry_push_nonnegative_int(fit.get("nOutliers", fit.get("n_outliers")))
    if n_outliers is not None:
        return n_outliers
    return _astrometry_push_count_from_ids(fit.get("outlierIds", fit.get("outlier_ids", [])))


def _astrometry_push_mission_counts(metadata: Mapping[str, Any]) -> list[dict[str, Any]]:
    raw = metadata.get("missionCounts", metadata.get("mission_counts", []))
    if isinstance(raw, str):
        parts = [item.strip() for item in raw.replace("|", ";").split(";") if item.strip()]
        rows = []
        for item in parts:
            if "=" in item:
                mission, count = item.rsplit("=", 1)
            elif ":" in item:
                mission, count = item.rsplit(":", 1)
            else:
                continue
            n_data = _astrometry_push_nonnegative_int(count.strip())
            if n_data is not None:
                rows.append({"mission": mission.strip() or "No mission", "n_data": n_data})
        return rows
    if not isinstance(raw, Sequence) or isinstance(raw, (bytes, bytearray)):
        return []
    rows = []
    for item in raw:
        if isinstance(item, Mapping):
            mission = str(item.get("mission", item.get("label", item.get("name", "No mission"))) or "No mission").strip()
            n_data = _astrometry_push_nonnegative_int(item.get("nData", item.get("n_data", item.get("count"))))
        elif isinstance(item, Sequence) and not isinstance(item, (str, bytes, bytearray)) and len(item) >= 2:
            mission = str(item[0] or "No mission").strip()
            n_data = _astrometry_push_nonnegative_int(item[1])
        else:
            continue
        if n_data is None:
            continue
        rows.append({"mission": mission or "No mission", "n_data": n_data})
    return rows


def _astrometry_push_mission_counts_text(mission_counts: Sequence[Mapping[str, Any]]) -> str:
    parts = []
    for item in mission_counts:
        mission = str(item.get("mission") or "No mission").strip() or "No mission"
        n_data = _astrometry_push_nonnegative_int(item.get("n_data", item.get("nData")))
        if n_data is None:
            continue
        parts.append(f"{mission}:{n_data}")
    return "[" + ", ".join(parts) + "]" if parts else ""


def _astrometry_push_fit_provenance(fit: Mapping[str, Any], metadata: Mapping[str, Any]) -> dict[str, Any]:
    method = str(fit.get("fitter") or fit.get("method") or fit.get("fitterLabel") or "scipy").strip().lower()
    if method not in {"scipy", "ultranest"}:
        method = "ultranest" if "ultra" in method else "scipy"
    mode = str(fit.get("mode") or "pm").strip().lower()
    n_rows = _astrometry_push_nonnegative_int(fit.get("nRows", fit.get("n_rows")))
    n_inliers = _astrometry_push_nonnegative_int(fit.get("nInliers", fit.get("n_inliers")))
    manual_rejected = _astrometry_push_manual_rejected_count(metadata)
    automatic_rejected = _astrometry_push_automatic_rejected_count(metadata, fit)
    mission_counts = _astrometry_push_mission_counts(metadata)
    mission_counts_text = _astrometry_push_mission_counts_text(mission_counts)
    outlier_mixture = not _as_false(fit.get("outlierMixture", fit.get("outlier_mixture", True)))
    parts = [
        f"fit_method={method}",
        f"fit_mode={mode}",
        f"fit_outlier_mixture={1 if outlier_mixture else 0}",
        f"n_fit_data={n_rows}" if n_rows is not None else "",
        f"n_fit_inliers={n_inliers}" if n_inliers is not None else "",
        f"n_manual_rejected={manual_rejected}",
        f"n_fit_rejected={automatic_rejected}",
        f"fit_missions={mission_counts_text}" if mission_counts_text else "",
    ]
    return {
        "method": method,
        "mode": mode,
        "n_rows": n_rows,
        "n_inliers": n_inliers,
        "manual_rejected": manual_rejected,
        "automatic_rejected": automatic_rejected,
        "mission_counts": mission_counts,
        "text": "; ".join(part for part in parts if part),
    }


def _astrometry_push_comments_with_provenance(base_comments: str, provenance: Mapping[str, Any]) -> str:
    text_value = str(base_comments or "").strip()
    provenance_text = str(provenance.get("text") or "").strip()
    if not provenance_text:
        return text_value
    if not text_value:
        return provenance_text
    if provenance_text in text_value:
        return text_value
    return f"{text_value}; {provenance_text}"


def _astrometry_push_default_origin(fit: Mapping[str, Any]) -> str:
    mode = "pm_plx" if str(fit.get("mode") or "").strip().lower() == "pm_plx" else "pm"
    origin = f"mocaviz_astrometry_{mode}_fit"
    if str(fit.get("fitter") or "").strip().lower() == "ultranest":
        origin += "_ultranest"
    return origin


def _astrometry_push_calculation_method(fit: Mapping[str, Any]) -> str:
    mode = "pmplx" if str(fit.get("mode") or "").strip().lower() == "pm_plx" else "pm"
    if str(fit.get("fitter") or "").strip().lower() == "ultranest":
        return f"mocaviz_{mode}_ultra"
    return f"mocaviz_{mode}_fit"


def _astrometry_mysql_identifier(name: str) -> str:
    if not SAFE_SCHEMA_RE.fullmatch(str(name)):
        raise ValueError(f"Unsafe SQL identifier: {name!r}")
    return f"`{name}`"


def _astrometry_insert_row(conn, table_name: str, row: Mapping[str, Any]) -> int | None:
    columns = _db_table_columns(conn, table_name)
    insert_keys = [
        key
        for key, value in row.items()
        if key in columns and value is not None
    ]
    if not insert_keys:
        raise RuntimeError(f"No insertable columns were prepared for {table_name}.")
    column_sql = ", ".join(_astrometry_mysql_identifier(key) for key in insert_keys)
    value_sql = ", ".join(f":{key}" for key in insert_keys)
    result = conn.execute(
        text(f"INSERT INTO {_astrometry_mysql_identifier(table_name)} ({column_sql}) VALUES ({value_sql})"),
        {key: row[key] for key in insert_keys},
    )
    inserted_id = getattr(result, "lastrowid", None)
    try:
        return int(inserted_id) if inserted_id else None
    except (TypeError, ValueError):
        return None


def _astrometry_duplicate_count(conn, table_name: str, row: Mapping[str, Any]) -> dict[str, Any]:
    columns = _db_table_columns(conn, table_name)
    if "moca_oid" not in columns:
        return {"count": 0, "basis": "none"}
    conditions = ["moca_oid = :moca_oid"]
    params: dict[str, Any] = {"moca_oid": row.get("moca_oid")}
    basis = "moca_oid"
    if row.get("moca_pid") and "moca_pid" in columns:
        conditions.append("moca_pid = :moca_pid")
        params["moca_pid"] = row.get("moca_pid")
        basis = "moca_pid"
    elif row.get("origin") and "origin" in columns:
        conditions.append("origin = :origin")
        params["origin"] = row.get("origin")
        basis = "origin"
    if "ignored" in columns:
        conditions.append("COALESCE(ignored, 0) = 0")
    query = text(
        f"SELECT COUNT(*) FROM {_astrometry_mysql_identifier(table_name)} "
        f"WHERE {' AND '.join(conditions)}"
    )
    count = int(conn.execute(query, params).scalar() or 0)
    return {"count": count, "basis": basis}


def _astrometry_validate_moca_pid(conn, moca_pid: str | None) -> None:
    if not moca_pid or not _db_table_exists(conn, "moca_publications"):
        return
    count = int(conn.execute(
        text("SELECT COUNT(*) FROM moca_publications WHERE moca_pid = :moca_pid"),
        {"moca_pid": moca_pid},
    ).scalar() or 0)
    if count < 1:
        raise ValueError(f"moca_pid {moca_pid!r} does not exist in moca_publications.")


def _astrometry_push_rows(body: Mapping[str, Any]) -> dict[str, Any]:
    selected = _astrometry_push_selected_tables(body)
    fit = body.get("fit") if isinstance(body.get("fit"), Mapping) else {}
    fitted_coordinate = body.get("fittedCoordinate") if isinstance(body.get("fittedCoordinate"), Mapping) else {}
    metadata = body.get("metadata") if isinstance(body.get("metadata"), Mapping) else {}
    target = body.get("target") if isinstance(body.get("target"), Mapping) else {}
    moca_oid_raw = target.get("moca_oid", body.get("moca_oid", fit.get("moca_oid")))
    try:
        moca_oid = int(moca_oid_raw)
    except (TypeError, ValueError):
        raise ValueError("A numeric moca_oid is required for astrometry pushes.") from None
    if moca_oid <= 0:
        raise ValueError("A positive moca_oid is required for astrometry pushes.")

    mode = str(fit.get("mode") or "").strip().lower()
    if mode not in {"pm", "pm_plx"}:
        raise ValueError("Run a PM or PM+PLX fit before pushing values.")

    is_public, rls = _astrometry_push_visibility(body)
    moca_pid = _astrometry_push_moca_pid(metadata.get("mocaPid", metadata.get("moca_pid")))
    origin = _astrometry_push_text(
        metadata.get("origin"),
        default=_astrometry_push_default_origin(fit),
        max_length=255,
    )
    comments = _astrometry_push_text(
        metadata.get("comments"),
        default=f"{origin} (management push from JS astrometric explorer)",
    )
    provenance = _astrometry_push_fit_provenance(fit, metadata)
    comments = _astrometry_push_comments_with_provenance(comments, provenance)
    mission_name, data_release = _astrometry_push_mission_parts(body)
    common = {
        "moca_oid": moca_oid,
        "moca_pid": moca_pid,
        "mission_name": mission_name,
        "data_release": data_release,
        "origin": origin,
        "ignored": 0,
        "is_public": is_public,
        "comments": comments,
        "rls": rls,
    }

    rows: list[dict[str, Any]] = []
    if "pm" in selected:
        rows.append({
            "kind": "pm",
            "label": "Fitted proper motion",
            "table": "data_proper_motions",
            "values": {
                **common,
                "pmra_masyr": _astrometry_push_float(fit.get("pmra"), "fitted pmra"),
                "pmdec_masyr": _astrometry_push_float(fit.get("pmdec"), "fitted pmdec"),
                "pmra_masyr_unc": _astrometry_push_float(fit.get("pmraUnc"), "fitted pmra uncertainty", positive=True),
                "pmdec_masyr_unc": _astrometry_push_float(fit.get("pmdecUnc"), "fitted pmdec uncertainty", positive=True),
                "calculation_method": _astrometry_push_calculation_method(fit),
            },
        })
    if "parallax" in selected:
        if mode != "pm_plx":
            raise ValueError("A PM+PLX fit is required before pushing a fitted parallax.")
        rows.append({
            "kind": "parallax",
            "label": "Fitted parallax",
            "table": "data_parallaxes",
            "values": {
                **common,
                "parallax_mas": _astrometry_push_float(fit.get("plx"), "fitted parallax"),
                "parallax_mas_unc": _astrometry_push_float(fit.get("plxUnc"), "fitted parallax uncertainty", positive=True),
            },
        })
    if "coordinate" in selected:
        rows.append({
            "kind": "coordinate",
            "label": "Fitted reference coordinate",
            "table": "data_equatorial_coordinates",
            "values": {
                **common,
                "ra": _astrometry_push_float(fitted_coordinate.get("ra"), "fitted R.A."),
                "dec": _astrometry_push_float(fitted_coordinate.get("dec"), "fitted Decl."),
                "ra_unc_mas": _astrometry_push_float(
                    fitted_coordinate.get("raUncMas", fitted_coordinate.get("ra_unc_mas")),
                    "fitted R.A. uncertainty",
                    positive=True,
                ),
                "dec_unc_mas": _astrometry_push_float(
                    fitted_coordinate.get("decUncMas", fitted_coordinate.get("dec_unc_mas")),
                    "fitted Decl. uncertainty",
                    positive=True,
                ),
                "measurement_epoch_yr": _astrometry_push_float(
                    fitted_coordinate.get("epoch", fit.get("t0")),
                    "fitted coordinate epoch",
                ),
                "measurement_epoch_yr_unc": _astrometry_push_optional_float(fitted_coordinate.get("epochUnc")) or 0.0,
                "frame_equinox": "J2000",
                "coord_frame": "ICRS",
                "single_epoch": 0,
                "pm_corrected": 1,
                "plx_corrected": 1 if mode == "pm_plx" else 0,
                "point_of_view": "earth",
            },
        })

    return {
        "moca_oid": moca_oid,
        "moca_pid": moca_pid,
        "origin": origin,
        "comments": comments,
        "is_public": is_public,
        "rls": rls,
        "fit_provenance": provenance,
        "rows": rows,
        "fit": {
            "mode": mode,
            "fitter": provenance.get("method") or fit.get("fitter") or "scipy",
            "n_rows": provenance.get("n_rows"),
            "n_inliers": provenance.get("n_inliers"),
            "manual_rejected": provenance.get("manual_rejected"),
            "automatic_rejected": provenance.get("automatic_rejected"),
            "mission_counts": provenance.get("mission_counts"),
            "reduced_chi2": fit.get("reducedChi2"),
        },
    }


def _astrometry_push_changelog_row(
    conn,
    *,
    args: dict[str, Any],
    prepared: Mapping[str, Any],
    inserted_rows: Sequence[Mapping[str, Any]],
) -> int | None:
    if not inserted_rows or not _db_table_exists(conn, "moca_changelog"):
        return None
    cfg = _db_config(args)
    tables = ", ".join(sorted({str(row.get("table")) for row in inserted_rows}))
    labels = ", ".join(str(row.get("label") or row.get("kind")) for row in inserted_rows)
    fit = prepared.get("fit") if isinstance(prepared.get("fit"), Mapping) else {}
    description = (
        "MOCAViz astrometric explorer pushed "
        f"{labels} for moca_oid={prepared.get('moca_oid')} "
        f"from a {fit.get('fitter') or 'scipy'} {fit.get('mode') or 'pm'} fit."
    )
    provenance = prepared.get("fit_provenance") if isinstance(prepared.get("fit_provenance"), Mapping) else {}
    if provenance.get("text"):
        description = f"{description} {provenance['text']}"
    machine_name = ""
    try:
        machine_name = os.uname().nodename
    except Exception:
        machine_name = _request_host_name()
    row = {
        "user": _astrometry_push_text(cfg.get("username"), max_length=50),
        "machine_name": _astrometry_push_text(machine_name, max_length=50),
        "modified_tables": tables,
        "nrows_modified": len(inserted_rows),
        "user_description": description,
        "rls": prepared.get("rls"),
        "is_public": prepared.get("is_public"),
    }
    return _astrometry_insert_row(conn, "moca_changelog", row)


def _push_astrometry_fit_to_mocadb(args: dict[str, Any], body: Mapping[str, Any]) -> dict[str, Any]:
    dry_run = not _as_false(body.get("dryRun", body.get("dry_run", True)))
    allow_duplicate = _astrometry_push_bool(body.get("allowDuplicate", body.get("allow_duplicate", False)))
    prepared = _astrometry_push_rows(body)
    engine = _engine(_connection_string(args))
    inserted: list[dict[str, Any]] = []
    duplicates: list[dict[str, Any]] = []
    required_tables = {str(row["table"]) for row in prepared["rows"]}

    with engine.begin() as conn:
        for table_name in required_tables:
            if not _db_table_exists(conn, table_name):
                raise RuntimeError(f"The {table_name} table is not available.")
        _astrometry_validate_moca_pid(conn, prepared.get("moca_pid"))

        for row in prepared["rows"]:
            duplicate = _astrometry_duplicate_count(conn, str(row["table"]), row["values"])
            row["duplicate_count"] = duplicate["count"]
            row["duplicate_basis"] = duplicate["basis"]
            if duplicate["count"] > 0:
                duplicates.append({
                    "kind": row["kind"],
                    "label": row["label"],
                    "table": row["table"],
                    "count": duplicate["count"],
                    "basis": duplicate["basis"],
                })

        if duplicates and not dry_run and not allow_duplicate:
            return {
                "dryRun": dry_run,
                "blocked": True,
                "requiresConfirmation": True,
                "error": "Existing active rows match this push. Enable duplicate pushes to insert anyway.",
                "preparedRows": prepared["rows"],
                "duplicates": duplicates,
                "fitProvenance": (prepared.get("fit_provenance") or {}).get("text") if isinstance(prepared.get("fit_provenance"), Mapping) else "",
            }

        if not dry_run:
            for row in prepared["rows"]:
                inserted_id = _astrometry_insert_row(conn, str(row["table"]), row["values"])
                inserted.append({
                    "kind": row["kind"],
                    "label": row["label"],
                    "table": row["table"],
                    "id": inserted_id,
                })
            changelog_id = _astrometry_push_changelog_row(conn, args=args, prepared=prepared, inserted_rows=inserted)
        else:
            changelog_id = None

    cleared = {}
    if not dry_run:
        cleared = {"astrometryObjects": len(_ASTROMETRY_OBJECT_CACHE)}
        _ASTROMETRY_OBJECT_CACHE.clear()
    return {
        "dryRun": dry_run,
        "blocked": False,
        "requiresConfirmation": bool(duplicates and dry_run),
        "preparedRows": prepared["rows"],
        "duplicates": duplicates,
        "inserted": inserted,
        "insertedCount": len(inserted),
        "changelogId": changelog_id,
        "moca_oid": prepared.get("moca_oid"),
        "origin": prepared.get("origin"),
        "moca_pid": prepared.get("moca_pid"),
        "is_public": prepared.get("is_public"),
        "rls": prepared.get("rls"),
        "fitProvenance": (prepared.get("fit_provenance") or {}).get("text") if isinstance(prepared.get("fit_provenance"), Mapping) else "",
        "cleared": cleared,
    }


def _format_astrometry_reference(row: dict[str, Any] | None, prefix: str) -> str:
    if not row:
        return f"No adopted {prefix}"
    source = row.get("publication_name") or row.get("moca_pid") or row.get("origin") or f"No adopted {prefix}"
    mission = " ".join(
        str(part).strip()
        for part in (row.get("mission_name"), row.get("data_release"))
        if part is not None and str(part).strip()
    )
    return f"{source}, {mission}" if mission else str(source)


def _astrometry_bibcode_sql(alias: str, table_columns: set[str], publication_columns: set[str]) -> str:
    parts = []
    if "bibcode" in table_columns:
        parts.append(f"{alias}.bibcode")
    if "bibcode" in publication_columns:
        parts.append("mp.bibcode")
    if not parts:
        return "NULL"
    if len(parts) == 1:
        return parts[0]
    return "COALESCE(" + ", ".join(parts) + ")"


def _search_astrometry_objects_from_db(args: dict[str, Any], query: str, selected_oid: int | None) -> dict[str, Any]:
    engine = _engine(_connection_string(args))
    with engine.connect() as conn:
        if selected_oid is not None:
            rows = _records(_read_sql(conn, """
                SELECT mo.moca_oid, mo.designation
                FROM moca_objects mo
                WHERE mo.moca_oid = :oid
                LIMIT 1
            """, {"oid": selected_oid}))
            options = [
                {
                    "value": row["moca_oid"],
                    "moca_oid": row["moca_oid"],
                    "designation": row.get("designation"),
                    "label": f"oid{row['moca_oid']}: {row.get('designation') or 'MOCAdb object'}",
                }
                for row in rows
            ]
            return {"options": options, "value": selected_oid if options else None, "meta": {"row_count": len(options)}}

        query = (query or "").strip()
        if not query:
            query = "602"
        if query.isdigit():
            rows = _records(_read_sql(conn, """
                SELECT mo.moca_oid, mo.designation
                FROM moca_objects mo
                WHERE mo.moca_oid = :oid
                LIMIT 1
            """, {"oid": int(query)}))
        else:
            params = {"prefix": f"{query}%"}
            object_rows = _records(_read_sql(conn, """
                SELECT mo.moca_oid, mo.designation
                FROM moca_objects mo
                WHERE mo.designation LIKE :prefix
                ORDER BY mo.designation, mo.moca_oid
                LIMIT 15
            """, params))
            if object_rows:
                rows = object_rows
            else:
                rows = _records(_read_sql(conn, """
                    SELECT mad.moca_oid, mad.designation
                    FROM mechanics_all_designations mad
                    WHERE mad.designation LIKE :prefix
                    ORDER BY mad.designation, mad.moca_oid
                    LIMIT 30
                """, params))
    options = [
        {
            "value": row["moca_oid"],
            "moca_oid": row["moca_oid"],
            "designation": row.get("designation"),
            "label": f"oid{row['moca_oid']}: {row.get('designation') or 'MOCAdb object'}",
        }
        for row in rows
    ]
    return {"options": options, "value": options[0]["value"] if options else None, "meta": {"row_count": len(options)}}


def _load_astrometry_object_from_db(args: dict[str, Any], oid: int) -> dict[str, Any]:
    cache_key = _astrometry_db_cache_key(args, oid)
    include_merged = _include_merged_astrometry(args)
    single_epoch_filter = "1 = 1" if include_merged else "deq.single_epoch = 1"
    now = time.time()
    cached = _ASTROMETRY_OBJECT_CACHE.get(cache_key)
    if cached and now - cached[0] < CACHE_SECONDS:
        payload = copy.deepcopy(cached[1])
        payload["cache"] = {"hit": True, "ttl_seconds": CACHE_SECONDS}
        return payload

    engine = _engine(_connection_string(args))
    with engine.connect() as conn:
        target_rows = _records(_read_sql(conn, """
            SELECT mo.moca_oid, mo.designation
            FROM moca_objects mo
            WHERE mo.moca_oid = :oid
            LIMIT 1
        """, {"oid": oid}))
        designation_rows = _records(_read_sql(conn, """
            SELECT mad.designation
            FROM mechanics_all_designations mad
            WHERE mad.moca_oid = :oid
            ORDER BY mad.designation
            LIMIT 80
        """, {"oid": oid}))
        publication_columns = _db_table_columns(conn, "moca_publications") if _db_table_exists(conn, "moca_publications") else set()
        coordinate_columns = _db_table_columns(conn, "data_equatorial_coordinates")
        pm_columns = _db_table_columns(conn, "data_proper_motions")
        plx_columns = _db_table_columns(conn, "data_parallaxes")
        reference_bibcode_sql = _astrometry_bibcode_sql("deq", coordinate_columns, publication_columns)
        pm_bibcode_sql = _astrometry_bibcode_sql("dpm", pm_columns, publication_columns)
        plx_bibcode_sql = _astrometry_bibcode_sql("dplx", plx_columns, publication_columns)
        reference_ra_unc_sql = "deq.ra_unc_mas" if "ra_unc_mas" in coordinate_columns else "NULL"
        reference_dec_unc_sql = "deq.dec_unc_mas" if "dec_unc_mas" in coordinate_columns else "NULL"
        reference_rows = _records(_read_sql(conn, f"""
            SELECT
                deq.id,
                deq.ra,
                deq.`dec`,
                {reference_ra_unc_sql} AS ra_unc_mas,
                {reference_dec_unc_sql} AS dec_unc_mas,
                deq.ra - IFNULL(
                    deq.calibration_delta_ra_mas / (3600 * 1000 * COS(deq.`dec` * PI() / 180)),
                    0
                ) AS raw_ra,
                deq.`dec` - IFNULL(deq.calibration_delta_dec_mas / (3600 * 1000), 0) AS raw_dec,
                deq.measurement_epoch_yr,
                deq.adopt_as_reference,
                deq.bibcode,
                {reference_bibcode_sql} AS publication_bibcode,
                deq.moca_pid,
                mp.name AS publication_name,
                deq.mission_name,
                deq.data_release,
                deq.origin,
                deq.comments,
                deq.pm_corrected,
                deq.plx_corrected
            FROM data_equatorial_coordinates deq
            LEFT JOIN moca_publications mp ON mp.moca_pid = deq.moca_pid
            WHERE deq.moca_oid = :oid
                AND deq.ignored = 0
                AND deq.adopt_as_reference = 1
            ORDER BY deq.measurement_epoch_yr DESC, deq.id DESC
            LIMIT 1
        """, {"oid": oid}))
        pm_rows = _records(_read_sql(conn, f"""
            SELECT
                dpm.pmra_masyr,
                dpm.pmdec_masyr,
                dpm.pmra_masyr_unc,
                dpm.pmdec_masyr_unc,
                dpm.moca_pid,
                {pm_bibcode_sql} AS publication_bibcode,
                dpm.origin,
                dpm.mission_name,
                dpm.data_release,
                mp.name AS publication_name
            FROM data_proper_motions dpm
            LEFT JOIN moca_publications mp ON mp.moca_pid = dpm.moca_pid
            WHERE dpm.moca_oid = :oid
                AND dpm.adopted = 1
            LIMIT 1
        """, {"oid": oid}))
        plx_rows = _records(_read_sql(conn, f"""
            SELECT
                dplx.parallax_mas,
                dplx.parallax_mas_unc,
                dplx.moca_pid,
                {plx_bibcode_sql} AS publication_bibcode,
                dplx.origin,
                dplx.mission_name,
                dplx.data_release,
                mp.name AS publication_name
            FROM data_parallaxes dplx
            LEFT JOIN moca_publications mp ON mp.moca_pid = dplx.moca_pid
            WHERE dplx.moca_oid = :oid
                AND dplx.adopted = 1
            LIMIT 1
        """, {"oid": oid}))
        rows_df = _read_sql(conn, """
            SELECT
                deq.id,
                deq.ra,
                deq.`dec`,
                deq.ra - IFNULL(
                    deq.calibration_delta_ra_mas / (3600 * 1000 * COS(deq.`dec` * PI() / 180)),
                    0
                ) AS raw_ra,
                deq.`dec` - IFNULL(deq.calibration_delta_dec_mas / (3600 * 1000), 0) AS raw_dec,
                deq.measurement_epoch_yr,
                deq.single_epoch,
                deq.ra_unc_mas,
                deq.dec_unc_mas,
                COALESCE(deq.measurement_epoch_yr_unc, 0) AS measurement_epoch_yr_unc,
                CASE
                    WHEN deq.mission_name IS NULL OR TRIM(deq.mission_name) = ''
                        THEN COALESCE(CAST(deq.moca_pid AS CHAR), 'No mission')
                    WHEN TRIM(COALESCE(deq.data_release, '')) = ''
                        THEN TRIM(deq.mission_name)
                    ELSE TRIM(CONCAT(deq.mission_name, ' ', deq.data_release))
                END AS mission,
                deq.moca_pid,
                deq.mission_name,
                deq.data_release,
                deq.origin,
                deq.comments,
                deq.airmass,
                deq.moca_psid,
                deq.calibration_delta_ra_mas,
                deq.calibration_delta_dec_mas,
                deq.nstars_calibration,
                deq.calibration_method,
                COALESCE(mm.include_in_recalibrated_display, 0) AS include_in_recalibrated_display
            FROM data_equatorial_coordinates deq
            LEFT JOIN moca_missions mm
                ON mm.mission_name = deq.mission_name
                AND mm.data_release = deq.data_release
            WHERE deq.moca_oid = :oid
                AND deq.ignored = 0
                AND {single_epoch_filter}
            ORDER BY deq.measurement_epoch_yr, deq.id
            LIMIT 20000
        """.format(single_epoch_filter=single_epoch_filter), {"oid": oid})

    rows = _records(rows_df)
    reference = reference_rows[0] if reference_rows else None
    if reference is None and rows:
        finite_rows = [
            row for row in rows
            if row.get("ra") is not None and row.get("dec") is not None and row.get("measurement_epoch_yr") is not None
        ]
        if finite_rows:
            median_index = len(finite_rows) // 2
            reference = {
                "id": finite_rows[median_index].get("id"),
                "ra": finite_rows[median_index].get("ra"),
                "dec": finite_rows[median_index].get("dec"),
                "ra_unc_mas": finite_rows[median_index].get("ra_unc_mas"),
                "dec_unc_mas": finite_rows[median_index].get("dec_unc_mas"),
                "measurement_epoch_yr": finite_rows[median_index].get("measurement_epoch_yr"),
                "fallback": True,
            }

    target = target_rows[0] if target_rows else {"moca_oid": int(oid), "designation": None}
    pm = pm_rows[0] if pm_rows else {}
    pm["reference"] = _format_astrometry_reference(pm_rows[0] if pm_rows else None, "PM")
    plx = plx_rows[0] if plx_rows else {}
    plx["reference"] = _format_astrometry_reference(plx_rows[0] if plx_rows else None, "parallax")
    mission_counts: dict[str, int] = {}
    for row in rows:
        mission = str(row.get("mission") or "No mission")
        mission_counts[mission] = mission_counts.get(mission, 0) + 1
    missions = [
        {"value": mission, "label": f"{mission} ({count})", "count": count}
        for mission, count in sorted(mission_counts.items(), key=lambda item: item[0].lower())
    ]
    payload = {
        "target": {
            "moca_oid": int(oid),
            "designation": target.get("designation"),
            "designations": [row.get("designation") for row in designation_rows if row.get("designation")],
        },
        "reference": reference or {},
        "pm": pm,
        "parallax": plx,
        "missions": missions,
        "rows": rows,
        "meta": {
            "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
            "row_count": len(rows),
            "mission_count": len(missions),
            "private_db": _is_private_db(args),
            "include_merged_astrometry": include_merged,
        },
        "cache": {"hit": False, "ttl_seconds": CACHE_SECONDS},
    }
    _ASTROMETRY_OBJECT_CACHE[cache_key] = (now, copy.deepcopy(payload))
    return payload


def _mock_astrometry_search(query: str, selected_oid: int | None = None) -> dict[str, Any]:
    options = [
        {"value": 602, "moca_oid": 602, "designation": "SIMP J013656.5+093347.3", "label": "oid602: SIMP J013656.5+093347.3"},
        {"value": 10995, "moca_oid": 10995, "designation": "Mock high-motion dwarf", "label": "oid10995: Mock high-motion dwarf"},
    ]
    if selected_oid is not None:
        options = [row for row in options if int(row["moca_oid"]) == int(selected_oid)]
    elif query:
        q = str(query).lower()
        options = [row for row in options if q in str(row["label"]).lower()]
    return {"options": options, "value": options[0]["value"] if options else None, "meta": {"row_count": len(options)}}


def _mock_astrometry_object(oid: int, include_merged: bool = False) -> dict[str, Any]:
    rng = np.random.default_rng(int(oid) % 10000)
    base_ra = 24.2354
    base_dec = 9.5631
    epoch_ref = 2016.0
    pmra = 1230.0
    pmdec = -430.0
    plx = 163.0
    missions = [("CFHT WIRCam", "2010"), ("UKIRT WFCAM", "2015"), ("Gaia", "DR3"), ("JWST", "2023")]
    epochs = np.sort(rng.uniform(2008.0, 2025.3, 90))
    rows = []
    for index, epoch in enumerate(epochs):
        mission_name, release = missions[index % len(missions)]
        dra_mas = pmra * (epoch - epoch_ref) + rng.normal(0, 18)
        ddec_mas = pmdec * (epoch - epoch_ref) + rng.normal(0, 14)
        ra = base_ra + dra_mas / (math.cos(math.radians(base_dec)) * 3600 * 1000)
        dec = base_dec + ddec_mas / (3600 * 1000)
        calibrated = index % 5 != 0
        rows.append({
            "id": index + 1,
            "ra": round(ra, 9),
            "dec": round(dec, 9),
            "raw_ra": round(ra - (0.008 if calibrated else 0.0) / (math.cos(math.radians(base_dec)) * 3600 * 1000), 9),
            "raw_dec": round(dec + (0.006 if calibrated else 0.0) / (3600 * 1000), 9),
            "measurement_epoch_yr": round(float(epoch), 6),
            "single_epoch": 1,
            "ra_unc_mas": round(float(rng.uniform(8, 32)), 3),
            "dec_unc_mas": round(float(rng.uniform(8, 32)), 3),
            "measurement_epoch_yr_unc": 0.0,
            "mission": f"{mission_name} {release}",
            "moca_pid": "mock",
            "mission_name": mission_name,
            "data_release": release,
            "origin": "mock_astrometry",
            "comments": "Synthetic astrometry for local smoke testing",
            "airmass": None,
            "moca_psid": None,
            "calibration_delta_ra_mas": 0.008 if calibrated else None,
            "calibration_delta_dec_mas": -0.006 if calibrated else None,
            "nstars_calibration": int(rng.integers(20, 180)) if calibrated else None,
            "calibration_method": "mock recalibration" if calibrated else None,
            "include_in_recalibrated_display": 1 if "Gaia" in mission_name else 0,
        })
    if include_merged:
        for merged_index, epoch in enumerate(np.linspace(2011.5, 2023.5, 10)):
            moca_pid = "mock_merged_pub_a" if merged_index < 5 else "mock_merged_pub_b"
            dra_mas = pmra * (epoch - epoch_ref) + rng.normal(0, 10)
            ddec_mas = pmdec * (epoch - epoch_ref) + rng.normal(0, 10)
            ra = base_ra + dra_mas / (math.cos(math.radians(base_dec)) * 3600 * 1000)
            dec = base_dec + ddec_mas / (3600 * 1000)
            rows.append({
                "id": f"merged-{merged_index + 1}",
                "ra": round(ra, 9),
                "dec": round(dec, 9),
                "raw_ra": round(ra, 9),
                "raw_dec": round(dec, 9),
                "measurement_epoch_yr": round(float(epoch), 6),
                "single_epoch": 0,
                "ra_unc_mas": round(float(rng.uniform(12, 28)), 3),
                "dec_unc_mas": round(float(rng.uniform(12, 28)), 3),
                "measurement_epoch_yr_unc": 0.0,
                "mission": moca_pid,
                "moca_pid": moca_pid,
                "mission_name": None,
                "data_release": None,
                "origin": "mock_merged_astrometry",
                "comments": "Synthetic merged astrometry for local smoke testing",
                "airmass": None,
                "moca_psid": None,
                "calibration_delta_ra_mas": None,
                "calibration_delta_dec_mas": None,
                "nstars_calibration": None,
                "calibration_method": None,
                "include_in_recalibrated_display": 0,
            })
    mission_counts: dict[str, int] = {}
    for row in rows:
        mission_counts[row["mission"]] = mission_counts.get(row["mission"], 0) + 1
    return {
        "target": {
            "moca_oid": int(oid),
            "designation": "SIMP J013656.5+093347.3" if int(oid) == 602 else "Mock high-motion dwarf",
            "designations": ["SIMP J013656.5+093347.3", "2MASS J01365662+0933473"],
        },
        "reference": {
            "id": 1,
            "ra": base_ra,
            "dec": base_dec,
            "ra_unc_mas": 8.0,
            "dec_unc_mas": 9.0,
            "measurement_epoch_yr": epoch_ref,
            "adopt_as_reference": 1,
            "bibcode": "2026Mock....1A",
            "publication_bibcode": "2026Mock....1A",
            "publication_name": "Mock Reference Coordinates et al. (2026)",
            "moca_pid": "mock",
            "mission_name": "Mock Reference Survey",
            "data_release": "DR1",
            "origin": "mock_astrometry",
            "comments": "Synthetic adopted reference astrometry for local smoke testing",
        },
        "pm": {
            "pmra_masyr": pmra,
            "pmdec_masyr": pmdec,
            "pmra_masyr_unc": 4.0,
            "pmdec_masyr_unc": 5.0,
            "publication_name": "Mock Proper Motion et al. (2026)",
            "publication_bibcode": "2026Mock....2B",
            "moca_pid": "mock_pm",
            "reference": "Mock adopted PM",
        },
        "parallax": {
            "parallax_mas": plx,
            "parallax_mas_unc": 3.0,
            "publication_name": "Mock Parallax et al. (2026)",
            "publication_bibcode": "2026Mock....3C",
            "moca_pid": "mock_plx",
            "reference": "Mock adopted parallax",
        },
        "missions": [
            {"value": mission, "label": f"{mission} ({count})", "count": count}
            for mission, count in sorted(mission_counts.items())
        ],
        "rows": rows,
        "meta": {
            "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
            "row_count": len(rows),
            "mission_count": len(mission_counts),
            "private_db": False,
            "include_merged_astrometry": include_merged,
        },
        "cache": {"hit": False, "ttl_seconds": 0},
    }


def _legacy_rv_dataset_value(target_name: Any, template_name: Any, pipeline_version: Any) -> str:
    return "|".join(str(value or "") for value in (target_name, template_name, pipeline_version))


def _legacy_rv_dataset_selection(args: dict[str, Any]) -> tuple[str, str, str] | None:
    target_name = args.get("target_name") or args.get("target")
    template_name = args.get("template_name") or args.get("template")
    pipeline_version = args.get("pipeline_version") or args.get("version")
    if target_name and template_name and pipeline_version:
        return str(target_name), str(template_name), str(pipeline_version)

    raw_dataset = args.get("dataset") or args.get("rv_dataset")
    if not raw_dataset:
        return None
    parts = str(raw_dataset).split("|", 2)
    if len(parts) != 3 or not all(parts):
        return None
    return parts[0], parts[1], parts[2]


def _legacy_rv_cache_key(args: dict[str, Any], *parts: Any) -> str:
    return "|".join([_spt_db_cache_key(args), "legacy-radial-velocities", *[str(part) for part in parts]])


def _legacy_rv_option_from_row(row: dict[str, Any]) -> dict[str, Any]:
    value = _legacy_rv_dataset_value(row.get("target_name"), row.get("template_name"), row.get("pipeline_version"))
    count = row.get("row_count")
    suffix = f" ({count} segments)" if count is not None else ""
    return {
        "value": value,
        "label": f"{value}{suffix}",
        "target_name": row.get("target_name"),
        "template_name": row.get("template_name"),
        "pipeline_version": row.get("pipeline_version"),
        "row_count": count,
        "moca_oid": row.get("moca_oid"),
        "moca_specid": row.get("moca_specid"),
        "moca_instid": row.get("moca_instid"),
    }


def _mock_legacy_rv_options() -> dict[str, Any]:
    rows = [
        {
            "target_name": "target_13510",
            "template_name": "sonora_mock_template_a.fits",
            "pipeline_version": "legacy_mock_v1",
            "row_count": 42,
            "moca_oid": 602,
            "moca_specid": 13510,
            "moca_instid": "spex_irtf",
        },
        {
            "target_name": "target_450",
            "template_name": "sonora_mock_template_b.fits",
            "pipeline_version": "legacy_mock_v2",
            "row_count": 36,
            "moca_oid": 10995,
            "moca_specid": 450,
            "moca_instid": "nires_keck",
        },
    ]
    options = [_legacy_rv_option_from_row(row) for row in rows]
    return {
        "options": options,
        "value": options[0]["value"],
        "meta": {
            "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
            "dataset_count": len(options),
        },
        "cache": {"hit": False, "ttl_seconds": 0},
    }


def _mock_legacy_rv_payload(args: dict[str, Any]) -> dict[str, Any]:
    selection = _legacy_rv_dataset_selection(args) or ("target_13510", "sonora_mock_template_a.fits", "legacy_mock_v1")
    target_name, template_name, pipeline_version = selection
    seed = int(hashlib.sha1(_legacy_rv_dataset_value(*selection).encode("utf-8")).hexdigest()[:8], 16)
    rng = np.random.default_rng(seed)
    instid = "spex_irtf" if "13510" in target_name else "nires_keck"
    specid = 13510 if "13510" in target_name else 450
    oid = 602 if specid == 13510 else 10995
    n_rows = 42 if specid == 13510 else 36
    base_rv = -18.4 if specid == 13510 else 12.7
    rows: list[dict[str, Any]] = []
    for index in range(n_rows):
        wave_min = 0.86 + 0.034 * index
        wave_max = wave_min + 0.045
        rv_unc = float(rng.uniform(0.55, 2.2))
        data_contrast = float(rng.uniform(0.018, 0.09))
        model_contrast = float(rng.uniform(0.14, 0.42))
        lsf = float(rng.normal(1.12, 0.08))
        if index in {6, 24}:
            data_contrast = 0.004
        if index in {14}:
            model_contrast = 0.045
        if index in {31}:
            lsf = 1.72
        if index in {38} and n_rows > 40:
            rv_unc = 0.0
        rows.append({
            "id": 900000 + index,
            "moca_oid": oid,
            "moca_instid": instid,
            "moca_specid": specid,
            "moca_fsid": 9100 + index,
            "pipeline_version": pipeline_version,
            "target_name": target_name,
            "template_name": template_name,
            "berv_kms": 18.233,
            "berv_kms_unc": 0.013,
            "order_number": 1 + index // 7,
            "window_number": 1 + (index // 2) % 4,
            "segment_number": index + 1,
            "wave_min": round(wave_min, 5),
            "wave_max": round(wave_max, 5),
            "segment_wavelength": round((wave_min + wave_max) / 2, 5),
            "nwindows": 7,
            "nsegments": n_rows,
            "npoints": int(rng.integers(45, 140)),
            "radial_velocity_kms": round(base_rv + 1.3 * math.sin(index / 4.7) + float(rng.normal(0, rv_unc * 0.55)), 4),
            "radial_velocity_kms_unc": round(rv_unc, 4),
            "origin": "mock_mcmc_rv_pipeline",
            "blaze0": round(float(rng.normal(-0.03, 0.08)), 4),
            "blaze0_unc": round(float(rng.uniform(0.01, 0.05)), 4),
            "blaze1": round(float(rng.normal(0.02, 0.08)), 4),
            "blaze1_unc": round(float(rng.uniform(0.01, 0.05)), 4),
            "vsini_kms": round(float(rng.uniform(4, 32)), 4),
            "vsini_kms_unc": round(float(rng.uniform(0.4, 3.4)), 4),
            "lsf": round(lsf, 4),
            "lsf_unc": round(float(rng.uniform(0.01, 0.07)), 4),
            "best_chi2": round(float(rng.uniform(0.8, 2.4)), 4),
            "lnp_avg": round(float(rng.normal(-1240, 40)), 4),
            "lnp_mad": round(float(rng.uniform(4, 18)), 4),
            "lnp_std": round(float(rng.uniform(8, 28)), 4),
            "lnp_median": round(float(rng.normal(-1235, 40)), 4),
            "lnp_max": round(float(rng.normal(-1210, 35)), 4),
            "mean_acceptance_rate": round(float(rng.uniform(0.14, 0.42)), 5),
            "mean_finite_fraction": round(float(rng.uniform(0.91, 1.0)), 5),
            "mean_outofbounds_fraction": round(float(rng.uniform(0.0, 0.07)), 5),
            "parscale_rv": 25.0,
            "rv_min_bound": -150.0,
            "rv_max_bound": 150.0,
            "niter_mcmc": 8000,
            "nburnin_mcmc": 2000,
            "nchains_mcmc": 24,
            "model_contrast": round(model_contrast, 5),
            "nmodel_10p_contrast": int(rng.integers(18, 95)),
            "data_contrast": round(data_contrast, 5),
            "model_fit_url": "",
            "ignored": 0,
            "comments": "Synthetic legacy RV row for local smoke testing",
        })
    dataset_info = _legacy_rv_dataset_info(rows[0] if rows else {})
    return {
        "selection": {
            "dataset": _legacy_rv_dataset_value(*selection),
            "target_name": target_name,
            "template_name": template_name,
            "pipeline_version": pipeline_version,
        },
        "datasetInfo": dataset_info,
        "rows": rows,
        "images": {"chi2_url": "", "best_model_fit_url": ""},
        "meta": {
            "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
            "row_count": len(rows),
            "private_db": _is_private_db(args),
        },
        "cache": {"hit": False, "ttl_seconds": 0},
    }


def _load_legacy_rv_options_from_db(args: dict[str, Any]) -> dict[str, Any]:
    cache_key = _legacy_rv_cache_key(args, "options")
    now = time.time()
    cached = _LEGACY_RV_CACHE.get(cache_key)
    if cached and now - cached[0] < CACHE_SECONDS:
        payload = copy.deepcopy(cached[1])
        payload["cache"] = {"hit": True, "ttl_seconds": CACHE_SECONDS}
        return payload

    engine = _engine(_connection_string(args))
    with engine.connect() as conn:
        rows = _records(_read_sql(conn, """
            SELECT
                target_name,
                template_name,
                pipeline_version,
                COUNT(*) AS row_count,
                MIN(moca_oid) AS moca_oid,
                MIN(moca_specid) AS moca_specid,
                MIN(moca_instid) AS moca_instid
            FROM pcat_mcmc_rv_pipeline
            WHERE target_name IS NOT NULL
                AND template_name IS NOT NULL
                AND pipeline_version IS NOT NULL
                AND LOWER(CONCAT_WS('|', target_name, template_name, pipeline_version)) NOT LIKE '%spirou%'
            GROUP BY target_name, template_name, pipeline_version
            ORDER BY target_name, template_name, pipeline_version
        """))
    options = [_legacy_rv_option_from_row(row) for row in rows]
    payload = {
        "options": options,
        "value": options[0]["value"] if options else None,
        "meta": {
            "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
            "dataset_count": len(options),
            "private_db": _is_private_db(args),
        },
        "cache": {"hit": False, "ttl_seconds": CACHE_SECONDS},
    }
    _LEGACY_RV_CACHE[cache_key] = (now, copy.deepcopy(payload))
    return payload


def _legacy_rv_dataset_info(first_row: dict[str, Any]) -> dict[str, Any]:
    keys = [
        "pipeline_version",
        "target_name",
        "template_name",
        "moca_oid",
        "moca_specid",
        "moca_instid",
        "berv_kms",
        "berv_kms_unc",
        "nwindows",
        "nsegments",
        "npoints",
        "origin",
        "parscale_rv",
        "rv_min_bound",
        "rv_max_bound",
        "niter_mcmc",
        "nburnin_mcmc",
        "nchains_mcmc",
    ]
    return {key: first_row.get(key) for key in keys if first_row.get(key) is not None}


def _legacy_rv_specid_from_selection(target_name: str, rows: list[dict[str, Any]]) -> int | None:
    for row in rows:
        try:
            if row.get("moca_specid") is not None:
                return int(row["moca_specid"])
        except (TypeError, ValueError):
            pass
    parts = str(target_name or "").split("_")
    for part in parts:
        if part.isdigit():
            return int(part)
    return None


def _legacy_rv_model_grid_images(conn, specid: int | None, template_name: str) -> dict[str, str]:
    if specid is None or not template_name:
        return {"chi2_url": "", "best_model_fit_url": ""}
    rows = _records(_read_sql(conn, """
        SELECT
            mfs.description,
            MIN(mf.url) AS url
        FROM calc_model_grid_fits cmgf
        JOIN data_model_grid_files dmgf
            ON dmgf.moca_mgridfileid = cmgf.moca_mgridfileid
        JOIN mechanics_file_sets mfs
            ON mfs.moca_fsid = cmgf.moca_fsid
        JOIN mechanics_files mf
            ON mf.moca_fid = mfs.moca_fid
        WHERE cmgf.moca_specid = :specid
            AND CONCAT(cmgf.moca_mgridid, '_', dmgf.file_name) = :template_name
            AND (mfs.description = 'All model fit chi2' OR mfs.description = 'Best model fit')
        GROUP BY mfs.description
    """, {"specid": int(specid), "template_name": template_name}))
    by_description = {str(row.get("description") or ""): str(row.get("url") or "") for row in rows}
    return {
        "chi2_url": by_description.get("All model fit chi2", ""),
        "best_model_fit_url": by_description.get("Best model fit", ""),
    }


def _load_legacy_rv_dataset_from_db(args: dict[str, Any]) -> dict[str, Any]:
    selection = _legacy_rv_dataset_selection(args)
    if selection is None:
        options_payload = _load_legacy_rv_options_from_db(args)
        default_value = options_payload.get("value")
        if default_value:
            selection = _legacy_rv_dataset_selection({"dataset": default_value})
    if selection is None:
        return {
            "selection": {},
            "datasetInfo": {},
            "rows": [],
            "images": {"chi2_url": "", "best_model_fit_url": ""},
            "meta": {
                "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
                "row_count": 0,
                "private_db": _is_private_db(args),
            },
            "cache": {"hit": False, "ttl_seconds": CACHE_SECONDS},
        }

    target_name, template_name, pipeline_version = selection
    dataset_value = _legacy_rv_dataset_value(target_name, template_name, pipeline_version)
    cache_key = _legacy_rv_cache_key(args, "data", hashlib.sha1(dataset_value.encode("utf-8")).hexdigest())
    now = time.time()
    cached = _LEGACY_RV_CACHE.get(cache_key)
    if cached and now - cached[0] < CACHE_SECONDS:
        payload = copy.deepcopy(cached[1])
        payload["cache"] = {"hit": True, "ttl_seconds": CACHE_SECONDS}
        return payload

    engine = _engine(_connection_string(args))
    with engine.connect() as conn:
        rows = _records(_read_sql(conn, """
            SELECT
                rv.id,
                rv.moca_oid,
                rv.moca_instid,
                rv.moca_specid,
                rv.moca_fsid,
                rv.pipeline_version,
                rv.target_name,
                rv.template_name,
                rv.berv_kms,
                rv.berv_kms_unc,
                rv.order_number,
                rv.window_number,
                rv.segment_number,
                rv.wave_min,
                rv.wave_max,
                ((rv.wave_min + rv.wave_max) / 2.0) AS segment_wavelength,
                rv.nwindows,
                rv.nsegments,
                rv.npoints,
                rv.radial_velocity_kms,
                rv.radial_velocity_kms_unc,
                rv.origin,
                rv.blaze0,
                rv.blaze0_unc,
                rv.blaze1,
                rv.blaze1_unc,
                rv.vsini_kms,
                rv.vsini_kms_unc,
                rv.lsf,
                rv.lsf_unc,
                rv.best_chi2,
                rv.lnp_avg,
                rv.lnp_mad,
                rv.lnp_std,
                rv.lnp_median,
                rv.lnp_max,
                rv.mean_acceptance_rate,
                rv.mean_finite_fraction,
                rv.mean_outofbounds_fraction,
                rv.parscale_rv,
                rv.rv_min_bound,
                rv.rv_max_bound,
                rv.niter_mcmc,
                rv.nburnin_mcmc,
                rv.nchains_mcmc,
                rv.model_contrast,
                rv.nmodel_10p_contrast,
                rv.data_contrast,
                rv.ignored,
                rv.comments,
                fit.model_fit_url
            FROM pcat_mcmc_rv_pipeline rv
            LEFT JOIN (
                SELECT
                    mfs.moca_fsid,
                    MIN(mf.url) AS model_fit_url
                FROM mechanics_file_sets mfs
                JOIN mechanics_files mf
                    ON mf.moca_fid = mfs.moca_fid
                WHERE mfs.description = 'MCMC RV model fit'
                GROUP BY mfs.moca_fsid
            ) fit
                ON fit.moca_fsid = rv.moca_fsid
            WHERE rv.target_name = :target_name
                AND rv.template_name = :template_name
                AND rv.pipeline_version = :pipeline_version
            ORDER BY rv.order_number, rv.window_number, rv.segment_number, rv.id
        """, {
            "target_name": target_name,
            "template_name": template_name,
            "pipeline_version": pipeline_version,
        }))
        specid = _legacy_rv_specid_from_selection(target_name, rows)
        images = _legacy_rv_model_grid_images(conn, specid, template_name)

    dataset_info = _legacy_rv_dataset_info(rows[0] if rows else {
        "target_name": target_name,
        "template_name": template_name,
        "pipeline_version": pipeline_version,
    })
    payload = {
        "selection": {
            "dataset": dataset_value,
            "target_name": target_name,
            "template_name": template_name,
            "pipeline_version": pipeline_version,
        },
        "datasetInfo": dataset_info,
        "rows": rows,
        "images": images,
        "meta": {
            "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
            "row_count": len(rows),
            "private_db": _is_private_db(args),
        },
        "cache": {"hit": False, "ttl_seconds": CACHE_SECONDS},
    }
    _LEGACY_RV_CACHE[cache_key] = (now, copy.deepcopy(payload))
    return payload


