def _mock_retrieval_condensation_curves() -> list[dict[str, Any]]:
    log_pressures = np.linspace(-6.0, 3.0, 19)
    h2o_temperatures = [
        158.19, 163.05, 168.22, 173.73, 179.60, 185.87, 192.59,
        199.81, 207.59, 215.99, 225.10, 235.00, 245.81, 257.67,
        270.73, 286.98, 306.03, 328.21, 354.41,
    ]
    specs = [
        {
            "moca_ccurveid": "FE_METAL_VISSCHER2010_SOLAR",
            "moca_condid": "fe_metal",
            "moca_ccsetid": "visscher2010_solar_analytic",
            "curve_label": "Fe metal condensation",
            "condensate_name": "Iron metal",
            "condensate_formula": "Fe",
            "mineral_name": "iron",
            "phase_label": "metal_solid",
            "source_equation_label": "Visscher2010 Eq.2",
            "source_bibcode": "2010ApJ...716.1060V",
            "temperatures": [float(10000.0 / (5.44 - 0.48 * float(logp))) for logp in log_pressures],
        },
        {
            "moca_ccurveid": "FORSTERITE_MG2SIO4_VISSCHER2010_SOLAR",
            "moca_condid": "forsterite_mg2sio4",
            "moca_ccsetid": "visscher2010_solar_analytic",
            "curve_label": "Forsterite Mg2SiO4 condensation",
            "condensate_name": "Forsterite",
            "condensate_formula": "Mg2SiO4",
            "mineral_name": "forsterite",
            "phase_label": "solid",
            "source_equation_label": "Visscher2010 Eq.18",
            "source_bibcode": "2010ApJ...716.1060V",
            "temperatures": [float(10000.0 / (5.89 - 0.37 * float(logp))) for logp in log_pressures],
        },
        {
            "moca_ccurveid": "ENSTATITE_MGSIO3_VISSCHER2010_SOLAR",
            "moca_condid": "enstatite_mgsio3",
            "moca_ccsetid": "visscher2010_solar_analytic",
            "curve_label": "Enstatite MgSiO3 condensation",
            "condensate_name": "Enstatite",
            "condensate_formula": "MgSiO3",
            "mineral_name": "enstatite",
            "phase_label": "solid",
            "source_equation_label": "Visscher2010 Eq.20",
            "source_bibcode": "2010ApJ...716.1060V",
            "temperatures": [float(10000.0 / (6.26 - 0.35 * float(logp))) for logp in log_pressures],
        },
        {
            "moca_ccurveid": "H2O_ICE_LIQUID_MURPHYKOOP2005_XH2O5E4",
            "moca_condid": "h2o_ice_liquid",
            "moca_ccsetid": "h2o_murphykoop2005_xh2o5e4_starter",
            "curve_label": "H2O ice/liquid condensation starter",
            "condensate_name": "Water",
            "condensate_formula": "H2O",
            "mineral_name": None,
            "phase_label": "ice_or_liquid",
            "source_equation_label": "MurphyKoop2005",
            "source_bibcode": "2005QJRMS.131.1539M",
            "temperatures": h2o_temperatures,
        },
    ]
    curves: list[dict[str, Any]] = []
    for spec in specs:
        temperatures = spec.pop("temperatures")
        points = [
            {
                "source_point_index": index,
                "pressure_bar": float(10.0 ** float(log_pressure)),
                "log10_pressure_bar": float(log_pressure),
                "temperature_k": float(temperature),
                "point_source_kind": "mock_starter_curve",
            }
            for index, (log_pressure, temperature) in enumerate(zip(log_pressures, temperatures, strict=False), start=1)
        ]
        curves.append({
            **spec,
            "curve_status": "active",
            "transition_label": "gas_to_condensed",
            "pressure_unit": "bar",
            "temperature_unit": "K",
            "points": points,
        })
    return curves


def _mock_retrieval_payload(args: dict[str, Any], atmosphere_id: int) -> dict[str, Any]:
    pressures = np.geomspace(1e-4, 200.0, 72)
    logp = np.log10(pressures)
    temp = 920 + 235 * (logp + 1.8) ** 2 / 5.8 + 80 * np.sin((logp + 4.0) * 1.35)
    temp = np.clip(temp, 760, 1760)
    profiles = []
    for index, (pressure, log_pressure, value) in enumerate(zip(pressures, logp, temp, strict=False)):
        spread = 38 + 11 * abs(math.sin(index / 7))
        profiles.append({
            "layer_index": index,
            "profile_axis_index": 0,
            "pressure_bar": float(pressure),
            "log10_pressure_bar": float(log_pressure),
            "pressure_role": "layer_midpoint",
            "moca_atpqid": "TEMP_K",
            "quantity_name": "Temperature",
            "quantity_kind": "temperature",
            "value": float(value),
            "value_p16": float(value - spread),
            "value_p50": float(value),
            "value_p84": float(value + spread),
            "value_unit": "K",
        })

    species_specs = [
        ("H2O", 0.12, -1.2, "#364bff"),
        ("CH4", 0.22, -0.15, "#b04a4a"),
        ("CO", 0.55, 0.45, "#ef5350"),
        ("CO2", 1.05, -0.65, "#4d9221"),
        ("K", 1.25, -3.2, "#e0b400"),
        ("FeH", 1.55, -2.4, "#3f948c"),
    ]
    contribution_rows = []
    for axis_index, (species, wavelength, peak_logp, _color) in enumerate(species_specs, start=1):
        for index, (pressure, log_pressure) in enumerate(zip(pressures, logp, strict=False)):
            value = math.exp(-0.5 * ((float(log_pressure) - peak_logp) / 0.42) ** 2)
            contribution_rows.append({
                "layer_index": index,
                "profile_axis_index": axis_index,
                "pressure_bar": float(pressure),
                "log10_pressure_bar": float(log_pressure),
                "pressure_role": "layer_midpoint",
                "moca_atpqid": "CONTRIB_FUNC",
                "quantity_name": "Contribution function",
                "quantity_kind": "contribution_function",
                "spectral_region_label": f"{species} {wavelength:.2f}um",
                "wavelength_um": wavelength,
                "component_kind": "species",
                "component_label": species,
                "species_formula": species,
                "value": float(value),
                "value_unit": "normalized",
            })

    cloud_parameters = [
        {
            "moca_atparid": "CLOUD_TOP_PRESSURE_BAR",
            "parameter_name": "Cloud top pressure",
            "parameter_kind": "cloud",
            "component_kind": "cloud",
            "component_label": "Mg2SiO4 slab",
            "species_formula": "Mg2SiO4",
            "pressure_bar": 0.08,
            "value": 0.08,
            "value_p16": 0.05,
            "value_p84": 0.13,
            "value_unit": "bar",
        },
        {
            "moca_atparid": "CLOUD_BASE_PRESSURE_BAR",
            "parameter_name": "Cloud base pressure",
            "parameter_kind": "cloud",
            "component_kind": "cloud",
            "component_label": "Mg2SiO4 slab",
            "species_formula": "Mg2SiO4",
            "pressure_bar": 1.6,
            "value": 1.6,
            "value_p16": 1.0,
            "value_p84": 2.4,
            "value_unit": "bar",
        },
        {
            "moca_atparid": "CLOUD_COVERING_FRACTION",
            "parameter_name": "Cloud covering fraction",
            "parameter_kind": "cloud",
            "component_kind": "cloud",
            "component_label": "patchy component",
            "species_formula": "Mg2SiO4",
            "value": 0.42,
            "value_p16": 0.34,
            "value_p84": 0.51,
            "value_unit": "dimensionless",
        },
    ]
    scalar_parameters = [
        *cloud_parameters,
        {"moca_atparid": "MASS_MJUP", "parameter_name": "Mass", "parameter_kind": "derived_atmosphere", "value": 14.6, "value_p16": 10.8, "value_p84": 19.1, "value_unit": "Mjup"},
        {"moca_atparid": "RADIUS_RJUP", "parameter_name": "Radius", "parameter_kind": "derived_atmosphere", "value": 1.09, "value_p16": 1.02, "value_p84": 1.16, "value_unit": "Rjup"},
        {"moca_atparid": "LOGG_CGS", "parameter_name": "Surface gravity", "parameter_kind": "derived_atmosphere", "value": 4.55, "value_p16": 4.33, "value_p84": 4.78, "value_unit": "dex(cgs)"},
        {"moca_atparid": "RCB_PRESSURE_BAR", "parameter_name": "Radiative-convective boundary pressure", "parameter_kind": "thermal_parameterization", "value": 32.0, "value_p16": 19.0, "value_p84": 55.0, "value_unit": "bar"},
        {"moca_atparid": "LOG_EVIDENCE", "parameter_name": "Log evidence", "parameter_kind": "evidence", "value": -1284.6, "value_unit": "dimensionless"},
    ]
    abundance_rows = [
        ("log10(f_H2O)", "molecular_vmr", -3.35, 0.18),
        ("log10(f_CH4)", "molecular_vmr", -3.58, 0.17),
        ("log10(f_CO)", "molecular_vmr", -4.25, 0.32),
        ("log10(f_CO2)", "molecular_vmr", -6.02, 0.45),
        ("log10(f_NH3)", "molecular_vmr", -4.78, 0.21),
        ("log10(f_K)", "molecular_vmr", -7.12, 0.35),
        ("C/O_gas", "elemental_ratio", 0.61, 0.07),
        ("[M/H]_gas", "bulk_metallicity", 0.18, 0.16),
    ]
    abundances = [
        {
            "id": index + 1,
            "moca_oid": 602,
            "moca_pid": "Nase25",
            "bibcode": "2025A&A...702A...1N",
            "abundance_type": abundance_type,
            "abundance_label": abundance_type,
            "quantity_kind": quantity_kind,
            "feh_val": value,
            "feh_unc": uncertainty,
            "feh_unc_pos": uncertainty,
            "feh_unc_neg": uncertainty,
            "same_publication": 1,
            "same_calculation_method": 1,
        }
        for index, (abundance_type, quantity_kind, value, uncertainty) in enumerate(abundance_rows)
    ]
    comparison = []
    rng = np.random.default_rng(602)
    for row in abundances:
        for offset in range(18):
            scatter = 0.11 if row["quantity_kind"] != "molecular_vmr" else 0.28
            comparison.append({
                "moca_oid": 370000 + offset,
                "designation": f"Mock comparison {offset + 1}",
                "moca_pid": "comparison",
                "bibcode": "comparison",
                "abundance_type": row["abundance_type"],
                "quantity_kind": row["quantity_kind"],
                "feh_val": float(row["feh_val"] + rng.normal(0, scatter)),
                "feh_unc": row["feh_unc"],
                "selected_object": 0,
            })
        comparison.append({**row, "selected_object": 1})

    wavelengths = np.linspace(0.9, 5.1, 180)
    best = 1410 + 190 * np.sin(wavelengths * 2.15) + 95 * np.sin(wavelengths * 5.2)
    observed = best + 42 * np.sin(wavelengths * 9.1)
    spectrum_components = []
    for species, center, _peak_logp, color in species_specs:
        absorption = 85 * np.exp(-0.5 * ((wavelengths - center) / 0.17) ** 2)
        spectrum_components.append({
            "label": species,
            "color": color,
            "wavelength_um": [float(value) for value in wavelengths],
            "brightness_temperature_k": [float(value) for value in best + absorption],
        })

    sample_count = 900
    means = np.array([1150.0, 4.55, 0.18, 0.61])
    scales = np.array([42.0, 0.18, 0.16, 0.07])
    cov = np.diag(scales**2)
    cov[1, 2] = cov[2, 1] = -0.45 * scales[1] * scales[2]
    cov[2, 3] = cov[3, 2] = 0.28 * scales[2] * scales[3]
    samples = rng.multivariate_normal(means, cov, size=sample_count)
    posterior_params = ["Teff_K", "logg", "[M/H]_gas", "C/O_gas"]
    posterior_samples = [
        {posterior_params[index]: float(value) for index, value in enumerate(row)}
        for row in samples
    ]
    condensation_curves = _mock_retrieval_condensation_curves()
    atmosphere = {
        "id": int(atmosphere_id),
        "atmosphere_structure_id": int(atmosphere_id),
        "moca_oid": 602,
        "designation": "SIMP J013656.5+093347.3",
        "moca_pid": "Nase25",
        "bibcode": "2025A&A...702A...1N",
        "publication_name": "Nasedkin et al. 2025",
        "publication_bibcode": "2025A&A...702A...1N",
        "structure_kind": "phase_resolved_retrieval",
        "retrieval_code": "petitRADTRANS retrieval",
        "retrieval_model": "full-rotation fiducial retrieval",
        "profile_parameterization": "gradient-parameterized T/P profile",
        "chemistry_assumption": "hybrid pressure-dependent CH4/CO and uniform gases",
        "cloud_assumption": "patchy Mg2SiO4 and Fe clouds",
        "pressure_unit": "bar",
        "n_pressure_points": len(profiles),
    }
    return {
        "selection": {"atmosphere_structure_id": int(atmosphere_id)},
        "atmosphere": atmosphere,
        "siblingAtmospheres": _mock_retrieval_search(args)["options"],
        "profiles": profiles,
        "profileRows": [*profiles, *contribution_rows],
        "cloudParameters": cloud_parameters,
        "scalarParameters": scalar_parameters,
        "condensationCurves": condensation_curves,
        "abundances": abundances,
        "comparisonAbundances": comparison,
        "solarReferences": [
            {"abundance_type": "[M/H]_gas", "value": 0.0, "label": "solar [M/H]"},
            {"abundance_type": "[M/H]_bulk", "value": 0.0, "label": "solar [M/H]"},
            {"abundance_type": "C/O_gas", "value": 0.55, "label": "solar C/O"},
            {"abundance_type": "C/O_bulk", "value": 0.55, "label": "solar C/O"},
        ],
        "contributionFunctions": contribution_rows,
        "retrievedSpectrum": {
            "available": True,
            "kind": "mock_brightness_temperature",
            "wavelength_um": [float(value) for value in wavelengths],
            "observed_brightness_temperature_k": [float(value) for value in observed],
            "best_fit_brightness_temperature_k": [float(value) for value in best],
            "components": spectrum_components,
        },
        "posterior": {
            "available": True,
            "parameters": posterior_params,
            "samples": posterior_samples,
        },
        "meta": {
            "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
            "private_db": True,
            "mock": True,
            "profile_count": len(profiles),
            "contribution_count": len(contribution_rows),
            "scalar_parameter_count": len(scalar_parameters),
            "cloud_parameter_count": len(cloud_parameters),
            "condensation_curve_count": len(condensation_curves),
            "condensation_curve_point_count": sum(len(curve.get("points") or []) for curve in condensation_curves),
            "abundance_count": len(abundances),
            "comparison_abundance_count": len(comparison),
        },
        "cache": {"hit": False, "ttl_seconds": 0},
    }


def _load_retrieval_search_from_db(args: dict[str, Any]) -> dict[str, Any]:
    query = str(args.get("q") or args.get("search") or "").strip()
    selected_id = _retrieval_int_arg(args, "id", "atmosphere_id", "atmosphere_structure_id", "retrieval_id")
    selected_oid = _retrieval_int_arg(args, "moca_oid", "oid")
    include_ignored = _as_bool(args.get("include_ignored") or args.get("show_ignored"))
    limit = min(max(_retrieval_int_arg(args, "limit", "max_rows") or 80, 1), 250)
    cache_key = _retrieval_cache_key(args, "search", query, selected_id or "", selected_oid or "", include_ignored, limit)
    now = time.time()
    cached = _RETRIEVAL_EXPLORER_CACHE.get(cache_key)
    if cached and now - cached[0] < CACHE_SECONDS:
        payload = copy.deepcopy(cached[1])
        payload["cache"] = {"hit": True, "ttl_seconds": CACHE_SECONDS}
        return payload

    engine = _engine(_connection_string(args))
    with engine.connect() as conn:
        missing = _retrieval_missing_tables(conn)
        if missing:
            return {
                "options": [],
                "value": selected_id,
                "meta": {
                    "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
                    "row_count": 0,
                    "missing_tables": missing,
                    "private_db": _is_private_db(args),
                },
                "cache": {"hit": False, "ttl_seconds": CACHE_SECONDS},
            }
        das_columns = _db_table_columns(conn, "data_atmosphere_structure")
        order_terms = [
            *_retrieval_adoption_order_terms("das", das_columns),
            "temperature_layer_count DESC",
            "contribution_layer_count DESC",
            "das.modified_timestamp DESC",
            "das.id DESC",
        ]
        clauses = []
        params: dict[str, Any] = {"limit": int(limit)}
        if not include_ignored:
            clauses.append("COALESCE(das.ignored, 0) = 0")
        if selected_id is not None:
            clauses.append("das.id = :selected_id")
            params["selected_id"] = int(selected_id)
        elif selected_oid is not None:
            clauses.append("das.moca_oid = :selected_oid")
            params["selected_oid"] = int(selected_oid)
        if query:
            clauses.append("""
                (
                    LOWER(COALESCE(mo.designation, das.object_designation, '')) LIKE :query
                    OR CAST(das.moca_oid AS CHAR) LIKE :query
                    OR CAST(das.id AS CHAR) LIKE :query
                    OR LOWER(COALESCE(das.moca_pid, '')) LIKE :query
                    OR LOWER(COALESCE(das.bibcode, mp.bibcode, '')) LIKE :query
                    OR LOWER(COALESCE(das.retrieval_code, '')) LIKE :query
                    OR LOWER(COALESCE(das.retrieval_model, '')) LIKE :query
                    OR LOWER(COALESCE(das.cloud_assumption, '')) LIKE :query
                )
            """)
            params["query"] = f"%{query.lower()}%"
        where_sql = " AND ".join(f"({clause})" for clause in clauses) if clauses else "1 = 1"
        rows = _records(_read_sql(conn, f"""
            SELECT
                das.id AS atmosphere_structure_id,
                das.id,
                das.moca_oid,
                mo.designation,
                das.moca_pid,
                COALESCE(das.bibcode, mp.bibcode) AS bibcode,
                das.moca_specid,
                das.structure_kind,
                das.time_bin_label,
                das.rotational_phase,
                das.longitude_deg,
                das.retrieval_code,
                das.retrieval_model,
                das.profile_parameterization,
                das.chemistry_assumption,
                das.cloud_assumption,
                das.n_pressure_points,
                das.ignored,
                das.adopted,
                das.is_public,
                (
                    SELECT COUNT(*)
                    FROM data_atmosphere_structure_layers l
                    WHERE l.atmosphere_structure_id = das.id
                ) AS layer_count,
                (
                    SELECT COUNT(*)
                    FROM data_atmosphere_structure_layers l
                    WHERE l.atmosphere_structure_id = das.id
                        AND l.moca_atpqid = 'TEMP_K'
                ) AS temperature_layer_count,
                (
                    SELECT COUNT(*)
                    FROM data_atmosphere_structure_layers l
                    WHERE l.atmosphere_structure_id = das.id
                        AND l.moca_atpqid = 'CONTRIB_FUNC'
                ) AS contribution_layer_count,
                (
                    SELECT COUNT(*)
                    FROM data_atmosphere_structure_parameters p
                    WHERE p.atmosphere_structure_id = das.id
                ) AS parameter_count,
                (
                    SELECT COUNT(*)
                    FROM data_atmosphere_structure_parameters p
                    JOIN moca_atmosphere_parameters ap
                        ON ap.moca_atparid = p.moca_atparid
                    WHERE p.atmosphere_structure_id = das.id
                        AND ap.parameter_kind = 'cloud'
                ) AS cloud_parameter_count,
                (
                    SELECT COUNT(*)
                    FROM data_object_metallicities dom
                    LEFT JOIN moca_abundances ma
                        ON ma.abundance_type = dom.abundance_type
                    WHERE dom.moca_oid = das.moca_oid
                        AND COALESCE(dom.ignored, 0) = 0
                        AND COALESCE(ma.quantity_kind, '') <> 'legacy'
                ) AS abundance_count
            FROM data_atmosphere_structure das
            LEFT JOIN moca_objects mo
                ON mo.moca_oid = das.moca_oid
            LEFT JOIN moca_publications mp
                ON mp.moca_pid = das.moca_pid
            WHERE {where_sql}
            ORDER BY {", ".join(order_terms)}
            LIMIT :limit
        """, params))
    options = _retrieval_search_rows_to_options(rows)
    payload = {
        "options": options,
        "value": int(selected_id) if selected_id is not None else (options[0]["value"] if options else None),
        "meta": {
            "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
            "row_count": len(options),
            "private_db": _is_private_db(args),
            "include_ignored": include_ignored,
        },
        "cache": {"hit": False, "ttl_seconds": CACHE_SECONDS},
    }
    _RETRIEVAL_EXPLORER_CACHE[cache_key] = (now, copy.deepcopy(payload))
    return payload


def _retrieval_select_column(alias: str, columns: set[str], column: str, output: str | None = None) -> str:
    out = output or column
    if column in columns:
        return f"{alias}.`{column}` AS `{out}`"
    return f"NULL AS `{out}`"


def _retrieval_adoption_order_terms(alias: str, columns: set[str]) -> list[str]:
    terms = []
    if "adopted" in columns:
        terms.append(f"COALESCE({alias}.`adopted`, 0) DESC")
    if "public_adopted" in columns:
        terms.append(f"COALESCE({alias}.`public_adopted`, 0) DESC")
    return terms


def _load_retrieval_condensation_curves_from_db(conn) -> list[dict[str, Any]]:
    if not all(_db_table_exists(conn, table) for table in RETRIEVAL_EXPLORER_CONDENSATION_TABLES):
        return []
    curve_cols = _db_table_columns(conn, "data_condensation_curves")
    point_cols = _db_table_columns(conn, "data_condensation_curve_points")
    condensate_cols = _db_table_columns(conn, "moca_condensates")
    set_cols = _db_table_columns(conn, "moca_condensation_curve_sets")
    if not {"id", "moca_ccurveid", "moca_condid", "moca_ccsetid"}.issubset(curve_cols):
        return []
    if not {"condensation_curve_id", "pressure_bar", "temperature_k"}.issubset(point_cols):
        return []
    if "moca_condid" not in condensate_cols or "moca_ccsetid" not in set_cols:
        return []

    select_terms = [
        "dcc.`id` AS `condensation_curve_id`",
        "dcc.`moca_ccurveid` AS `moca_ccurveid`",
        "dcc.`moca_condid` AS `moca_condid`",
        "dcc.`moca_ccsetid` AS `moca_ccsetid`",
        _retrieval_select_column("dcc", curve_cols, "curve_label"),
        _retrieval_select_column("dcc", curve_cols, "curve_status"),
        _retrieval_select_column("dcc", curve_cols, "transition_label"),
        _retrieval_select_column("dcc", curve_cols, "phase_label"),
        _retrieval_select_column("dcc", curve_cols, "source_equation_label"),
        _retrieval_select_column("dcc", curve_cols, "valid_log10_pressure_bar_min"),
        _retrieval_select_column("dcc", curve_cols, "valid_log10_pressure_bar_max"),
        _retrieval_select_column("dcc", curve_cols, "comments", "curve_comments"),
        _retrieval_select_column("mc", condensate_cols, "display_name", "condensate_name"),
        _retrieval_select_column("mc", condensate_cols, "condensate_formula"),
        _retrieval_select_column("mc", condensate_cols, "mineral_name"),
        _retrieval_select_column("mc", condensate_cols, "condensate_kind"),
        _retrieval_select_column("ccs", set_cols, "set_name"),
        _retrieval_select_column("ccs", set_cols, "source_bibcode", "set_source_bibcode"),
        _retrieval_select_column("ccs", set_cols, "source_doi"),
        _retrieval_select_column("ccs", set_cols, "source_url"),
        _retrieval_select_column("ccs", set_cols, "chemistry_assumption"),
        _retrieval_select_column("ccs", set_cols, "pressure_unit"),
        _retrieval_select_column("ccs", set_cols, "temperature_unit"),
        _retrieval_select_column("dccp", point_cols, "id", "condensation_curve_point_id"),
        _retrieval_select_column("dccp", point_cols, "source_point_index"),
        "dccp.`pressure_bar` AS `pressure_bar`",
        _retrieval_select_column("dccp", point_cols, "log10_pressure_bar"),
        "dccp.`temperature_k` AS `temperature_k`",
        _retrieval_select_column("dccp", point_cols, "point_source_kind"),
    ]
    ignored_clauses = []
    for alias, columns in (
        ("dcc", curve_cols),
        ("dccp", point_cols),
        ("mc", condensate_cols),
        ("ccs", set_cols),
    ):
        if "ignored" in columns:
            ignored_clauses.append(f"COALESCE({alias}.`ignored`, 0) = 0")
    where_sql = " AND ".join(ignored_clauses) if ignored_clauses else "1 = 1"
    order_terms = []
    if "curve_label" in curve_cols:
        order_terms.append("dcc.`curve_label`")
    order_terms.append("dcc.`moca_ccurveid`")
    if "source_point_index" in point_cols:
        order_terms.append("dccp.`source_point_index`")
    if "log10_pressure_bar" in point_cols:
        order_terms.append("dccp.`log10_pressure_bar`")
    order_terms.append("dccp.`pressure_bar`")
    try:
        rows = _records(_read_sql(conn, f"""
            SELECT
                {", ".join(select_terms)}
            FROM data_condensation_curves dcc
            JOIN moca_condensates mc
                ON mc.`moca_condid` = dcc.`moca_condid`
            JOIN moca_condensation_curve_sets ccs
                ON ccs.`moca_ccsetid` = dcc.`moca_ccsetid`
            JOIN data_condensation_curve_points dccp
                ON dccp.`condensation_curve_id` = dcc.`id`
            WHERE {where_sql}
            ORDER BY {", ".join(order_terms)}
        """))
    except Exception:
        return []

    grouped: dict[str, dict[str, Any]] = {}
    for row in rows:
        pressure = _retrieval_float_or_none(row.get("pressure_bar"))
        temperature = _retrieval_float_or_none(row.get("temperature_k"))
        if pressure is None or pressure <= 0 or temperature is None:
            continue
        curve_key = str(row.get("moca_ccurveid") or row.get("condensation_curve_id") or "").strip()
        if not curve_key:
            continue
        curve = grouped.get(curve_key)
        if curve is None:
            curve = {
                "condensation_curve_id": _retrieval_int_value(row.get("condensation_curve_id")),
                "moca_ccurveid": row.get("moca_ccurveid"),
                "moca_condid": row.get("moca_condid"),
                "moca_ccsetid": row.get("moca_ccsetid"),
                "curve_label": row.get("curve_label"),
                "curve_status": row.get("curve_status"),
                "transition_label": row.get("transition_label"),
                "phase_label": row.get("phase_label"),
                "source_equation_label": row.get("source_equation_label"),
                "valid_log10_pressure_bar_min": _retrieval_float_or_none(row.get("valid_log10_pressure_bar_min")),
                "valid_log10_pressure_bar_max": _retrieval_float_or_none(row.get("valid_log10_pressure_bar_max")),
                "curve_comments": row.get("curve_comments"),
                "condensate_name": row.get("condensate_name"),
                "condensate_formula": row.get("condensate_formula"),
                "mineral_name": row.get("mineral_name"),
                "condensate_kind": row.get("condensate_kind"),
                "set_name": row.get("set_name"),
                "source_bibcode": row.get("set_source_bibcode"),
                "source_doi": row.get("source_doi"),
                "source_url": row.get("source_url"),
                "chemistry_assumption": row.get("chemistry_assumption"),
                "pressure_unit": row.get("pressure_unit") or "bar",
                "temperature_unit": row.get("temperature_unit") or "K",
                "points": [],
            }
            grouped[curve_key] = curve
        log_pressure = _retrieval_float_or_none(row.get("log10_pressure_bar"))
        if log_pressure is None:
            log_pressure = math.log10(pressure)
        curve["points"].append({
            "condensation_curve_point_id": _retrieval_int_value(row.get("condensation_curve_point_id")),
            "source_point_index": _retrieval_int_value(row.get("source_point_index")),
            "pressure_bar": pressure,
            "log10_pressure_bar": log_pressure,
            "temperature_k": temperature,
            "point_source_kind": row.get("point_source_kind"),
        })

    curves = []
    for curve in grouped.values():
        curve["points"].sort(key=lambda point: (
            point.get("source_point_index") is None,
            point.get("source_point_index") or 0,
            point.get("log10_pressure_bar") or 0,
        ))
        if len(curve["points"]) >= 2:
            curves.append(curve)
    curves.sort(key=lambda curve: str(curve.get("curve_label") or curve.get("moca_ccurveid") or ""))
    return curves


def _load_retrieval_atmosphere_from_db(args: dict[str, Any], atmosphere_id: int) -> dict[str, Any]:
    include_ignored = _as_bool(args.get("include_ignored") or args.get("show_ignored"))
    cache_key = _retrieval_cache_key(args, "atmosphere", atmosphere_id, include_ignored)
    now = time.time()
    cached = _RETRIEVAL_EXPLORER_CACHE.get(cache_key)
    if cached and now - cached[0] < CACHE_SECONDS:
        payload = copy.deepcopy(cached[1])
        payload["cache"] = {"hit": True, "ttl_seconds": CACHE_SECONDS}
        return payload

    engine = _engine(_connection_string(args))
    with engine.connect() as conn:
        missing = _retrieval_missing_tables(conn)
        if missing:
            return {
                "selection": {"atmosphere_structure_id": int(atmosphere_id)},
                "atmosphere": {},
                "siblingAtmospheres": [],
                "profiles": [],
                "profileRows": [],
                "cloudParameters": [],
                "scalarParameters": [],
                "condensationCurves": [],
                "abundances": [],
                "comparisonAbundances": [],
                "solarReferences": _retrieval_solar_references(),
                "contributionFunctions": [],
                "retrievedSpectrum": {"available": False, "message": "No retrieved-spectrum product table is available in the current schema."},
                "posterior": {"available": False, "message": "No atmosphere-to-sampling-run link is available in the current schema."},
                "meta": {
                    "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
                    "missing_tables": missing,
                    "private_db": _is_private_db(args),
                },
                "cache": {"hit": False, "ttl_seconds": CACHE_SECONDS},
            }
        spectral_type_columns = (
            _db_table_columns(conn, "data_spectral_types")
            if _db_table_exists(conn, "data_spectral_types") else set()
        )
        spectral_type_order_terms = _retrieval_adoption_order_terms("dst", spectral_type_columns)
        if "photometric_estimate" in spectral_type_columns:
            spectral_type_order_terms.append("COALESCE(dst.`photometric_estimate`, 0) ASC")
        spectral_type_order_terms.append("dst.`id` DESC" if "id" in spectral_type_columns else "dst.`moca_oid` DESC")
        spectral_type_order_sql = ",\n                            ".join(spectral_type_order_terms)
        atmosphere_rows = _records(_read_sql(conn, """
            SELECT
                das.*,
                mo.designation,
                mp.name AS publication_name,
                mp.bibcode AS publication_bibcode,
                ms.spectrum_name,
                ms.instrument_name AS spectrum_instrument_name,
                ms.min_wavelength_angstrom,
                ms.max_wavelength_angstrom
            FROM data_atmosphere_structure das
            LEFT JOIN moca_objects mo
                ON mo.moca_oid = das.moca_oid
            LEFT JOIN moca_publications mp
                ON mp.moca_pid = das.moca_pid
            LEFT JOIN moca_spectra ms
                ON ms.moca_specid = das.moca_specid
            WHERE das.id = :atmosphere_id
        """, {"atmosphere_id": int(atmosphere_id)}))
        if not atmosphere_rows:
            return {
                "selection": {"atmosphere_structure_id": int(atmosphere_id)},
                "atmosphere": {},
                "siblingAtmospheres": [],
                "profiles": [],
                "profileRows": [],
                "cloudParameters": [],
                "scalarParameters": [],
                "condensationCurves": [],
                "abundances": [],
                "comparisonAbundances": [],
                "solarReferences": _retrieval_solar_references(),
                "contributionFunctions": [],
                "retrievedSpectrum": {"available": False, "message": "No atmosphere row was found."},
                "posterior": {"available": False, "message": "No atmosphere row was found."},
                "meta": {
                    "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
                    "private_db": _is_private_db(args),
                },
                "cache": {"hit": False, "ttl_seconds": CACHE_SECONDS},
            }
        atmosphere = atmosphere_rows[0]
        profile_rows = _records(_read_sql(conn, f"""
            SELECT
                l.*,
                q.quantity_name,
                q.quantity_symbol,
                q.quantity_kind,
                q.default_unit,
                q.is_logarithmic
            FROM data_atmosphere_structure_layers l
            LEFT JOIN moca_atmosphere_profile_quantities q
                ON q.moca_atpqid = l.moca_atpqid
            WHERE l.atmosphere_structure_id = :atmosphere_id
            ORDER BY l.moca_atpqid,
                l.profile_axis_index,
                l.component_kind,
                l.component_label,
                l.species_formula,
                l.pressure_bar
        """, {"atmosphere_id": int(atmosphere_id)}))
        scalar_rows = _records(_read_sql(conn, """
            SELECT
                p.*,
                ap.parameter_name,
                ap.parameter_symbol,
                ap.parameter_kind,
                ap.value_space,
                ap.default_unit,
                ap.is_logarithmic,
                ap.description AS parameter_description
            FROM data_atmosphere_structure_parameters p
            LEFT JOIN moca_atmosphere_parameters ap
                ON ap.moca_atparid = p.moca_atparid
            WHERE p.atmosphere_structure_id = :atmosphere_id
            ORDER BY COALESCE(ap.parameter_kind, ''),
                p.moca_atparid,
                p.parameter_index,
                p.component_kind,
                p.component_label,
                p.species_formula
        """, {"atmosphere_id": int(atmosphere_id)}))
        cloud_rows = [row for row in scalar_rows if str(row.get("parameter_kind") or "") == "cloud"]
        moca_oid = _retrieval_int_value(atmosphere.get("moca_oid"))
        abundances: list[dict[str, Any]] = []
        comparison_abundances: list[dict[str, Any]] = []
        sibling_atmospheres: list[dict[str, Any]] = []
        if moca_oid is not None:
            abundance_ignored_clause = "" if include_ignored else "AND COALESCE(dom.ignored, 0) = 0"
            abundances = _records(_read_sql(conn, f"""
                SELECT
                    dom.*,
                    ma.abundance_label,
                    ma.quantity_kind,
                    ma.species_formula,
                    ma.numerator_formula,
                    ma.denominator_formula,
                    ma.abundance_phase,
                    ma.value_space,
                    ma.default_unit,
                    ma.is_logarithmic,
                    mo.designation,
                    (
                        SELECT COALESCE(NULLIF(dst.complete_spectral_type, ''), NULLIF(dst.spectral_type, ''), NULLIF(dst.simple_spectral_type, ''))
                        FROM data_spectral_types dst
                        WHERE dst.moca_oid = dom.moca_oid
                            AND COALESCE(dst.ignored, 0) = 0
                            AND COALESCE(NULLIF(dst.complete_spectral_type, ''), NULLIF(dst.spectral_type, ''), NULLIF(dst.simple_spectral_type, '')) IS NOT NULL
                        ORDER BY {spectral_type_order_sql}
                        LIMIT 1
                    ) AS spectral_type,
                    (
                        SELECT dst.spectral_type_number
                        FROM data_spectral_types dst
                        WHERE dst.moca_oid = dom.moca_oid
                            AND COALESCE(dst.ignored, 0) = 0
                            AND dst.spectral_type_number IS NOT NULL
                        ORDER BY {spectral_type_order_sql}
                        LIMIT 1
                    ) AS spectral_type_number,
                    COALESCE(dom.bibcode, mp.bibcode) AS source_bibcode,
                    CASE WHEN dom.moca_pid = :moca_pid THEN 1 ELSE 0 END AS same_publication,
                    CASE
                        WHEN COALESCE(dom.calculation_method, '') = COALESCE(:calculation_method, '')
                            AND COALESCE(:calculation_method, '') <> ''
                        THEN 1 ELSE 0
                    END AS same_calculation_method
                FROM data_object_metallicities dom
                LEFT JOIN moca_abundances ma
                    ON ma.abundance_type = dom.abundance_type
                LEFT JOIN moca_objects mo
                    ON mo.moca_oid = dom.moca_oid
                LEFT JOIN moca_publications mp
                    ON mp.moca_pid = dom.moca_pid
                WHERE dom.moca_oid = :moca_oid
                    {abundance_ignored_clause}
                    AND COALESCE(ma.quantity_kind, '') <> 'legacy'
                ORDER BY same_publication DESC,
                    same_calculation_method DESC,
                    ma.quantity_kind,
                    dom.abundance_type,
                    dom.id
            """, {
                "moca_oid": moca_oid,
                "moca_pid": atmosphere.get("moca_pid"),
                "calculation_method": atmosphere.get("calculation_method"),
            }))
            abundance_types = sorted({
                str(row.get("abundance_type") or "")
                for row in abundances
                if row.get("abundance_type")
            })
            if abundance_types:
                comparison_abundances = _records(_read_sql_expanding(conn, f"""
                    SELECT
                        dom.id,
                        dom.moca_oid,
                        mo.designation,
                        (
                            SELECT COALESCE(NULLIF(dst.complete_spectral_type, ''), NULLIF(dst.spectral_type, ''), NULLIF(dst.simple_spectral_type, ''))
                            FROM data_spectral_types dst
                            WHERE dst.moca_oid = dom.moca_oid
                                AND COALESCE(dst.ignored, 0) = 0
                                AND COALESCE(NULLIF(dst.complete_spectral_type, ''), NULLIF(dst.spectral_type, ''), NULLIF(dst.simple_spectral_type, '')) IS NOT NULL
                            ORDER BY {spectral_type_order_sql}
                            LIMIT 1
                        ) AS spectral_type,
                        (
                            SELECT dst.spectral_type_number
                            FROM data_spectral_types dst
                            WHERE dst.moca_oid = dom.moca_oid
                                AND COALESCE(dst.ignored, 0) = 0
                                AND dst.spectral_type_number IS NOT NULL
                            ORDER BY {spectral_type_order_sql}
                            LIMIT 1
                        ) AS spectral_type_number,
                        dom.moca_pid,
                        COALESCE(dom.bibcode, mp.bibcode) AS source_bibcode,
                        dom.abundance_type,
                        ma.abundance_label,
                        ma.quantity_kind,
                        ma.species_formula,
                        ma.value_space,
                        ma.default_unit,
                        dom.feh_val,
                        dom.feh_unc,
                        dom.feh_unc_pos,
                        dom.feh_unc_neg,
                        dom.calculation_method,
                        CASE WHEN dom.moca_oid = :moca_oid THEN 1 ELSE 0 END AS selected_object
                    FROM data_object_metallicities dom
                    LEFT JOIN moca_abundances ma
                        ON ma.abundance_type = dom.abundance_type
                    LEFT JOIN moca_objects mo
                        ON mo.moca_oid = dom.moca_oid
                    LEFT JOIN moca_publications mp
                        ON mp.moca_pid = dom.moca_pid
                    WHERE dom.abundance_type IN :abundance_types
                        {abundance_ignored_clause}
                        AND COALESCE(ma.quantity_kind, '') <> 'legacy'
                    ORDER BY selected_object DESC,
                        dom.abundance_type,
                        dom.moca_oid,
                        dom.id
                    LIMIT 2500
                """, "abundance_types", abundance_types, {"moca_oid": moca_oid}))
            sibling_rows = _records(_read_sql(conn, f"""
                SELECT
                    das.id AS atmosphere_structure_id,
                    das.id,
                    das.moca_oid,
                    mo.designation,
                    das.moca_pid,
                    COALESCE(das.bibcode, mp.bibcode) AS bibcode,
                    das.structure_kind,
                    das.time_bin_label,
                    das.retrieval_code,
                    das.retrieval_model,
                    das.cloud_assumption,
                    das.ignored,
                    das.is_public
                FROM data_atmosphere_structure das
                LEFT JOIN moca_objects mo
                    ON mo.moca_oid = das.moca_oid
                LEFT JOIN moca_publications mp
                    ON mp.moca_pid = das.moca_pid
                WHERE das.moca_oid = :moca_oid
                    {'' if include_ignored else 'AND COALESCE(das.ignored, 0) = 0'}
                ORDER BY COALESCE(das.adopted, 0) DESC,
                    das.modified_timestamp DESC,
                    das.id DESC
                LIMIT 100
            """, {"moca_oid": moca_oid}))
            sibling_atmospheres = _retrieval_search_rows_to_options(sibling_rows)
        condensation_curves = _load_retrieval_condensation_curves_from_db(conn)

    temp_profiles = [row for row in profile_rows if str(row.get("moca_atpqid") or "") == "TEMP_K"]
    contribution_rows = [row for row in profile_rows if str(row.get("moca_atpqid") or "") == "CONTRIB_FUNC"]
    payload = {
        "selection": {"atmosphere_structure_id": int(atmosphere_id)},
        "atmosphere": atmosphere,
        "siblingAtmospheres": sibling_atmospheres,
        "profiles": temp_profiles,
        "profileRows": profile_rows,
        "cloudParameters": cloud_rows,
        "scalarParameters": scalar_rows,
        "condensationCurves": condensation_curves,
        "abundances": abundances,
        "comparisonAbundances": comparison_abundances,
        "solarReferences": _retrieval_solar_references(),
        "contributionFunctions": contribution_rows,
        "retrievedSpectrum": {
            "available": False,
            "message": "The current retrieval schema links the input observed spectrum but has no dedicated best-fit/retrieved spectrum product table yet.",
        },
        "posterior": {
            "available": False,
            "message": "Generic sampling payload tables exist, but data_atmosphere_structure is not linked to a sampling run in the current schema.",
        },
        "meta": {
            "loaded_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
            "private_db": _is_private_db(args),
            "include_ignored": include_ignored,
            "profile_count": len(temp_profiles),
            "profile_row_count": len(profile_rows),
            "contribution_count": len(contribution_rows),
            "scalar_parameter_count": len(scalar_rows),
            "cloud_parameter_count": len(cloud_rows),
            "condensation_curve_count": len(condensation_curves),
            "condensation_curve_point_count": sum(len(curve.get("points") or []) for curve in condensation_curves),
            "abundance_count": len(abundances),
            "comparison_abundance_count": len(comparison_abundances),
        },
        "cache": {"hit": False, "ttl_seconds": CACHE_SECONDS},
    }
    _RETRIEVAL_EXPLORER_CACHE[cache_key] = (now, copy.deepcopy(payload))
    return payload


def _retrieval_int_value(value: Any) -> int | None:
    if value is None:
        return None
    try:
        number = int(float(value))
    except (TypeError, ValueError):
        return None
    return number if number > 0 else None


def _retrieval_solar_references() -> list[dict[str, Any]]:
    return [
        {"abundance_type": "[M/H]_gas", "value": 0.0, "label": "solar [M/H]"},
        {"abundance_type": "[M/H]_bulk", "value": 0.0, "label": "solar [M/H]"},
        {"abundance_type": "[Fe/H]", "value": 0.0, "label": "solar [Fe/H]"},
        {"abundance_type": "C/O_gas", "value": 0.55, "label": "solar C/O"},
        {"abundance_type": "C/O_bulk", "value": 0.55, "label": "solar C/O"},
    ]


