    gaia_cmd_count = len(_GAIA_CMD_CACHE)
    moca_explorer_count = len(_MOCA_EXPLORER_CACHE)
    bd_evolution_count = len(_BD_EVOLUTION_CACHE)
    group_hierarchy_count = len(_GROUP_HIERARCHY_CACHE)
